/**
 * 99 Names of Allah (Asma ul Husna) Data
 * Standard list (Tirmidhi narration order), meanings in all 7 UI languages.
 * meanings.ar is a brief Arabic gloss of the name.
 *
 * Also: PROPHETS_25 — the 25 prophets named in the Quran (standard list).
 * Each `count` was computed from this repo's data/quran-tokens.json by
 * summing the name's token forms (incl. attached vocatives/prepositions,
 * e.g. يادم = "O Adam", وابرهيم = "and Ibrahim") and matches the
 * well-known published mention counts. `forms` lists those exact
 * normalized token spellings (Uthmani rasm, diacritics stripped) so the
 * app can find every occurrence at runtime. Where the bare spelling is
 * ambiguous (هود also = "Jews", صلح also = "righteous", يحيى also =
 * the verb "he lives"), the disambiguated verse list is stored in `refs`
 * instead. `ref` is the name's first occurrence (mushaf order).
 */

const NAMES_99 = [
  { n: 1, ar: "الرَّحْمَٰنُ", translit: "Ar-Raḥmān", meanings: { en: "The Most Merciful", bn: "পরম করুণাময়", fr: "Le Tout Miséricordieux", id: "Yang Maha Pengasih", ur: "نہایت مہربان", tr: "Çok Merhametli", ar: "واسع الرحمة" , zh: '至慈者', ja: '全ての慈悲ぶかき者'},
    explain: { en: "Ar-Rahman is the name that encompasses Allah's all-encompassing mercy extended to every creature in this world — believer and disbeliever alike. It is derived from rahmah (mercy) in the intensified form, signifying a mercy so vast it embraces all of creation without discrimination. Ibn al-Qayyim noted that Ar-Rahman is specific to Allah alone and cannot be applied to any created being. The Basmala begins with this name to remind us that every act begins under His boundless mercy (Quran 1:1; 59:22).", bn: "আর-রাহমান নামটি আল্লাহর সেই ব্যাপক রহমতকে বোঝায় যা এই দুনিয়ায় প্রতিটি সৃষ্টির উপর বিস্তৃত — মুমিন ও অবিশ্বাসী উভয়ের উপর। ইবনুল কাইয়িম বলেছেন, এই নাম কেবল আল্লাহর জন্যই নির্দিষ্ট। বিসমিল্লাহ এই নাম দিয়ে শুরু হয় যা স্মরণ করিয়ে দেয় যে প্রতিটি কাজ তাঁর অসীম দয়ার ছায়ায় শুরু হয়।" },
    hadith: { en: "Allah has ninety-nine names, one hundred minus one. Whoever memorises (and acts upon) them will enter Paradise.", bn: "আল্লাহর নিরানব্বইটি নাম রয়েছে — একশোটি থেকে একটি কম। যে ব্যক্তি এগুলো মুখস্থ করবে সে জান্নাতে প্রবেশ করবে।", src: "Sahih al-Bukhari 6410; Sahih Muslim 2677" },
    invoke: { en: "When seeking mercy and compassion in all matters, begin your du'a with 'Ya Rahman, Ya Rahim' — just as every surah (except al-Tawbah) opens with the Basmala. Call upon Him by this name especially when you feel hopeless or distressed.", bn: "দয়া ও করুণার জন্য দু'আ করার সময় 'ইয়া রাহমান, ইয়া রাহিম' বলে শুরু করুন। যখন হতাশ বা বিপদগ্রস্ত অনুভব করবেন তখন এই নামে ডাকুন।" } ,
    quranicRefs: [
      { ref: "1:3", noteEn: "Paired with Ar-Rahim in al-Fatiha, framing all worship under boundless mercy.", noteBn: "আল-ফাতিহায় আর-রাহিমের পাশে, সমস্ত ইবাদতকে অসীম রহমতের মধ্যে রাখে।" },
      { ref: "20:5", noteEn: "Ar-Rahman settled (istawa) upon the Throne — anchoring transcendence with this name.", noteBn: "আর-রাহমান আরশের উপর ইস্তিওয়া করলেন — এই নামের সাথে অতীন্দ্রিয়তা যুক্তকারী আয়াত।" },
      { ref: "55:1", noteEn: "Opens Surah Ar-Rahman, cataloguing divine blessings with the refrain 'Which of your Lord's favours will you deny?'", noteBn: "সূরা আর-রাহমান খোলে, বারবার বলে 'তোমরা তোমাদের প্রভুর কোন নিয়ামতকে অস্বীকার করবে?'" },
      { ref: "19:45", noteEn: "Ibrahim warns his father that Ar-Rahman's punishment may befall him for following Shaytan.", noteBn: "ইব্রাহিম তাঁর পিতাকে সতর্ক করেন যে শয়তান অনুসরণে আর-রাহমানের শাস্তি আসতে পারে।" },
      { ref: "78:37", noteEn: "Lord of heavens and earth — none shall have power to speak before Ar-Rahman.", noteBn: "আকাশ-পৃথিবীর রব — আর-রাহমানের সামনে কেউ কথা বলার ক্ষমতা রাখবে না।" }
    ]},
  { n: 2, ar: "الرَّحِيمُ", translit: "Ar-Raḥīm", meanings: { en: "The Most Compassionate", bn: "অতি দয়ালু", fr: "Le Très Miséricordieux", id: "Yang Maha Penyayang", ur: "نہایت رحم والا", tr: "Çok Merhamet Eden", ar: "دائم الرحمة" , zh: '特慈者', ja: '最も慈悲ぶかき者'},
    explain: { en: "Ar-Rahim refers to Allah's special, enduring mercy directed specifically toward the believers on the Day of Judgement and in the Hereafter. While Ar-Rahman's mercy spans all creation in this world, Ar-Rahim's mercy is a targeted compassion reserved for those who believe and do good. The Prophet (peace be upon him) described Allah as 'more merciful to His servants than a mother to her child' (Bukhari 5999). Together, Ar-Rahman and Ar-Rahim convey the complete picture of divine mercy.", bn: "আর-রাহিম আল্লাহর সেই বিশেষ ও চিরস্থায়ী রহমতকে বোঝায় যা বিশেষত মুমিনদের জন্য কিয়ামতের দিনে এবং আখিরাতে নির্দিষ্ট। নবী (সা.) বলেছেন, আল্লাহ তাঁর বান্দাদের প্রতি একজন মায়ের চেয়েও বেশি দয়ালু।" } ,
    hadith: { en: "The Prophet ﷺ taught Abu Bakr to say in his prayer: 'O Allah, I have greatly wronged myself and none forgives sins but You, so forgive me, for indeed You are Al-Ghafur, Ar-Rahim (the Oft-Forgiving, the Most Merciful).'", bn: "নবী ﷺ আবু বকর (রাঃ)-কে নামাজে এই দু'আ শেখান: 'হে আল্লাহ, আমি নিজের উপর অনেক জুলুম করেছি, আর আপনি ছাড়া কেউ গুনাহ ক্ষমা করতে পারে না; সুতরাং আমাকে ক্ষমা করুন, কারণ নিশ্চয়ই আপনি আল-গাফুর, আর-রাহিম (অতি ক্ষমাশীল, পরম দয়ালু)।'", src: "Sahih al-Bukhari 834; Sahih Muslim 2705" },
    quranicRefs: [
      { ref: "1:3", noteEn: "Paired with Ar-Rahman in al-Fatiha, completing the two dimensions of divine mercy.", noteBn: "আল-ফাতিহায় আর-রাহমানের পাশে, ঐশ্বরিক রহমতের দুই মাত্রা পূর্ণ করে।" },
      { ref: "2:163", noteEn: "Allah is One, Ar-Rahman Ar-Rahim — mercy is essential to divine unity.", noteBn: "আল্লাহ এক, আর-রাহমান আর-রাহিম — রহমত ঐশ্বরিক একত্বের অবিচ্ছেদ্য।" },
      { ref: "33:43", noteEn: "He sends blessings upon believers — He is Ar-Rahim toward the faithful.", noteBn: "তিনি বিশ্বাসীদের উপর দরুদ পাঠান — তিনি মুমিনদের প্রতি আর-রাহিম।" },
      { ref: "48:14", noteEn: "Allah is Ghafur and Rahim — forgiveness and mercy affirmed after the pledge of allegiance.", noteBn: "আল্লাহ গাফুর ও রাহিম — বাইআতের পরে ক্ষমা ও রহমত নিশ্চিত।" },
      { ref: "59:10", noteEn: "Believers pray for their predecessors: 'Our Lord, You are Ra'uf and Rahim.'", noteBn: "বিশ্বাসীরা পূর্বসূরীদের জন্য প্রার্থনা করে: 'হে প্রভু, আপনি রাউফ ও রাহিম।'" }
    ]},
  { n: 3, ar: "الْمَلِكُ", translit: "Al-Malik", meanings: { en: "The King", bn: "সর্বাধিপতি", fr: "Le Souverain", id: "Yang Maha Merajai", ur: "بادشاہ", tr: "Mülkün Sahibi", ar: "الملك الحق" , zh: '君王者', ja: '王、君主、究極なる真の王'},
    explain: { en: "Al-Malik is the Absolute King whose sovereignty requires no subjects to confirm it and no territory to define it. Every earthly kingdom is borrowed and temporary; His kingdom is eternal and total. On the Day of Resurrection, Allah will declare: 'To whom does sovereignty belong today? To Allah, the One, the Subduer!' (Quran 40:16). Ibn al-Qayyim wrote that reflecting on this name strips the heart of servitude to anyone but Allah.", bn: "আল-মালিক হলেন সেই পরম রাজা যাঁর সার্বভৌমত্বের জন্য কোনো প্রজার স্বীকৃতি বা কোনো ভূখণ্ডের প্রয়োজন নেই। কিয়ামতের দিন আল্লাহ ঘোষণা করবেন: 'আজকে রাজত্ব কার? একক পরাক্রমশালী আল্লাহর।' (কুরআন ৪০:১৬)" },
    hadith: { en: "The most vile of names in Allah's sight on the Day of Resurrection will be a man calling himself 'King of Kings' — for there is no king but Allah.", bn: "কিয়ামতের দিন আল্লাহর কাছে সবচেয়ে ঘৃণ্য নাম হবে সেই ব্যক্তির যে নিজেকে 'রাজাধিরাজ' বলে — কারণ আল্লাহ ছাড়া কোনো রাজা নেই।", src: "Sahih al-Bukhari 6205; Sahih Muslim 2143" } ,
    quranicRefs: [
      { ref: "20:114", noteEn: "fa-ta'ala Allahu-l-Maliku-l-Haqq — exalted is Allah, the True Sovereign.", noteBn: "ফাতাআলাল্লাহুল-মালিকুল-হাক্ক — আল্লাহ অত্যন্ত উচ্চ, সত্যিকারের সার্বভৌম।" },
      { ref: "23:116", noteEn: "fa-ta'ala Allahu-l-Maliku-l-Haqq — closes the surah reaffirming absolute sovereignty.", noteBn: "ফাতাআলাল্লাহুল-মালিকুল-হাক্ক — আল্লাহর পরম সার্বভৌমত্ব পুনরুল্লেখ করে সূরা শেষ।" },
      { ref: "59:23", noteEn: "Listed in the cluster of divine names in Surah al-Hashr alongside Al-Quddus and As-Salam.", noteBn: "সূরা আল-হাশরে আল-কুদ্দুস ও আস-সালামের পাশে ঐশ্বরিক নামের গুচ্ছে তালিকাভুক্ত।" },
      { ref: "62:1", noteEn: "All in heavens and earth glorifies Allah, Al-Malik, Al-Quddus, Al-Aziz, Al-Hakim.", noteBn: "আকাশ ও পৃথিবীর সব আল্লাহর তাসবিহ করে — আল-মালিক, আল-কুদ্দুস, আল-আযিয, আল-হাকিম।" },
      { ref: "114:2", noteEn: "Maliki-n-nas — King of mankind — in Surah an-Nas, one of the two refuge surahs.", noteBn: "মালিকিন-নাস — মানবজাতির রাজা — সূরা আন-নাসে, দুই আশ্রয়ের সূরার একটিতে।" }
    ]},
  { n: 4, ar: "الْقُدُّوسُ", translit: "Al-Quddūs", meanings: { en: "The Most Holy", bn: "মহাপবিত্র", fr: "Le Très Saint", id: "Yang Maha Suci", ur: "نہایت پاک", tr: "Çok Kutsal", ar: "المنزه عن النقائص" , zh: '至潔者', ja: '最も神聖なる者'},
    explain: { en: "Al-Quddus signifies that Allah is utterly free from every imperfection, deficiency, likeness to creation, and any attribute that does not befit His majesty. The angels glorify Him with this name in their constant tasbih (Quran 59:23). Al-Ghazali in al-Maqsad al-Asna explains that recognising Allah's absolute holiness is the foundation of true tawhid — for once you know He is unblemished, you realize all worship belongs to Him alone.", bn: "আল-কুদ্দুস অর্থ আল্লাহ সকল ত্রুটি, অপূর্ণতা এবং সৃষ্টির সাদৃশ্য থেকে সম্পূর্ণ মুক্ত। ফেরেশতারা এই নামে তাঁর তাসবিহ পাঠ করেন (কুরআন ৫৯:২৩)।" } ,
    hadith: { en: "In his bowing and prostration the Prophet ﷺ used to say: 'Subbuhun Quddusun, Rabbu-l-mala'ikati wa-r-ruh' (Perfect, Most Holy, Lord of the angels and the Spirit).", bn: "নবী ﷺ রুকু ও সিজদায় বলতেন: 'সুব্বুহুন কুদ্দুসুন, রাব্বুল মালাইকাতি ওয়ার-রুহ' (পূত-পবিত্র, মহাপবিত্র, ফেরেশতাগণ ও রূহের রব)।", src: "Sahih Muslim 487" },
    quranicRefs: [
      { ref: "59:23", noteEn: "Named after Al-Malik — the angels glorify Al-Quddus perpetually.", noteBn: "আল-মালিকের পরে নামকরণ — ফেরেশতারা আল-কুদ্দুসের তাসবিহ অবিরাম করে।" },
      { ref: "62:1", noteEn: "All in heavens and earth glorifies Allah Al-Malik Al-Quddus — holiness as the basis of universal glorification.", noteBn: "আকাশ-পৃথিবীর সব আল্লাহ আল-মালিক আল-কুদ্দুসের তাসবিহ করে — সর্বজনীন মহিমার ভিত্তি পবিত্রতা।" }
    ]},
  { n: 5, ar: "السَّلَامُ", translit: "As-Salām", meanings: { en: "The Source of Peace", bn: "শান্তিদাতা", fr: "La Paix", id: "Yang Maha Sejahtera", ur: "سلامتی والا", tr: "Esenlik Veren", ar: "السالم من كل عيب" , zh: '安宁者，赐安宁者', ja: '平和と恩恵、平和と安らぎの源'},
    explain: { en: "As-Salam means that Allah is Himself the embodiment of peace and the source of all peace and safety. He is free from all defects in His essence, attributes, and actions, and He grants peace (salam) to His servants in this life and in Paradise. The greeting 'Assalamu Alaikum' is derived from this name, and the Prophet (peace be upon him) would say 'Allahumma Anta-s-Salam' after each prayer, acknowledging that true peace flows only from Allah.", bn: "আস-সালাম অর্থ আল্লাহ নিজেই শান্তির মূর্ত প্রতীক এবং সকল শান্তির উৎস। নবী (সা.) প্রতিটি নামাজের পরে বলতেন: 'আল্লাহুম্মা আনতাস-সালাম' — স্বীকার করতেন যে প্রকৃত শান্তি কেবল আল্লাহর কাছ থেকেই আসে।" },
    invoke: { en: "After each obligatory prayer, say 'Allahumma Anta-s-Salam wa minka-s-Salam, tabarakta ya Dhal-Jalali wal-Ikram' (O Allah, You are Peace and from You comes peace, blessed are You, O Lord of Majesty and Honor). This was the Prophet's own practice.", bn: "প্রতিটি ফরজ নামাজের পরে পড়ুন: 'আল্লাহুম্মা আনতাস-সালাম ওয়া মিনকাস-সালাম, তাবারাকতা ইয়া যাল-জালালি ওয়াল-ইকরাম।' এটি নবী (সা.)-এর নিজস্ব অভ্যাস ছিল।" } ,
    hadith: { en: "After each obligatory prayer the Prophet (peace be upon him) used to say: 'Allahumma Anta-s-Salam wa minka-s-Salam, tabarakta ya Dhal-Jalali wal-Ikram.'", bn: "প্রতিটি ফরজ নামাজের পরে নবী (সা.) বলতেন: 'আল্লাহুম্মা আনতাস-সালামু ওয়া মিনকাস-সালামু, তাবারাকতা ইয়া যুল-জালালি ওয়াল-ইকরাম।'", src: "Sahih Muslim 591" },
    quranicRefs: [
      { ref: "59:23", noteEn: "Named in the cluster of divine names in Surah al-Hashr — peace as a divine attribute alongside security and guardianship.", noteBn: "সূরা আল-হাশরে ঐশ্বরিক নামের গুচ্ছে — নিরাপত্তা ও অভিভাবকত্বের পাশে শান্তি।" }
    ]},
  { n: 6, ar: "الْمُؤْمِنُ", translit: "Al-Mu'min", meanings: { en: "The Giver of Security", bn: "নিরাপত্তাদাতা", fr: "Le Rassurant", id: "Yang Maha Memberi Keamanan", ur: "امن دینے والا", tr: "Güven Veren", ar: "المؤمِّن لعباده" , zh: '保證者', ja: '安全を与える者'},
    explain: { en: "Al-Mu'min has two complementary dimensions: He is the One who grants faith (iman) to His servants, and He is the One who gives security and safety — granting safety from His own punishment to those who obey Him. Al-Ghazali notes that only a servant who truly trusts in Allah can experience the inner security (itminan) that flows from this name. The word 'iman' (faith) and 'amn' (safety) share the same Arabic root, showing that faith and security are inseparable.", bn: "আল-মুমিন-এর দুটি মাত্রা আছে: তিনি বান্দাদের ঈমান দান করেন এবং তাদের নিরাপত্তা দেন। আল-গাজালী উল্লেখ করেছেন যে, যে বান্দা সত্যিকারভাবে আল্লাহর উপর ভরসা রাখেন তিনিই এই নামের মাধ্যমে অভ্যন্তরীণ প্রশান্তি অনুভব করেন।" } ,
    quranicRefs: [
      { ref: "59:23", noteEn: "Named in Surah al-Hashr alongside As-Salam and Al-Muhaymin — security as a divine quality.", noteBn: "সূরা আল-হাশরে আস-সালাম ও আল-মুহায়মিনের পাশে — ঐশ্বরিক গুণ হিসেবে নিরাপত্তা।" }
    ]},
  { n: 7, ar: "الْمُهَيْمِنُ", translit: "Al-Muhaymin", meanings: { en: "The Guardian", bn: "রক্ষণাবেক্ষণকারী", fr: "Le Protecteur", id: "Yang Maha Memelihara", ur: "نگہبان", tr: "Gözetip Koruyan", ar: "الرقيب الحافظ" , zh: '守護者', ja: '守護者、管理者'},
    explain: { en: "Al-Muhaymin comes from the root haymana, meaning to oversee, guard, and preserve with complete awareness. Allah watches over every detail of creation — nothing escapes His vigilance. This name also appears in Quran 5:48 describing the Quran itself as a guardian over previous scriptures, indicating that total, attentive guardianship is a divine quality manifested through His revelation.", bn: "আল-মুহায়মিন শব্দটি হায়মানা মূল থেকে এসেছে, অর্থ সম্পূর্ণ সচেতনতার সাথে তত্ত্বাবধান ও রক্ষা করা। সৃষ্টির প্রতিটি বিস্তারিত বিষয় তাঁর দৃষ্টির বাইরে নয়।" } ,
    quranicRefs: [
      { ref: "59:23", noteEn: "Named in Surah al-Hashr — the Overseer who watches and guards all creation.", noteBn: "সূরা আল-হাশরে নামকরণ — তত্ত্বাবধায়ক যিনি সমস্ত সৃষ্টি পর্যবেক্ষণ ও রক্ষা করেন।" }
    ]},
  { n: 8, ar: "الْعَزِيزُ", translit: "Al-ʿAzīz", meanings: { en: "The Almighty", bn: "মহাপরাক্রমশালী", fr: "Le Tout Puissant", id: "Yang Maha Perkasa", ur: "سب پر غالب", tr: "Mutlak Güç Sahibi", ar: "الغالب الذي لا يُقهر" , zh: '勝利者、大能者', ja: '全能者'},
    explain: { en: "Al-'Aziz denotes that Allah is invincible, unconquerable, and utterly without equal. The root 'azza carries three meanings that are all applicable: rare and precious (nothing like Him exists), mighty and strong (no one can overpower Him), and the one who overcomes others without being overcome. Ibn al-Qayyim noted that al-'Aziz is often paired with al-Hakim in the Quran to show that Allah's power is always accompanied by wisdom — He is not arbitrary in His might.", bn: "আল-আযিয অর্থ আল্লাহ অজেয়, অপরাজেয় এবং তুলনাহীন। এই মূল শব্দের তিনটি অর্থ রয়েছে: বিরল ও মূল্যবান, শক্তিশালী ও প্রবল, এবং অন্যদের অভিভূত করেন কিন্তু নিজে কখনো পরাভূত হন না।" } ,
    quranicRefs: [
      { ref: "2:129", noteEn: "Ibrahim's prayer: 'Send a messenger from themselves... You are Al-Aziz, Al-Hakim.'", noteBn: "ইব্রাহিমের দুআ: 'তাদের মধ্য থেকে রাসূল পাঠাও... আপনি আল-আযিয, আল-হাকিম।'" },
      { ref: "26:9", noteEn: "Inna Rabbaka la-Huwa-l-Aziz-ur-Rahim — Your Lord is Al-Aziz, the Merciful, closing the Moses narrative.", noteBn: "ইন্না রাব্বাকা লা-হুওয়াল-আযিযুর-রাহিম — তোমার প্রভু আল-আযিয, রাহিম, মূসার কাহিনী সমাপ্ত।" },
      { ref: "59:23", noteEn: "Listed among the divine names in Surah al-Hashr alongside Al-Jabbar and Al-Mutakabbir.", noteBn: "সূরা আল-হাশরে আল-জাব্বার ও আল-মুতাকাব্বিরের পাশে ঐশ্বরিক নামের মধ্যে।" },
      { ref: "59:24", noteEn: "Al-Aziz Al-Hakim — concludes the creation-names sequence, affirming might paired with wisdom.", noteBn: "আল-আযিয আল-হাকিম — সৃষ্টির নামের ক্রম শেষ করে, প্রজ্ঞার সাথে শক্তি নিশ্চিত।" }
    ]},
  { n: 9, ar: "الْجَبَّارُ", translit: "Al-Jabbār", meanings: { en: "The Compeller", bn: "মহাপ্রতাপশালী", fr: "Le Contraignant", id: "Yang Maha Gagah", ur: "زبردست", tr: "Dilediğini Yaptıran", ar: "الذي يجبر الخلق" , zh: '超越者', ja: '力強き者'},
    explain: { en: "Al-Jabbar has a dual meaning that is both majestic and merciful. First, it means the One who compels and cannot be resisted — His will is carried out irresistibly. Second, from the same root (jabara), it means the One who repairs what is broken, restores the broken-hearted, and sets the fractured bone (jabr). Al-Ghazali writes that this name should inspire awe without despair: yes, He is irresistible in power, but He also mends broken spirits.", bn: "আল-জাব্বার-এর দ্বৈত অর্থ রয়েছে। প্রথমত, যাঁর ইচ্ছাকে প্রতিরোধ করা যায় না। দ্বিতীয়ত, একই মূল থেকে (জাবারা) তিনি ভাঙা হৃদয় মেরামত করেন ও বিপদাপন্নদের সাহায্য করেন।" } ,
    hadith: { en: "In the night prayer the Prophet ﷺ would say in his bowing: 'Subhana dhi-l-jabaruti wa-l-malakuti wa-l-kibriya'i wa-l-'azamah' (Glory to the Owner of absolute power, dominion, grandeur and majesty).", bn: "নবী ﷺ রাতের নামাজে রুকুতে বলতেন: 'সুবহানা যিল-জাবারুতি ওয়াল-মালাকুতি ওয়াল-কিবরিয়াই ওয়াল-আযামাহ' (পরাক্রম, রাজত্ব, মহত্ত্ব ও শ্রেষ্ঠত্বের অধিকারীর পবিত্রতা)।", src: "Sunan Abi Dawud 873; Sunan an-Nasa'i 1049" },
    quranicRefs: [
      { ref: "59:23", noteEn: "Named in Surah al-Hashr — the Compeller whose will none can resist, yet who also mends the broken.", noteBn: "সূরা আল-হাশরে নামকরণ — যাঁর ইচ্ছা কেউ প্রতিরোধ করতে পারে না, অথচ যিনি ভাঙাকে মেরামত করেন।" }
    ]},
  { n: 10, ar: "الْمُتَكَبِّرُ", translit: "Al-Mutakabbir", meanings: { en: "The Supreme", bn: "মহাগৌরবান্বিত", fr: "Le Superbe", id: "Yang Maha Megah", ur: "بڑائی والا", tr: "Büyüklükte Eşsiz", ar: "المتعالي عن السوء" , zh: '廣博者', ja: '強大なる者'},
    explain: { en: "Al-Mutakabbir is the One who rightfully manifests supreme greatness, because He truly possesses it — unlike human arrogance which is a false claim. In Quran 59:23 this name appears after al-Jabbar, reminding us that divine pride (kibr) is not a flaw but the truthful assertion of His transcendence over all imperfection. The Prophet (peace be upon him) warned that no one who has an atom's weight of kibr (pride) in their heart will enter Paradise — meaning this attribute belongs to Allah alone.", bn: "আল-মুতাকাব্বির হলেন যিনি ন্যায্যভাবে সর্বোচ্চ মহিমা প্রকাশ করেন, কারণ তিনি সত্যিকার অর্থেই মহান। মানুষের অহংকার মিথ্যা দাবি, কিন্তু আল্লাহর কিবর সত্যের ঘোষণা। নবী (সা.) সতর্ক করেছেন যে অণু পরিমাণ অহংকার হৃদয়ে থাকলে জান্নাতে প্রবেশ করা যাবে না।" } ,
    hadith: { en: "Allah ﷻ says: 'Pride (al-kibriya') is My cloak and greatness (al-'azamah) is My lower garment; whoever contends with Me over either of them, I shall cast into the Fire.'", bn: "আল্লাহ ﷻ বলেন: 'গর্ব-মহিমা আমার চাদর এবং শ্রেষ্ঠত্ব আমার পরিধেয়; যে এ দুটির কোনো একটিতে আমার সাথে প্রতিদ্বন্দ্বিতা করবে, আমি তাকে জাহান্নামে নিক্ষেপ করব।'", src: "Sahih Muslim 2620" },
    quranicRefs: [
      { ref: "59:23", noteEn: "Named after Al-Jabbar in Surah al-Hashr — divine greatness as truthful assertion of transcendence.", noteBn: "সূরা আল-হাশরে আল-জাব্বারের পরে — সর্বোচ্চ মহিমার সত্যিকার ঘোষণা হিসেবে ঐশ্বরিক মহত্ত্ব।" }
    ]},
  { n: 11, ar: "الْخَالِقُ", translit: "Al-Khāliq", meanings: { en: "The Creator", bn: "সৃষ্টিকর্তা", fr: "Le Créateur", id: "Yang Maha Pencipta", ur: "پیدا کرنے والا", tr: "Yaratan", ar: "الموجِد من العدم" , zh: '創造者', ja: '創造者'},
    explain: { en: "Al-Khaliq refers to Allah's act of bringing things into existence from absolute nothingness — creation ex nihilo. This is qualitatively distinct from human 'creation' which always works with pre-existing material. In Quran 59:24, all three creative names — al-Khaliq, al-Bari', al-Musawwir — appear together, showing the complete arc of creation: from divine will (al-Khaliq), to bringing into being (al-Bari'), to giving each thing its unique form (al-Musawwir).", bn: "আল-খালিক অর্থ আল্লাহ শূন্য থেকে সৃষ্টি করেন — এটি মানুষের 'সৃষ্টি' থেকে মৌলিকভাবে আলাদা যা সবসময় পূর্বে বিদ্যমান উপকরণ দিয়ে কাজ করে। কুরআন ৫৯:২৪-এ তিনটি সৃজনশীল নাম একসাথে আসে।" },
    hadith: { en: "Allah, the Blessed and Exalted, said: 'Who is more unjust than one who tries to create like My creation? Let him create a grain of corn or a grain of wheat or a barleycorn.'", bn: "আল্লাহ বলেন: 'তার চেয়ে বড় জালিম কে, যে আমার সৃষ্টির মতো সৃষ্টি করার চেষ্টা করে? সে যেন একটি ভুট্টার দানা বা গমের দানা বা যবের দানা সৃষ্টি করে দেখায়।'", src: "Sahih al-Bukhari 5953" } ,
    quranicRefs: [
      { ref: "6:102", noteEn: "Dhalikal-llahu Rabbukum la ilaha illa Huwa Khaliqu kulli shay' — Creator of all things, there is none but Him.", noteBn: "যালিকুমুল্লাহু রাব্বুকুম লা ইলাহা ইল্লা হুওয়া খালিকু কুল্লি শায় — সব কিছুর স্রষ্টা, তিনি ছাড়া কেউ নেই।" },
      { ref: "13:16", noteEn: "Qul Allahu Khaliqu kulli shay' — Say: Allah is Creator of all things; He is Al-Wahid, Al-Qahhar.", noteBn: "কুল আল্লাহু খালিকু কুল্লি শায় — বলো: আল্লাহ সব কিছুর স্রষ্টা; তিনি আল-ওয়াহিদ, আল-কাহহার।" },
      { ref: "39:62", noteEn: "Allahu Khaliqu kulli shay' wa Huwa ala kulli shay'in Wakil — Creator and Trustee of all.", noteBn: "আল্লাহু খালিকু কুল্লি শায় ওয়া হুওয়া আলা কুল্লি শায়িন ওয়াকিল — সব কিছুর স্রষ্টা ও তত্ত্বাবধায়ক।" },
      { ref: "59:24", noteEn: "All three creation names — Al-Khaliq, Al-Bari, Al-Musawwir — appear together in this verse.", noteBn: "তিনটি সৃষ্টির নাম — আল-খালিক, আল-বারি, আল-মুসাওয়ির — এই আয়াতে একসাথে।" }
    ]},
  { n: 12, ar: "الْبَارِئُ", translit: "Al-Bāri'", meanings: { en: "The Originator", bn: "নিখুঁত স্রষ্টা", fr: "Le Producteur", id: "Yang Maha Mengadakan", ur: "وجود بخشنے والا", tr: "Kusursuz Yaratan", ar: "الخالق بلا مثال" , zh: '從虛無中創造者', ja: '正当なる者'},
    explain: { en: "Al-Bari' is the One who separates and distinguishes each created thing from every other, bringing each into specific, individual existence with no confusion or overlap. The root bara'a means to distinguish and separate. While al-Khaliq emphasises the act of creating, al-Bari' emphasises the individuation of creation — that Allah gave every created thing its own distinct being. Al-Ghazali writes that this name points to Allah's absolute freedom from any model or prototype in His creation.", bn: "আল-বারি হলেন যিনি প্রতিটি সৃষ্টিকে পৃথক করেন এবং বিশেষ, স্বতন্ত্র অস্তিত্বে আনেন। বারাআ মূলের অর্থ আলাদা করা এবং পার্থক্য করা। আল-গাজালী লিখেছেন যে এই নাম আল্লাহর সৃষ্টিতে কোনো মডেল বা নমুনার পূর্বাপেক্ষিকতা থেকে তাঁর পরম স্বাধীনতা নির্দেশ করে।" } ,
    quranicRefs: [
      { ref: "59:24", noteEn: "Named alongside Al-Khaliq and Al-Musawwir in the triad of creation: conceiving, originating, fashioning.", noteBn: "সৃষ্টির ত্রয়ীতে আল-খালিক ও আল-মুসাওয়িরের পাশে: কল্পনা, উৎপত্তি এবং আকৃতিদান।" }
    ]},
  { n: 13, ar: "الْمُصَوِّرُ", translit: "Al-Muṣawwir", meanings: { en: "The Fashioner", bn: "আকৃতিদানকারী", fr: "Le Formateur", id: "Yang Maha Membentuk", ur: "صورت گر", tr: "Şekil Veren", ar: "المصوِّر للخلق" , zh: '塑形者', ja: '形作りし者'},
    explain: { en: "Al-Musawwir is the Divine Fashioner who gives each created being its unique form, shape, colour, and appearance. The Quran (3:6) states: 'He it is who forms you in the womb however He wills.' No two faces are alike, no two fingerprints identical — this is the signature of Al-Musawwir. Ibn al-Qayyim marvelled that Allah fashions billions of humans from the same basic materials yet gives each an incomparable form, demonstrating limitless creative artistry.", bn: "আল-মুসাওয়ির হলেন সেই ঐশ্বরিক শিল্পী যিনি প্রতিটি সৃষ্টিকে অনন্য রূপ, আকার ও রং দেন। কুরআন (৩:৬) বলে: 'তিনিই গর্ভে তোমাদের রূপ দেন যেভাবে তিনি চান।' কোনো দুটি মুখ একরকম নয়, কোনো দুটি আঙুলের ছাপ অভিন্ন নয়।" } ,
    quranicRefs: [
      { ref: "3:6", noteEn: "Huwa-lladhi yusawwirukum fi-l-arham kayfa yasha — He fashions you in the womb however He wills.", noteBn: "হুওয়াল্লাযি ইউসাওয়িরুকুম ফিল-আরহামি কায়ফা ইয়াশা — তিনি গর্ভে যেভাবে চান রূপ দেন।" },
      { ref: "59:24", noteEn: "Al-Musawwir appears with Al-Khaliq and Al-Bari — the fashioner completing the arc of creation.", noteBn: "আল-মুসাওয়ির আল-খালিক ও আল-বারির সাথে — সৃষ্টির চাপ সম্পন্নকারী ঐশ্বরিক শিল্পী।" }
    ]},
  { n: 14, ar: "الْغَفَّارُ", translit: "Al-Ghaffār", meanings: { en: "The Ever-Forgiving", bn: "মহাক্ষমাশীল", fr: "Le Grand Pardonneur", id: "Yang Maha Pengampun", ur: "بہت بخشنے والا", tr: "Çok Bağışlayan", ar: "كثير المغفرة" , zh: '至恕者', ja: '許し'},
    explain: { en: "Al-Ghaffar, in the intensified form (fa''al), means the One who forgives again and again without limit — not once or twice but continuously, no matter how many times a servant returns in repentance. The root ghafara means to cover and conceal, so Allah covers sins and erases them from the record. The Prophet (peace be upon him) encouraged saying 'Astaghfirullah' 100 times daily, trusting in this name. Al-Ghazali distinguished Al-Ghaffar (habitual, repeated forgiveness) from Al-Ghafur (total forgiveness of a single sin).", bn: "আল-গাফফার — তীব্র রূপে (ফাঅ্আল) — অর্থ যিনি বারবার অসীমভাবে ক্ষমা করেন। মূল শব্দ গাফারা অর্থ ঢেকে রাখা ও গোপন করা, তাই আল্লাহ পাপ ঢেকে দেন এবং হিসাব থেকে মুছে ফেলেন। নবী (সা.) প্রতিদিন ১০০ বার ইস্তেগফার পড়তে উৎসাহিত করতেন।" },
    hadith: { en: "By Allah, I seek forgiveness from Allah and turn to Him in repentance more than seventy times a day.", bn: "আল্লাহর কসম, আমি প্রতিদিন আল্লাহর কাছে সত্তরেরও বেশিবার ক্ষমা প্রার্থনা করি এবং তওবা করি।", src: "Sahih al-Bukhari 6307" },
    invoke: { en: "Repeat 'Astaghfirullah al-Ghaffar' (I seek forgiveness from Allah, the Ever-Forgiving) when overwhelmed by guilt. The Quran (71:10-12) teaches that istighfar by this name brings rain, wealth, children, gardens, and rivers — forgiveness opens all doors.", bn: "'আস্তাগফিরুল্লাহ আল-গাফফার' বলুন যখন গুনাহের বোঝায় ভারাক্রান্ত হন। কুরআন (৭১:১০-১২) শেখায় যে এই নামে ইস্তেগফার বৃষ্টি, সম্পদ, সন্তান, বাগান ও নদী নিয়ে আসে।" } ,
    quranicRefs: [
      { ref: "20:82", noteEn: "wa inni la-Ghaffar-un li-man taba — I am Al-Ghaffar for whoever repents, believes and does good.", noteBn: "ওয়া ইন্নি লা-গাফফারুন লিমান তাবা — যে তওবা করে, ঈমান আনে ও সৎকর্ম করে তার জন্য আমি আল-গাফফার।" },
      { ref: "38:66", noteEn: "Rabb-us-samawati wal-ard... Al-Aziz-ul-Ghaffar — Lord of all creation, Almighty and Ever-Forgiving.", noteBn: "রাব্বুস-সামাওয়াতি ওয়াল-আরদ... আল-আযিযুল-গাফফার — সমস্ত সৃষ্টির রব, মহাশক্তিমান ও চির-ক্ষমাশীল।" },
      { ref: "39:5", noteEn: "Al-Aziz-ul-Ghaffar — might and forgiveness paired; divine power never overrides mercy.", noteBn: "আল-আযিযুল-গাফফার — শক্তি ও ক্ষমা যুগলে; ঐশ্বরিক শক্তি কখনো রহমতকে অতিক্রম করে না।" },
      { ref: "40:42", noteEn: "The believer in Pharaoh's court: I call you to Al-Ghaffar who can forgive all your sins.", noteBn: "ফিরআউনের দরবারে বিশ্বাসী: আমি তোমাদের আল-গাফফারের দিকে ডাকি যিনি সব পাপ মাফ করেন।" },
      { ref: "71:10", noteEn: "Nuh tells his people: Your Lord has been Al-Ghaffar — seek His forgiveness and He will send rain.", noteBn: "নূহ তাঁর জনগণকে বলেন: তোমাদের প্রভু আল-গাফফার — ক্ষমা চাও, তিনি বৃষ্টি পাঠাবেন।" }
    ]},
  { n: 15, ar: "الْقَهَّارُ", translit: "Al-Qahhār", meanings: { en: "The Subduer", bn: "মহাপরাক্রান্ত", fr: "Le Dominateur", id: "Yang Maha Menundukkan", ur: "سب پر قابو والا", tr: "Her Şeye Galip", ar: "القاهر فوق عباده" , zh: '征服者', ja: '全てを従える支配者'},
    explain: { en: "Al-Qahhar is the One who subdues and overpowers everything in existence — no will can resist Him, no plan can succeed against Him, no power can challenge Him. The Quran pairs this name with al-Wahid (the One) in Quran 13:16 and 14:48, showing that His oneness and His all-conquering power are inseparable. For the believer, recognising Allah as al-Qahhar brings liberation: if only Allah has ultimate power, then fearing anyone or anything other than Him is misplaced.", bn: "আল-কাহহার হলেন যিনি অস্তিত্বের সবকিছুকে বশীভূত করেন। কুরআন এই নামকে আল-ওয়াহিদের সাথে জুড়ে দিয়েছে (কুরআন ১৩:১৬; ১৪:৪৮), দেখাচ্ছে যে তাঁর একত্ব এবং সর্বজয়ী শক্তি অবিচ্ছেদ্য।" } ,
    quranicRefs: [
      { ref: "12:39", noteEn: "Yusuf in prison: Are many lords better, or Allah Al-Wahid Al-Qahhar — the One, the Subduer?", noteBn: "কারাগারে ইউসুফ: অনেক প্রভু ভালো, নাকি আল্লাহ আল-ওয়াহিদ আল-কাহহার?" },
      { ref: "13:16", noteEn: "Allah is Creator of all and He is Al-Wahid Al-Qahhar — oneness and supremacy inseparable.", noteBn: "আল্লাহ সব কিছুর স্রষ্টা এবং আল-ওয়াহিদ আল-কাহহার — একত্ব ও সর্বোচ্চতা অবিচ্ছেদ্য।" },
      { ref: "14:48", noteEn: "On the Day the earth is replaced, all stand before Allah Al-Wahid Al-Qahhar.", noteBn: "সেই দিন পৃথিবী পরিবর্তিত হবে, সবাই আল্লাহ আল-ওয়াহিদ আল-কাহহারের সামনে দাঁড়াবে।" },
      { ref: "38:65", noteEn: "No deity except Allah Al-Wahid Al-Qahhar — the cornerstone declaration of tawhid.", noteBn: "আল্লাহ আল-ওয়াহিদ আল-কাহহার ছাড়া কোনো উপাস্য নেই — তাওহিদের ভিত্তিপ্রস্তর।" },
      { ref: "39:4", noteEn: "Subhana-hu Huwa-llahu-l-Wahid-ul-Qahhar — Glory be to Him, He is Allah, the One, the Subduer.", noteBn: "সুবহানাহু হুওয়াল্লাহুল-ওয়াহিদুল-কাহহার — মহিমাময় তিনি, আল্লাহ, আল-ওয়াহিদ, আল-কাহহার।" },
      { ref: "40:16", noteEn: "al-mulku-l-yawm lillahi-l-Wahid-il-Qahhar — sovereignty today belongs to Allah, the One, the Subduer.", noteBn: "আল-মুলকুল-ইয়াওমা লিল্লাহিল-ওয়াহিদিল-কাহহার — আজকে সার্বভৌমত্ব আল্লাহ আল-ওয়াহিদ আল-কাহহারের।" }
    ]},
  { n: 16, ar: "الْوَهَّابُ", translit: "Al-Wahhāb", meanings: { en: "The Bestower", bn: "মহাদাতা", fr: "Le Donateur", id: "Yang Maha Pemberi Karunia", ur: "بہت عطا کرنے والا", tr: "Karşılıksız Veren", ar: "كثير العطاء" , zh: '賜福者', ja: '授ける者'},
    explain: { en: "Al-Wahhab is the One who gives freely, abundantly, and continuously without any expectation of return, benefit, or reciprocity. The root wahaba means to give as a pure gift. Every blessing a person possesses — life, intellect, health, family, faith — is a gift from Al-Wahhab. The Prophet Sulayman (Solomon) prayed: 'My Lord, forgive me and grant me a kingdom that shall not belong to anyone after me; You are the Bestower' (Quran 38:35). Ibn al-Qayyim noted that contemplating this name heals the disease of feeling entitled.", bn: "আল-ওয়াহহাব হলেন যিনি কোনো প্রতিদান, উপকার বা বিনিময়ের প্রত্যাশা ছাড়াই অবাধ ও অফুরন্তভাবে দান করেন। মূল শব্দ ওয়াহাবা অর্থ বিশুদ্ধ উপহার দেওয়া। নবী সুলায়মান (আ.) দু'আ করেছিলেন: 'হে আমার প্রভু, আমাকে একটি রাজ্য দান করুন' (কুরআন ৩৮:৩৫)।" },
    invoke: { en: "When you need a specific gift — a child, a spouse, knowledge, or guidance — call upon 'Ya Wahhab' as Sulayman (as) did. Recite: 'Rabbi hab li min ladunka rahma' (My Lord, grant me from Yourself a mercy — Quran 18:10). This is the du'a of those who feel their hands are empty.", bn: "যখন একটি নির্দিষ্ট উপহারের প্রয়োজন — সন্তান, সঙ্গী, জ্ঞান বা হেদায়েত — 'ইয়া ওয়াহহাব' বলে ডাকুন। পড়ুন: 'রাব্বি হাব লি মিন লাদুনকা রাহমা' (কুরআন ১৮:১০)।" } ,
    quranicRefs: [
      { ref: "3:8", noteEn: "Prayer: grant us from Yourself (wa-hab lana) mercy — You are Al-Wahhab.", noteBn: "দুআ: আপনার পক্ষ থেকে (ওয়া-হাব লানা) রহমত দাও — আপনি আল-ওয়াহহাব।" },
      { ref: "38:9", noteEn: "Do they possess the treasuries of Al-Aziz Al-Wahhab's mercy?", noteBn: "তাদের কাছে কি আল-আযিয আল-ওয়াহহাবের রহমতের ভাণ্ডার আছে?" },
      { ref: "38:35", noteEn: "Sulayman's prayer: grant me (hab li) a kingdom none will have after me — invoking Al-Wahhab.", noteBn: "সুলায়মানের দুআ: আমাকে (হাব লি) এমন রাজত্ব দাও যা আমার পরে কারো হবে না — আল-ওয়াহহাবকে আহ্বান।" }
    ]},
  { n: 17, ar: "الرَّزَّاقُ", translit: "Ar-Razzāq", meanings: { en: "The Provider", bn: "রিযিকদাতা", fr: "Le Pourvoyeur", id: "Yang Maha Pemberi Rezeki", ur: "رزق دینے والا", tr: "Rızık Veren", ar: "المتكفل بالرزق" , zh: '供給者', ja: '常に与える者'},
    explain: { en: "Ar-Razzaq is the One who continuously provides all creation with everything they need — food, drink, sustenance, livelihood, and every resource, both material and spiritual. The Quran states: 'Indeed, Allah is the All-Provider, Owner of Power, the Firm' (51:58). No creature will die until it has received its full portion of rizq (provision) — this is a divine guarantee. Al-Ghazali emphasises that no intermediary between us and Ar-Razzaq can withhold or delay what He has decreed for us.", bn: "আর-রাজ্জাক হলেন যিনি সমস্ত সৃষ্টিকে তাদের প্রয়োজনীয় সবকিছু ক্রমাগত সরবরাহ করেন — খাদ্য, পানীয়, জীবিকা এবং প্রতিটি সম্পদ। কুরআন বলে: 'নিশ্চয়ই আল্লাহ রিযিকদাতা, শক্তির মালিক' (৫১:৫৮)।" },
    hadith: { en: "The Holy Spirit (Jibril) breathed into my soul: No soul shall die until it has received its full provision, so seek it by lawful means.", bn: "পবিত্র আত্মা (জিব্রাইল) আমার আত্মায় অনুপ্রেরণা দিয়েছেন: কোনো আত্মা তার পূর্ণ রিজিক পাওয়ার আগে মৃত্যুবরণ করবে না, তাই হালাল উপায়ে তা অন্বেষণ করো।", src: "Sahih Ibn Hibban; al-Mustadrak (authentic)" },
    invoke: { en: "For rizq (provision) and relief from financial worry, repeat 'Ya Razzaq' frequently. Also recite Quran 51:58 and the morning du'a: 'Allahumma inni as'aluka rizqan halalan tayyiban wasi'an' (O Allah, I ask You for lawful, good, and abundant provision).", bn: "রিজিক ও আর্থিক উদ্বেগ থেকে মুক্তির জন্য 'ইয়া রাজ্জাক' বারবার বলুন। কুরআন ৫১:৫৮ পড়ুন এবং সকালের দু'আ: 'আল্লাহুম্মা ইন্নি আস'আলুকা রিজকান হালালান তাইয়িবান ওয়াসিআন।'" } ,
    quranicRefs: [
      { ref: "11:6", noteEn: "No creature on earth but its provision (rizq) is upon Allah — the foundational promise of Ar-Razzaq.", noteBn: "পৃথিবীতে এমন কোনো প্রাণী নেই যার রিজিকের দায়িত্ব আল্লাহর উপর নেই — আর-রাজ্জাকের মৌলিক প্রতিশ্রুতি।" },
      { ref: "51:58", noteEn: "Inna-llaha Huwa-r-Razzaq Dhu-l-Quwwati-l-Matin — the only verse naming Ar-Razzaq explicitly.", noteBn: "ইন্নাল্লাহা হুওয়ার-রাজ্জাকু যুল-কুওয়্যাতিল-মাতিন — আর-রাজ্জাককে সরাসরি নামকরণ করা একমাত্র আয়াত।" }
    ]},
  { n: 18, ar: "الْفَتَّاحُ", translit: "Al-Fattāḥ", meanings: { en: "The Opener", bn: "মহাবিজয়দানকারী", fr: "Celui qui ouvre", id: "Yang Maha Pembuka", ur: "کھولنے والا", tr: "Kapıları Açan", ar: "الحاكم الفاتح" , zh: '開啟者', ja: '開く者、勝利を与える者'},
    explain: { en: "Al-Fattah is the One who opens all locked doors — literal and metaphorical. He opens the door of mercy when all human options are exhausted, the door of knowledge when minds are confused, the door of provision when pathways seem closed, and the door of victory (fath) when believers are oppressed. Surah al-Fath (48) begins with Allah's promise of manifest victory (fath). Ibn al-Qayyim wrote that calling on this name is essential for anyone whose path seems blocked.", bn: "আল-ফাত্তাহ হলেন যিনি সমস্ত বন্ধ দরজা খোলেন — আক্ষরিক ও রূপক। তিনি রহমতের দরজা খোলেন যখন সব মানবিক বিকল্প শেষ হয়, জ্ঞানের দরজা যখন মন বিভ্রান্ত হয়, রিজিকের দরজা যখন পথ বন্ধ মনে হয়।" },
    invoke: { en: "When you face an obstacle that seems impossible — a closed career path, a blocked marriage, a stalled project — say 'Ya Fattah, iftah lana' (O Opener, open for us). Recite Quran 35:2: 'Whatever Allah grants to people of mercy — none can withhold it.'", bn: "যখন কোনো বাধা অসম্ভব মনে হয় — বন্ধ ক্যারিয়ার, থমকানো বিবাহ, আটকে যাওয়া প্রকল্প — 'ইয়া ফাত্তাহ, ইফতাহ লানা' বলুন। কুরআন ৩৫:২ পড়ুন: 'আল্লাহ মানুষের জন্য যে রহমত খুলে দেন কেউ তা আটকাতে পারে না।'" } ,
    hadith: { en: "Whoever says in the morning: 'Bismillahi tawakkaltu ala-llah wa la hawla wa la quwwata illa billah' — it is said to him: you are guided, provided for, and protected.", bn: "যে ব্যক্তি সকালে বলে: 'বিসমিল্লাহি তাওয়াক্কালতু আলাল্লাহি ওয়া লা হাওলা ওয়ালা কুওয়াতা ইল্লা বিল্লাহ' — তাকে বলা হয়: তোমাকে হেদায়েত, রিজিক ও রক্ষা দেওয়া হলো।", src: "Sunan Abu Dawud 5095; Sunan al-Tirmidhi 3426 (Hasan Sahih)" },
    quranicRefs: [
      { ref: "34:26", noteEn: "Our Lord will bring us together then judge (yaftahu) between us in truth — Al-Fattah as the divine arbitrator.", noteBn: "আমাদের প্রভু একত্রিত করবেন তারপর সত্যের সাথে বিচার (ইয়াফতাহু) করবেন — ঐশ্বরিক মধ্যস্থতাকারী।" },
      { ref: "35:2", noteEn: "Whatever Allah opens (yaftah) of mercy for people, none can withhold it — Al-Fattah's mercy is unstoppable.", noteBn: "আল্লাহ মানুষের জন্য যে রহমত খুলে দেন (ইয়াফতাহ), কেউ তা আটকাতে পারে না।" }
    ]},
  { n: 19, ar: "الْعَلِيمُ", translit: "Al-ʿAlīm", meanings: { en: "The All-Knowing", bn: "সর্বজ্ঞ", fr: "L'Omniscient", id: "Yang Maha Mengetahui", ur: "سب کچھ جاننے والا", tr: "Her Şeyi Bilen", ar: "المحيط علمه بكل شيء" , zh: '全知者', ja: '全てを知る者'},
    explain: { en: "Al-'Alim encompasses all knowledge — past, present, and future; seen and unseen; what has happened and what will never happen but if it had, how it would have unfolded. The Quran (31:34) states that only Allah knows what is in the wombs and what soul earns tomorrow. This name appears over 140 times in the Quran, often paired with al-Hakim (All-Wise), showing that Allah's knowledge always leads to wise, purposeful action. For the believer, this name is a source of comfort: Allah knows your situation better than you do.", bn: "আল-আলিম সমস্ত জ্ঞান অন্তর্ভুক্ত করেন — অতীত, বর্তমান ও ভবিষ্যৎ; দৃশ্যমান ও অদৃশ্য। কুরআনে এই নাম ১৪০ বারেরও বেশি আসে, প্রায়ই আল-হাকিমের সাথে যুগলে।" } ,
    hadith: { en: "The Prophet ﷺ taught the istikharah: 'O Allah, I seek Your guidance by Your knowledge, for You know and I know not, and You are the Knower of all that is unseen (Anta 'Allamu-l-ghuyub).'", bn: "নবী ﷺ ইস্তিখারার দু'আ শেখান: 'হে আল্লাহ, আমি আপনার জ্ঞানের মাধ্যমে কল্যাণ প্রার্থনা করি, কারণ আপনি জানেন, আমি জানি না; আর আপনিই গায়েবের সর্বজ্ঞ (আন্তা আল্লামুল-গুয়ুব)।'", src: "Sahih al-Bukhari 1166" },
    quranicRefs: [
      { ref: "2:29", noteEn: "He created all on earth then turned to heaven... and He is Alim of all things — cosmic scope of His knowledge.", noteBn: "পৃথিবীতে যা আছে সব সৃষ্টির পরে আকাশে মনোযোগ দিলেন... তিনি আলিম সব কিছু সম্পর্কে।" },
      { ref: "2:115", noteEn: "Inna-llaha Wasi'un Alim — wherever you turn, there is Allah's face; He is All-Encompassing and All-Knowing.", noteBn: "ইন্নাল্লাহা ওয়াসিউন আলিম — যেদিকে মুখ ফেরাও আল্লাহর মুখ; তিনি সর্বব্যাপী ও সর্বজ্ঞ।" },
      { ref: "6:13", noteEn: "To Him belongs all that dwells in night and day; He is As-Sami, Al-Alim — hearing and knowledge unified.", noteBn: "রাত ও দিনে যা বিচরণ করে সব তাঁর; তিনি আস-সামি, আল-আলিম — শ্রবণ ও জ্ঞান একত্রিত।" },
      { ref: "22:59", noteEn: "He will admit them to an entrance they will be pleased with; Allah is Alim and Halim.", noteBn: "তিনি তাদের পছন্দের প্রবেশপথে প্রবেশ করাবেন; আল্লাহ আলিম ও হালিম।" },
      { ref: "49:16", noteEn: "Inna-llaha Alim-un bi-ma fi-s-samawati wa ma fi-l-ard — Allah is Alim of all in the heavens and earth.", noteBn: "ইন্নাল্লাহা আলিমুন বিমা ফিস-সামাওয়াতি ওয়ামা ফিল-আরদ — আল্লাহ আকাশ-পৃথিবীর সব জানেন।" }
    ]},
  { n: 20, ar: "الْقَابِضُ", translit: "Al-Qābiḍ", meanings: { en: "The Withholder", bn: "সংকোচনকারী", fr: "Celui qui rétracte", id: "Yang Maha Menyempitkan", ur: "تنگی دینے والا", tr: "Daraltan", ar: "القابض للأرزاق" , zh: '遏止者、整頓者', ja: '制止する者'},
    explain: { en: "Al-Qabid is the One who withholds, constricts, and takes back — provision, life, opportunity — always according to divine wisdom, not arbitrariness. This name always appears paired with al-Basit (the Expander) in the Quran and Sunnah, reminding us that constriction is not permanent and is part of the same divine hand that expands. Times of tightness are a divine test and an invitation to turn back to Allah.", bn: "আল-কাবিদ হলেন যিনি সীমিত করেন, সংকুচিত করেন এবং ফিরিয়ে নেন — সর্বদা ঐশ্বরিক প্রজ্ঞা অনুযায়ী, খামখেয়ালী নয়। এই নাম সর্বদা আল-বাসিতের সাথে জোড়ায় আসে, মনে করিয়ে দেয় যে সংকোচন স্থায়ী নয়।" } ,
    quranicRefs: [
      { ref: "2:245", noteEn: "Allahu yaqbidu wa yabsutu — Allah withholds and expands; Al-Qabid paired with Al-Basit in divine economy.", noteBn: "আল্লাহু ইয়াকবিদু ওয়া ইয়াবসুতু — আল্লাহ সংকুচিত ও প্রসারিত করেন; ঐশ্বরিক অর্থনীতিতে আল-বাসিতের সাথে জুটি।" }
    ]},
  { n: 21, ar: "الْبَاسِطُ", translit: "Al-Bāsiṭ", meanings: { en: "The Expander", bn: "সম্প্রসারণকারী", fr: "Celui qui étend", id: "Yang Maha Melapangkan", ur: "کشادگی دینے والا", tr: "Genişleten", ar: "الباسط للأرزاق" , zh: '寬宏者、慷慨者', ja: '広げる者、惜しみなく与える者'},
    explain: { en: "Al-Basit is the One who expands provision, hearts, chests, and possibilities. The famous du'a 'Allahumma inni as'aluka sadr wasit' (O Allah, I ask You for an expanded chest) draws on this attribute. The Prophet (peace be upon him) said: 'No one who sets prices can do so — only Allah constricts and expands' (Abu Dawud 3450), establishing that Al-Qabid and Al-Basit alone control economic realities.", bn: "আল-বাসিত হলেন যিনি রিজিক, হৃদয়, বুক এবং সম্ভাবনা প্রশস্ত করেন। নবী (সা.) বলেছেন: 'কেউ মূল্য নির্ধারণ করতে পারবে না — কেবল আল্লাহই সংকুচিত ও প্রসারিত করেন।'" } ,
    quranicRefs: [
      { ref: "2:245", noteEn: "Allahu yaqbidu wa yabsutu — Al-Basit expands provision, hearts and possibilities alongside Al-Qabid.", noteBn: "আল্লাহু ইয়াকবিদু ওয়া ইয়াবসুতু — আল-কাবিদের পাশে আল-বাসিত রিজিক, হৃদয় ও সম্ভাবনা প্রসারিত করেন।" }
    ]},
  { n: 22, ar: "الْخَافِضُ", translit: "Al-Khāfiḍ", meanings: { en: "The Abaser", bn: "অবনতকারী", fr: "Celui qui abaisse", id: "Yang Maha Merendahkan", ur: "پست کرنے والا", tr: "Alçaltan", ar: "الخافض للجبابرة" , zh: '貶謫者', ja: '低める者'},
    explain: { en: "Al-Khafid is the One who lowers the arrogant and oppressive — the tyrants, the proud, those who transgress. This name appears paired with Ar-Rafi' (the Exalter), forming a perfect divine justice: those who humble themselves are raised, and those who raise themselves in arrogance are brought low. The Quran (56:3) uses this name to describe Allah's action on the Day of Resurrection, when all social orders are overturned.", bn: "আল-খাফিদ হলেন যিনি অহংকারী ও অত্যাচারীদের নামিয়ে আনেন। এই নাম আর-রাফি'-এর সাথে জোড়ায় আসে — যারা বিনয়ী তাদের উঁচু করা হয়, আর যারা অহংকারে নিজেদের উঁচু করে তাদের নামিয়ে দেওয়া হয়।" } ,
    quranicRefs: [
      { ref: "56:3", noteEn: "khafidatun rafi'ah — lowering some and raising others; divine justice overturning human hierarchies.", noteBn: "খাফিদাতুন রাফিআহ — কাউকে নামিয়ে কাউকে উঁচু করা — মানবিক অনুক্রম উল্টে দেওয়া ঐশ্বরিক ন্যায়।" }
    ]},
  { n: 23, ar: "الرَّافِعُ", translit: "Ar-Rāfiʿ", meanings: { en: "The Exalter", bn: "উন্নতকারী", fr: "Celui qui élève", id: "Yang Maha Meninggikan", ur: "بلند کرنے والا", tr: "Yücelten", ar: "الرافع لأوليائه" , zh: '擢昇者', ja: '高尚なる者'},
    explain: { en: "Ar-Rafi' is the One who elevates and raises in status — in this world and the next. He raises ranks in paradise, raises the righteous over the wicked, and raises the humble believer over the arrogant disbeliever. The Quran (58:11) says: 'Allah will raise those who have believed among you and those who were given knowledge, by degrees.' This name assures believers that the right path — of patience, sincerity, and worship — leads to elevation.", bn: "আর-রাফি হলেন যিনি মর্যাদায় উন্নীত করেন — ইহকালে ও পরকালে। কুরআন (৫৮:১১) বলে: 'আল্লাহ তোমাদের মধ্যে যারা বিশ্বাস করেছে এবং যাদের জ্ঞান দেওয়া হয়েছে তাদের মর্যাদায় উন্নীত করবেন।'" } ,
    quranicRefs: [
      { ref: "6:165", noteEn: "He raised some above others in rank to test you — divine elevation as trial and responsibility.", noteBn: "তিনি তোমাদের কাউকে কারো উপরে মর্যাদায় উন্নীত করলেন তোমাদের পরীক্ষার জন্য।" },
      { ref: "43:32", noteEn: "We raised some above others in rank so that some may take others into service — divine distribution of roles.", noteBn: "আমরা কাউকে কারো উপরে উন্নীত করলাম যাতে একজন অন্যকে সেবায় নিতে পারে।" },
      { ref: "56:3", noteEn: "khafidatun rafi'ah — the paired action of lowering and raising on the Day of Judgement.", noteBn: "খাফিদাতুন রাফিআহ — কিয়ামতের দিনে নামানো ও উন্নীত করার যুগ্ম কার্য।" },
      { ref: "58:11", noteEn: "yarfa'i-llahu-lladhina amanu... darajat — Allah raises believers and those given knowledge in rank.", noteBn: "ইয়ারফাইল্লাহুল্লাযিনা আমানু... দারাজাত — আল্লাহ ঈমানদার ও জ্ঞানপ্রাপ্তদের মর্যাদায় উন্নীত করেন।" }
    ]},
  { n: 24, ar: "الْمُعِزُّ", translit: "Al-Muʿizz", meanings: { en: "The Giver of Honor", bn: "সম্মানদাতা", fr: "Celui qui honore", id: "Yang Maha Memuliakan", ur: "عزت دینے والا", tr: "İzzet Veren", ar: "المعطي العزة" , zh: '賜榮者', ja: '栄誉を与える者'},
    explain: { en: "Al-Mu'izz is the One who grants true honour and dignity ('izzah) to whomever He wills. The Quran (3:26) says: 'You honour whom You will and You humble whom You will.' Real honour comes only from Allah — no degree, wealth, or lineage grants it permanently. The Prophet (peace be upon him) taught that whoever seeks honour through arrogance will be humiliated, but whoever seeks it through obedience to Allah will be truly honoured.", bn: "আল-মুইয্য হলেন যিনি প্রকৃত সম্মান ও মর্যাদা ('ইয্যাহ) যাকে চান তাকে দান করেন। কুরআন (৩:২৬) বলে: 'আপনি যাকে চান সম্মানিত করেন এবং যাকে চান অপমানিত করেন।'" } ,
    quranicRefs: [
      { ref: "3:26", noteEn: "tu'izzu man tasha' — You honour whom You will; true honour comes from Allah alone, not worldly rank.", noteBn: "তুইয্যু মান তাশা — আপনি যাকে চান সম্মানিত করেন; প্রকৃত সম্মান কেবল আল্লাহর কাছ থেকে।" }
    ]},
  { n: 25, ar: "الْمُذِلُّ", translit: "Al-Mudhill", meanings: { en: "The Humiliator", bn: "অপদস্থকারী", fr: "Celui qui humilie", id: "Yang Maha Menghinakan", ur: "ذلت دینے والا", tr: "Zillete Düşüren", ar: "المذل لأعدائه" , zh: '施恥者', ja: '不名誉を与える者'},
    explain: { en: "Al-Mudhil is the One who humiliates and degrades — specifically those who resist and transgress against His command, and those who seek honour through paths other than obedience to Him. This is not a vindictive attribute but a manifestation of perfect divine justice. Al-Ghazali notes that understanding this name should motivate the believer to flee from disobedience, since all paths that are not aligned with Allah's guidance lead ultimately to degradation.", bn: "আল-মুযিল হলেন যিনি অপমানিত ও অবনত করেন — বিশেষত যারা তাঁর আদেশ প্রতিরোধ করে এবং তাঁর আনুগত্য ছাড়া অন্য পথে সম্মান খোঁজে। এটি প্রতিশোধমূলক নয় বরং নিখুঁত ঐশ্বরিক ন্যায়বিচারের প্রকাশ।" } ,
    quranicRefs: [
      { ref: "3:26", noteEn: "wa tudhillu man tasha' — You humble whom You will; paired with tu'izzu, honour and humiliation are Allah's alone.", noteBn: "ওয়া তুযিল্লু মান তাশা — আপনি যাকে চান অপমানিত করেন; সম্মান-অপমান শুধু আল্লাহর হাতে।" }
    ]},
  { n: 26, ar: "السَّمِيعُ", translit: "As-Samīʿ", meanings: { en: "The All-Hearing", bn: "সর্বশ্রোতা", fr: "L'Audient", id: "Yang Maha Mendengar", ur: "سب کچھ سننے والا", tr: "Her Şeyi İşiten", ar: "السامع لكل شيء" , zh: '全聽者', ja: '全て聞こえし者'},
    explain: { en: "As-Sami' means Allah hears everything — every whisper, every silent du'a, every thought not yet uttered aloud, in every language, simultaneously, without limit or distraction. Hajar ('Alayhassalam), alone in the desert with her infant Ismail, ran between Safa and Marwa calling out — and Allah heard, and the spring of Zamzam burst forth. The believer who knows As-Sami' is never truly alone: every prayer, even unspoken, reaches Allah perfectly.", bn: "আস-সামি অর্থ আল্লাহ সবকিছু শুনেন — প্রতিটি ফিসফিস, প্রতিটি নীরব দু'আ, প্রতিটি এখনো উচ্চারিত না হওয়া চিন্তা। হাজার (আ.) একা মরুভূমিতে শিশু ইসমাইলকে নিয়ে সাফা ও মারওয়ার মাঝে দৌড়েছিলেন — আল্লাহ শুনেছিলেন, এবং জমজম কূপ উৎসারিত হয়েছিল।" },
    hadith: { en: "Allah, the Exalted, heard the complaint of the woman who argued with you about her husband and was complaining to Allah — and Allah heard what you were saying to each other, for Allah is the All-Hearing, the All-Seeing.", bn: "আল্লাহ সেই মহিলার অভিযোগ শুনলেন যে তার স্বামীর বিষয়ে তোমার সাথে তর্ক করছিল এবং আল্লাহর কাছে অভিযোগ করছিল। আল্লাহ তোমাদের কথোপকথন শুনেছেন।", src: "Tafsir ibn Kathir on Quran 58:1 (Sahih isnad)" } ,
    quranicRefs: [
      { ref: "2:127", noteEn: "Ibrahim and Ismail raise the Kaaba foundations: Inna-ka Anta-s-Sami-ul-Alim — You are As-Sami, Al-Alim.", noteBn: "ইব্রাহিম ও ইসমাইল কাবার ভিত্তি স্থাপনে: ইন্নাকা আনতাস-সামিউল-আলিম।" },
      { ref: "2:137", noteEn: "Wa Huwa-s-Sami-ul-Alim — affirmed after the command to follow Ibrahim's path.", noteBn: "ওয়া হুওয়াস-সামিউল-আলিম — ইব্রাহিমের পথ অনুসরণের আদেশের পরে নিশ্চিত।" },
      { ref: "4:148", noteEn: "Wa kana-llahu Sami'an Alima — As-Sami and Al-Alim in the context of speaking out against injustice.", noteBn: "ওয়া কানাল্লাহু সামিআন আলিমা — অন্যায়ের বিরুদ্ধে কথা বলার প্রসঙ্গে আস-সামি ও আল-আলিম।" },
      { ref: "8:17", noteEn: "Wa-llahu Sami'un Alim — after the Battle of Badr, affirming Allah heard the believers' prayers.", noteBn: "ওয়াল্লাহু সামিউন আলিম — বদরের পরে নিশ্চিত করে আল্লাহ বিশ্বাসীদের দুআ শুনেছেন।" },
      { ref: "49:1", noteEn: "Inna-llaha Sami'un Alim — commanding believers not to presume before Allah and His Messenger.", noteBn: "ইন্নাল্লাহা সামিউন আলিম — বিশ্বাসীদের আল্লাহ ও রাসূলের আগে না যাওয়ার আদেশে।" }
    ]},
  { n: 27, ar: "الْبَصِيرُ", translit: "Al-Baṣīr", meanings: { en: "The All-Seeing", bn: "সর্বদ্রষ্টা", fr: "Le Clairvoyant", id: "Yang Maha Melihat", ur: "سب کچھ دیکھنے والا", tr: "Her Şeyi Gören", ar: "المبصر لكل شيء" , zh: '全視者', ja: '全てを見し者'},
    explain: { en: "Al-Basir sees everything — the tiniest ant on a black stone in a moonless night, the movement of atoms, and the innermost secrets of hearts. As-Sami' and Al-Basir frequently appear together in the Quran (over 40 times), showing that Allah's comprehensive awareness encompasses both auditory and visual reality. For the servant of Allah, this name functions as a conscience: every action, even in the deepest privacy, is witnessed by the All-Seeing.", bn: "আল-বাসির সবকিছু দেখেন — অন্ধকার রাতে কালো পাথরে ক্ষুদ্রতম পিপড়া, পরমাণুর গতিবিধি এবং হৃদয়ের গভীরতম রহস্য। আস-সামি ও আল-বাসির কুরআনে ৪০ বারেরও বেশি একসাথে আসে।" } ,
    quranicRefs: [
      { ref: "4:58", noteEn: "Inna-llaha kana Sami'an Basira — As-Sami and Al-Basir paired when commanding just governance.", noteBn: "ইন্নাল্লাহা কানা সামিআন বাসিরা — ন্যায্য শাসনের আদেশে আস-সামি ও আল-বাসির যুগলে।" },
      { ref: "17:1", noteEn: "Surana-lladhi asra... Inna-hu Huwa-s-Sami-ul-Basir — the Night Journey verse; Al-Basir witnessed it all.", noteBn: "সুবহানাল্লাযি আসরা... ইন্নাহু হুওয়াস-সামিউল-বাসির — মিরাজের আয়াত; আল-বাসির সব প্রত্যক্ষ করলেন।" },
      { ref: "22:61", noteEn: "Inna-llaha Sami'un Basir — affirmed in the cycle of night and day; awareness spans all time.", noteBn: "ইন্নাল্লাহা সামিউন বাসির — রাত-দিনের চক্রে নিশ্চিত; সচেতনতা সব সময় জুড়ে।" },
      { ref: "40:20", noteEn: "Inna-llaha Huwa-s-Sami-ul-Basir — the ultimate witness, unlike false gods that neither hear nor see.", noteBn: "ইন্নাল্লাহা হুওয়াস-সামিউল-বাসির — পরম সাক্ষী, মিথ্যা দেবতাদের বিপরীতে।" },
      { ref: "42:11", noteEn: "Wa Huwa-s-Sami-ul-Basir — in the verse of divine incomparability: nothing is like Him yet He hears and sees all.", noteBn: "ওয়া হুওয়াস-সামিউল-বাসির — ঐশ্বরিক তুলনাহীনতার আয়াতে: তাঁর মতো কিছু নেই তবু তিনি সব শুনেন-দেখেন।" }
    ]},
  { n: 28, ar: "الْحَكَمُ", translit: "Al-Ḥakam", meanings: { en: "The Judge", bn: "মহাবিচারক", fr: "L'Arbitre", id: "Yang Maha Menetapkan Hukum", ur: "فیصلہ کرنے والا", tr: "Hükmeden", ar: "الحاكم العدل" , zh: '仲裁者', ja: '審判、調停者'},
    explain: { en: "Al-Hakam is the ultimate Judge whose rulings are final, perfect, and just. Unlike human courts which can be wrong, delayed, or bribed, Al-Hakam's judgement is infallible. The Prophet (peace be upon him) forbade giving the name 'Hakam' to people, explaining 'The Judge is Allah' (Abu Dawud 4955). Every injustice in this world will be addressed at the final court of Al-Hakam — a fact that should comfort the oppressed and warn the oppressor.", bn: "আল-হাকাম হলেন পরম বিচারক যাঁর রায় চূড়ান্ত, নিখুঁত ও ন্যায্য। নবী (সা.) মানুষকে 'হাকাম' নাম দিতে নিষেধ করেছিলেন, বলেছিলেন 'বিচারক হলেন আল্লাহ।' এই দুনিয়ার প্রতিটি অবিচার আল-হাকামের চূড়ান্ত আদালতে বিচার হবে।" } ,
    quranicRefs: [
      { ref: "6:114", noteEn: "A-fa-ghayra-llahi abtaghi hakaman — Shall I seek other than Allah as Al-Hakam? He revealed the Book in truth.", noteBn: "আফাগায়রাল্লাহি আবতাগি হাকামান — আল্লাহ ছাড়া অন্য কাউকে আল-হাকাম খুঁজব?" },
      { ref: "12:40", noteEn: "In al-hukmu illa lillah — judgement belongs only to Allah; Yusuf affirms tawhid to his prison companions.", noteBn: "ইনিল-হুকমু ইল্লা লিল্লাহ — বিচার কেবল আল্লাহরই; ইউসুফ কারা-সঙ্গীদের কাছে তাওহিদ নিশ্চিত করেন।" },
      { ref: "95:8", noteEn: "A-laysa-llahu bi-ahkami-l-Hakimin — Is not Allah the Most Just of all judges? A rhetorical affirmation.", noteBn: "আলায়সাল্লাহু বিআহকামিল-হাকিমিন — আল্লাহ কি সব বিচারকের মধ্যে সর্বোত্তম নন? অলঙ্কারিক নিশ্চিতকরণ।" }
    ]},
  { n: 29, ar: "الْعَدْلُ", translit: "Al-ʿAdl", meanings: { en: "The Just", bn: "ন্যায়বিচারক", fr: "Le Juste", id: "Yang Maha Adil", ur: "عادل", tr: "Mutlak Adil", ar: "العادل في حكمه" , zh: '正義者', ja: '絶対的に正しきもの'},
    explain: { en: "Al-'Adl is absolute justice — not approximation, not compromise, not cultural interpretation. Every decree of Allah is perfectly just, even when human minds cannot comprehend its justice. Ibn al-Qayyim writes extensively in Shifa' al-'Alil that understanding divine justice requires recognising that Allah's wisdom (hikmah) is the axis around which His justice revolves. The believer who trusts in Al-'Adl finds peace even in painful decrees, knowing they are never arbitrary.", bn: "আল-আদল হলো পরম ন্যায়বিচার — আনুমানিক নয়, আপোষমূলক নয়। আল্লাহর প্রতিটি ফয়সালা নিখুঁতভাবে ন্যায্য, এমনকি যখন মানব মন তার ন্যায্যতা বুঝতে পারে না। ইবনুল কাইয়িম লিখেছেন যে আল্লাহর প্রজ্ঞাই তাঁর ন্যায়বিচারের কেন্দ্রধুরা।" },
    hadith: { en: "O My servants, I have forbidden injustice for Myself and have made it forbidden amongst you, so do not oppress one another.", bn: "হে আমার বান্দারা, আমি নিজের জন্য জুলুমকে হারাম করেছি এবং তোমাদের মধ্যেও এটিকে হারাম করেছি, তাই তোমরা একে অপরের প্রতি জুলুম করো না।", src: "Sahih Muslim 2577 (Hadith Qudsi)" } ,
    quranicRefs: [
      { ref: "4:40", noteEn: "Inna-llaha la yazlimu mithqala dharratin — Allah does not wrong anyone an atom's weight; the foundation of divine justice.", noteBn: "ইন্নাল্লাহা লা ইয়াযলিমু মিছকালা যার্রাতিন — আল্লাহ কাউকে অণু পরিমাণও অন্যায় করেন না।" },
      { ref: "6:115", noteEn: "Wa tammat kalimatu Rabbika sidqan wa adlan — Your Lord's word is complete in truth and justice.", noteBn: "ওয়া তাম্মাত কালিমাতু রাব্বিকা সিদকান ওয়া আদলান — তোমার প্রভুর কথা সত্য ও ন্যায়বিচারে পূর্ণ।" },
      { ref: "16:90", noteEn: "Inna-llaha ya'muru bil-adl wal-ihsan — Allah commands justice and excellence; He embodies what He commands.", noteBn: "ইন্নাল্লাহা ইয়ামুরু বিল-আদলি ওয়াল-ইহসান — আল্লাহ ন্যায় ও উৎকর্ষের আদেশ দেন; তিনি নিজেই তা মূর্ত।" }
    ]},
  { n: 30, ar: "اللَّطِيفُ", translit: "Al-Laṭīf", meanings: { en: "The Subtle One", bn: "সূক্ষ্মদর্শী", fr: "Le Doux", id: "Yang Maha Lembut", ur: "باریک بین مہربان", tr: "Lütufkâr", ar: "اللطيف بعباده" , zh: '微妙者', ja: '小さな親切'},
    explain: { en: "Al-Latif is one of the most profound names, combining two meanings: the One who perceives the most subtle and minute details of everything, and the One who is gentle, kind, and gracious in His dealings — reaching His servants through pathways so subtle they may not even notice. Quran 6:103 states: 'No vision can grasp Him, but His grasp is over all vision; He is Al-Latif, the All-Aware.' Al-Ghazali wrote that this name describes Allah reaching into the depths of every situation with a touch so delicate it transforms without disturbing.", bn: "আল-লাতিফ সবচেয়ে গভীর নামগুলির একটি, দুটি অর্থ একত্রিত করে: যিনি সবকিছুর সূক্ষ্মতম বিবরণ উপলব্ধি করেন, এবং যিনি তাঁর আচরণে কোমল, দয়ালু ও অনুগ্রহশীল।" },
    invoke: { en: "When facing a complex situation that seems to have no good solution, call upon 'Ya Latif' repeatedly. Recite Quran 12:100 where Prophet Yusuf (as) says 'Inna Rabbi Latifun lima yasha' — my Lord is subtle in fulfilling what He wills. His help often arrives through unexpected, gentle pathways.", bn: "যখন জটিল পরিস্থিতিতে কোনো ভালো সমাধান নেই বলে মনে হয়, বারবার 'ইয়া লাতিফ' বলুন। কুরআন ১২:১০০ পড়ুন যেখানে নবী ইউসুফ (আ.) বলেন: 'ইন্না রাব্বি লাতিফুন লিমা ইয়াশা।' তাঁর সাহায্য প্রায়ই অপ্রত্যাশিত, কোমল পথে আসে।" } ,
    quranicRefs: [
      { ref: "6:103", noteEn: "La tudrikuhu-l-absaru wa Huwa-l-Latif-ul-Khabir — vision cannot grasp Him; He is Al-Latif and Al-Khabir.", noteBn: "লা তুদরিকুহুল-আবসারু ওয়া হুওয়াল-লাতিফুল-খাবির — দৃষ্টি তাঁকে আয়ত্ত করতে পারে না।" },
      { ref: "12:100", noteEn: "Inna Rabbi Latifun lima yasha — My Lord is Latif in fulfilling what He wills; Yusuf's gratitude after years of trial.", noteBn: "ইন্না রাব্বি লাতিফুন লিমা ইয়াশা — আমার প্রভু তাঁর ইচ্ছা পূরণে লাতিফ; পরীক্ষার পরে ইউসুফের কৃতজ্ঞতা।" },
      { ref: "22:63", noteEn: "Inna-llaha Latifun Khabir — declared when Allah sends rain and revives dead earth with green.", noteBn: "ইন্নাল্লাহা লাতিফুন খাবির — আল্লাহর বৃষ্টিতে মৃত পৃথিবী সবুজ হওয়ার প্রসঙ্গে।" },
      { ref: "31:16", noteEn: "Inna-llaha Latifun Khabir — even a mustard seed's deed hidden in rock will be brought forth by Al-Latif.", noteBn: "ইন্নাল্লাহা লাতিফুন খাবির — পাথরে লুকানো সরিষা দানা পরিমাণ কর্মও আল-লাতিফ বের করবেন।" },
      { ref: "42:19", noteEn: "Allahu Latifun bi-ibadihi yarzuqu man yasha — Allah is Latif toward His servants, providing for whom He wills.", noteBn: "আল্লাহু লাতিফুন বিইবাদিহি ইয়ারযুকু মান ইয়াশা — আল্লাহ তাঁর বান্দাদের প্রতি লাতিফ, যাকে চান রিজিক দেন।" }
    ]},
  { n: 31, ar: "الْخَبِيرُ", translit: "Al-Khabīr", meanings: { en: "The All-Aware", bn: "সর্বজ্ঞাত", fr: "Le Bien-Informé", id: "Yang Maha Mengenal", ur: "خبردار", tr: "Her Şeyden Haberdar", ar: "العليم ببواطن الأمور" , zh: '全知者', ja: '全てを認知せし者'},
    explain: { en: "Al-Khabir is the One who possesses profound inner knowledge (khibra) — not just surface awareness but the deep insider knowledge of hidden realities, motivations, and ultimate consequences. Al-'Alim knows what things are; Al-Khabir knows the inner nature and hidden states of things. Quran 31:16 tells Luqman's son: 'O my son, if a deed should be the weight of a mustard seed, and should be within a rock or in the heavens or in the earth, Allah will bring it forth. Indeed, Allah is Subtle and Acquainted (Khabir).'", bn: "আল-খাবির হলেন যিনি গভীর অভ্যন্তরীণ জ্ঞান (খিবরা) রাখেন — কেবল পৃষ্ঠীয় সচেতনতা নয় বরং লুকানো বাস্তবতার গভীর জ্ঞান। কুরআন ৩১:১৬-এ লুকমান তার পুত্রকে বলেন: 'হে আমার পুত্র, যদি সরিষার দানা পরিমাণও কোনো কাজ হয়... আল্লাহ তা নিয়ে আসবেন।'" } ,
    quranicRefs: [
      { ref: "6:18", noteEn: "Wa Huwa-l-Qahiru fawqa ibadihi wa Huwa-l-Hakim-ul-Khabir — He is supreme over His servants; Al-Hakim, Al-Khabir.", noteBn: "ওয়া হুওয়াল-কাহিরু ফাওকা ইবাদিহি ওয়া হুওয়াল-হাকিমুল-খাবির — বান্দাদের উপরে সর্বোচ্চ; আল-হাকিম, আল-খাবির।" },
      { ref: "11:1", noteEn: "The Quran is from Hakim and Khabir — wisdom and inner knowledge are the twin sources of revelation.", noteBn: "কুরআন হাকিম ও খাবিরের কাছ থেকে — প্রজ্ঞা ও অভ্যন্তরীণ জ্ঞান ওহির যমজ উৎস।" },
      { ref: "17:30", noteEn: "Inna-hu kana bi-ibadihi Khabiran Basira — He is Khabir and Basir regarding His servants; He knows provision's wisdom.", noteBn: "ইন্নাহু কানা বিইবাদিহি খাবিরান বাসিরা — তিনি তাঁর বান্দাদের সম্পর্কে খাবির ও বাসির।" },
      { ref: "49:13", noteEn: "Inna-llaha Alimun Khabir — the most honoured is the most God-fearing; Al-Khabir verifies inner reality.", noteBn: "ইন্নাল্লাহা আলিমুন খাবির — সবচেয়ে সম্মানিত সে যে সবচেয়ে বেশি আল্লাহভীরু; আল-খাবির অভ্যন্তরীণ বাস্তবতা যাচাই করেন।" }
    ]},
  { n: 32, ar: "الْحَلِيمُ", translit: "Al-Ḥalīm", meanings: { en: "The Forbearing", bn: "মহাসহনশীল", fr: "Le Longanime", id: "Yang Maha Penyantun", ur: "بردبار", tr: "Çok Hoşgörülü", ar: "الذي لا يعجل بالعقوبة" , zh: '克制者、寬大者', ja: '寛容なる者'},
    explain: { en: "Al-Halim is the One who withholds immediate punishment despite being fully capable of it, giving servants time to repent and reform. This is not weakness but the highest form of strength — restraining power out of wisdom and mercy. Every day that passes without divine punishment of sins is a manifestation of Al-Halim. Ibn al-Qayyim writes that Al-Halim's forbearance should motivate genuine repentance, not complacency, because punishment is not cancelled but deferred.", bn: "আল-হালিম হলেন যিনি সম্পূর্ণ সক্ষম হওয়া সত্ত্বেও তাৎক্ষণিক শাস্তি বিরত রাখেন, বান্দাদের তওবা ও সংশোধনের সুযোগ দেন। এটি দুর্বলতা নয় বরং শক্তির সর্বোচ্চ রূপ। প্রতিটি দিন যা পাপের তাৎক্ষণিক শাস্তি ছাড়া কেটে যায় আল-হালিমের প্রকাশ।" } ,
    hadith: { en: "At times of distress the Prophet ﷺ would say: 'La ilaha illa Allahu-l-'Azimu-l-Halim (there is no god but Allah, the Magnificent, the Forbearing), la ilaha illa Allahu Rabbu-l-'arshi-l-'azim.'", bn: "বিপদের সময় নবী ﷺ বলতেন: 'লা ইলাহা ইল্লাল্লাহুল-আযিমুল-হালিম (মহান ও সহনশীল আল্লাহ ছাড়া কোনো ইলাহ নেই), লা ইলাহা ইল্লাল্লাহু রাব্বুল-আরশিল-আযিম।'", src: "Sahih al-Bukhari 6346; Sahih Muslim 2730" },
    quranicRefs: [
      { ref: "2:225", noteEn: "Wa-llahu Ghafurun Halim — Allah is Ghafur and Halim regarding unintentional oaths; forbearance covers honest mistakes.", noteBn: "ওয়াল্লাহু গাফুরুন হালিম — অনিচ্ছাকৃত শপথে আল্লাহ গাফুর ও হালিম; সহিষ্ণুতা সৎ ভুল ঢেকে রাখে।" },
      { ref: "2:235", noteEn: "Wa-lamu anna-llaha Ghafurun Halim — know that Allah is Ghafur and Halim; forbearance gives time for correction.", noteBn: "ওয়াআলামু আন্নাল্লাহা গাফুরুন হালিম — আল্লাহ গাফুর ও হালিম; সহিষ্ণুতা সংশোধনের সময় দেয়।" },
      { ref: "3:155", noteEn: "Inna-llaha Ghafurun Halim — after the setback at Uhud, reassuring that flight was forgiven by Al-Halim.", noteBn: "ইন্নাল্লাহা গাফুরুন হালিম — উহুদ বিপর্যয়ের পরে, পলায়ন আল-হালিমের দ্বারা ক্ষমা করা হয়েছে।" },
      { ref: "4:12", noteEn: "Wa-llahu Alimun Halim — knowledge and forbearance paired in inheritance laws, showing compassion for human complexity.", noteBn: "ওয়াল্লাহু আলিমুন হালিম — উত্তরাধিকার আইনে জ্ঞান ও সহিষ্ণুতা যুগলে, মানবিক জটিলতায় সহানুভূতি।" },
      { ref: "22:59", noteEn: "La Aliman Halima — He will admit martyrs with good reward; He is Al-Alim and Al-Halim.", noteBn: "লা আলিমান হালিমা — তিনি শহীদদের ভালো রিজিক সহ প্রবেশ করাবেন; তিনি আল-আলিম ও আল-হালিম।" }
    ]},
  { n: 33, ar: "الْعَظِيمُ", translit: "Al-ʿAẓīm", meanings: { en: "The Magnificent", bn: "মহান", fr: "Le Magnifique", id: "Yang Maha Agung", ur: "عظمت والا", tr: "Pek Yüce", ar: "العظيم في كل شيء" , zh: '絕崇者', ja: '壮大なる者、無限なる者'},
    explain: { en: "Al-'Azim denotes a greatness so vast that all of creation together is less than a speck before it. The Prophet (peace be upon him) taught 'Subhana Rabbiya al-'Azim' in ruku' (bowing) in prayer, instructing that this specific moment of physical humility should be accompanied by this specific acknowledgment of divine greatness. Ayat al-Kursi (2:255) concludes with 'Wa Huwa al-'Aliyy al-'Azim' — tying boundless knowledge to infinite greatness.", bn: "আল-আযিম এমন মহত্ত্ব বোঝায় যার সামনে সমগ্র সৃষ্টি একটি বিন্দুর চেয়েও কম। নবী (সা.) রুকুতে 'সুবহানা রাব্বিয়াল-আযিম' পড়তে শিখিয়েছেন — শারীরিক বিনম্রতার এই বিশেষ মুহূর্তে ঐশ্বরিক মহত্ত্বের স্বীকৃতি দেওয়া হয়।" },
    hadith: { en: "Two words are light on the tongue, heavy in the balance, and beloved to the Most Merciful: Subhan-Allahi wa bi-hamdihi, Subhan-Allahi al-'Azim.", bn: "দুটি কথা জিহ্বায় হালকা, মিজানে ভারী এবং রহমানের কাছে প্রিয়: সুবহানাল্লাহি ওয়া বিহামদিহি, সুবহানাল্লাহিল-আযিম।", src: "Sahih al-Bukhari 6682; Sahih Muslim 2694" } ,
    quranicRefs: [
      { ref: "2:255", noteEn: "Wa Huwa-l-Aliyy-ul-Azim — the Throne Verse closes with Al-Azim after the fullest description of divine attributes.", noteBn: "ওয়া হুওয়াল-আলিয়্যুল-আযিম — আয়াতুল কুরসি ঐশ্বরিক গুণের পূর্ণ বর্ণনার পরে আল-আযিম দিয়ে শেষ।" },
      { ref: "42:4", noteEn: "Wa Huwa-l-Aliyy-ul-Azim — all in heavens and earth belongs to Him; He is Most High, Most Great.", noteBn: "ওয়া হুওয়াল-আলিয়্যুল-আযিম — আকাশ-পৃথিবীর সব তাঁর; তিনি সর্বোচ্চ, সর্বমহান।" },
      { ref: "56:74", noteEn: "fa-sabbih bi-smi Rabbika-l-Azim — glorify your Lord Al-Azim; the prescribed tasbih of ruku in prayer.", noteBn: "ফাসাব্বিহ বিসমি রাব্বিকাল-আযিম — প্রভু আল-আযিমের তাসবিহ করো; নামাজে রুকুর নির্ধারিত তাসবিহ।" },
      { ref: "56:96", noteEn: "fa-sabbih bi-smi Rabbika-l-Azim — repeated at surah's end, bookending the eschatological account.", noteBn: "ফাসাব্বিহ বিসমি রাব্বিকাল-আযিম — সূরার শেষে পুনরাবৃত্তি, পরলৌকিক বর্ণনা আল-আযিম দিয়ে আবদ্ধ।" }
    ]},
  { n: 34, ar: "الْغَفُورُ", translit: "Al-Ghafūr", meanings: { en: "The All-Forgiving", bn: "ক্ষমাপরায়ণ", fr: "Le Pardonneur", id: "Yang Maha Pengampun", ur: "بخشنے والا", tr: "Bağışlayıcı", ar: "الساتر للذنوب" , zh: '永恕者', ja: '全てを受け入れしもの'},
    explain: { en: "Al-Ghafur describes the totality of Allah's forgiveness — sins are not just overlooked but truly erased, covered, and removed as if they never happened. The difference from Al-Ghaffar is one of intensity: Al-Ghaffar is habitual, repeated forgiveness; Al-Ghafur is comprehensive, all-covering forgiveness. Quran 39:53 is the strongest promise: 'Say, O My servants who have transgressed against themselves, do not despair of the mercy of Allah. Indeed, Allah forgives all sins.' This was revealed as a universal invitation, not limited to any category of sin.", bn: "আল-গাফুর আল্লাহর ক্ষমার সামগ্রিকতা বর্ণনা করে — পাপগুলি কেবল উপেক্ষা করা নয় বরং সত্যিই মুছে দেওয়া হয়, ঢেকে দেওয়া হয়। কুরআন ৩৯:৫৩ সবচেয়ে শক্তিশালী প্রতিশ্রুতি: 'বলো, হে আমার বান্দারা যারা নিজেদের উপর অতিরিক্ত করেছ, আল্লাহর রহমত থেকে হতাশ হয়ো না।'" },
    hadith: { en: "If you were to commit sin until your sins reached the heaven, then you were to ask Allah for forgiveness, He would forgive you.", bn: "যদি তুমি এত পাপ করো যে পাপ আকাশ পর্যন্ত পৌঁছে যায়, তারপর আল্লাহর কাছে ক্ষমা চাও, তিনি তোমাকে ক্ষমা করবেন।", src: "Sunan ibn Majah 4248; al-Tirmidhi 3540 (Sahih)" } ,
    quranicRefs: [
      { ref: "2:173", noteEn: "Inna-llaha Ghafurun Rahim — paired with Ar-Rahim in rulings on necessity; mercy governs the law.", noteBn: "ইন্নাল্লাহা গাফুরুন রাহিম — প্রয়োজনীয়তার বিধানে আর-রাহিমের সাথে; রহমত আইন পরিচালনা করে।" },
      { ref: "35:28", noteEn: "Inna-llaha Azizun Ghafur — might and forgiveness together; power does not preclude mercy.", noteBn: "ইন্নাল্লাহা আযিযুন গাফুর — শক্তি ও ক্ষমা একসাথে; শক্তি রহমতকে বাধা দেয় না।" },
      { ref: "39:53", noteEn: "Inna-llaha yaghfiru-dh-dhunuba jami'a — Allah forgives ALL sins; the broadest forgiveness promise in the Quran.", noteBn: "ইন্নাল্লাহা ইয়াগফিরুয-যুনুবা জামিআ — আল্লাহ সব পাপ মাফ করেন; কুরআনের সবচেয়ে ব্যাপক ক্ষমার প্রতিশ্রুতি।" },
      { ref: "64:14", noteEn: "wa-in ta'fu wa-tasfahhu wa-taghfiru fa-inna-llaha Ghafurun Rahim — if you pardon, Allah is Ghafur and Rahim.", noteBn: "ওয়াইন তাআফু ওয়াতাসফাহু ওয়াতাগফিরু ফাইন্নাল্লাহা গাফুরুন রাহিম — ক্ষমা করলে আল্লাহ গাফুর ও রাহিম।" }
    ]},
  { n: 35, ar: "الشَّكُورُ", translit: "Ash-Shakūr", meanings: { en: "The Appreciative", bn: "গুণগ্রাহী", fr: "Le Reconnaissant", id: "Yang Maha Mensyukuri", ur: "قدر دان", tr: "Şükre Karşılık Veren", ar: "المجازي على القليل بالكثير" , zh: '受謝者', ja: '感謝される者'},
    explain: { en: "Ash-Shakur is a remarkable name: Allah is the One who is deeply appreciative of even the smallest good deed and rewards it with a return far exceeding what was offered. A human cannot truly 'give' Allah anything — yet He acknowledges and rewards every atom of sincerity. The Quran (35:30) says He 'rewards them fully and increases them of His bounty.' Al-Ghazali writes that knowing this name transforms worship: even a tiny sincere deed is not wasted before Allah.", bn: "আশ-শাকুর একটি উল্লেখযোগ্য নাম: আল্লাহ ক্ষুদ্রতম ভালো কাজেরও গভীরভাবে কদর করেন এবং প্রদত্তের চেয়ে অনেক বেশি পুরস্কৃত করেন। কুরআন (৩৫:৩০) বলে তিনি 'তাদের পূর্ণ পুরস্কার দেন এবং তাঁর অনুগ্রহ থেকে বৃদ্ধি করেন।'" } ,
    quranicRefs: [
      { ref: "35:30", noteEn: "Inna-hu Ghafurun Shakur — Forgiving and Appreciative; Allah appreciates even the deeds He forgave.", noteBn: "ইন্নাহু গাফুরুন শাকুর — ক্ষমাশীল ও কদরদানী; আল্লাহ যে কর্মগুলো ক্ষমা করেছেন সেগুলোরও মূল্য দেন।" },
      { ref: "35:34", noteEn: "Inna Rabbana la-Ghafurun Shakur — the people of Paradise praise their Lord who is Ghafur and Shakur.", noteBn: "ইন্না রাব্বানা লা-গাফুরুন শাকুর — জান্নাতের অধিবাসীরা প্রভুর প্রশংসা করে যিনি গাফুর ও শাকুর।" },
      { ref: "42:23", noteEn: "Inna-llaha Ghafurun Shakur — Allah rewards good deeds and appreciates even the smallest sincere act.", noteBn: "ইন্নাল্লাহা গাফুরুন শাকুর — আল্লাহ সৎকর্মের পুরস্কার দেন এবং ক্ষুদ্রতম আন্তরিক কাজেরও কদর করেন।" },
      { ref: "64:17", noteEn: "Wa-llahu Shakurun Halim — Allah is Ash-Shakur and Al-Halim; He rewards charity with appreciation and patience.", noteBn: "ওয়াল্লাহু শাকুরুন হালিম — আল্লাহ আশ-শাকুর ও আল-হালিম; দাতব্যকর্ম কৃতজ্ঞতা ও ধৈর্যের সাথে পুরস্কৃত।" }
    ]},
  { n: 36, ar: "الْعَلِيُّ", translit: "Al-ʿAliyy", meanings: { en: "The Most High", bn: "সর্বোচ্চ", fr: "Le Très-Haut", id: "Yang Maha Tinggi", ur: "سب سے بلند", tr: "Pek Yüksek", ar: "العالي فوق خلقه" , zh: '崇高者', ja: '高貴で崇高なる者'},
    explain: { en: "Al-'Aliyy is supremely high in essence, attributes, and status — not physically 'above' in a spatial sense, but ontologically transcendent over all creation. Ayat al-Kursi ends with 'al-'Aliyy al-'Azim' (2:255), connecting this name with supreme greatness. Ibn al-Qayyim distinguishes three types of 'uluww (highness): highness in essence ('uluww al-dhat), highness in attributes ('uluww al-sifat), and highness in power and domination ('uluww al-qahr) — Allah possesses all three absolutely.", bn: "আল-আলিয়্যু মূলে, গুণাবলীতে এবং মর্যাদায় সর্বোচ্চ। আয়াতুল কুরসি 'আল-আলিয়্যু আল-আযিম' (২:২৫৫) দিয়ে শেষ হয়। ইবনুল কাইয়িম তিন ধরনের উচ্চতা পৃথক করেছেন: সত্তার উচ্চতা, গুণাবলীর উচ্চতা এবং ক্ষমতার উচ্চতা — আল্লাহ তিনটিই পরম মাত্রায় রাখেন।" } ,
    quranicRefs: [
      { ref: "2:255", noteEn: "Wa Huwa-l-Aliyy-ul-Azim — the Throne Verse's closing pair: supreme in transcendence and greatness.", noteBn: "ওয়া হুওয়াল-আলিয়্যুল-আযিম — আয়াতুল কুরসির সমাপ্তি জুটি: অতীন্দ্রিয়তা ও মহত্ত্বে সর্বোচ্চ।" },
      { ref: "4:34", noteEn: "Inna-llaha kana Aliyyan Kabira — Allah is Al-Aliyy, Al-Kabir, in the context of authority and family relations.", noteBn: "ইন্নাল্লাহা কানা আলিয়্যান কাবিরা — আল্লাহ আল-আলিয়্যু, আল-কাবির, কর্তৃত্ব ও পারিবারিক সম্পর্কের প্রসঙ্গে।" },
      { ref: "22:62", noteEn: "Dhalika bi-anna-llaha Huwa-l-Haqq... wa anna-llaha Huwa-l-Aliyy-ul-Kabir — truth and highness affirmed together.", noteBn: "যালিকা বিআন্নাল্লাহা হুওয়াল-হাক্ক... ওয়া আন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — সত্য ও উচ্চতা একসাথে।" },
      { ref: "31:30", noteEn: "Wa anna-llaha Huwa-l-Aliyy-ul-Kabir — Al-Haqq, Al-Aliyy, Al-Kabir together; falsehood is vain beside His highness.", noteBn: "ওয়া আন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — আল-হাক্ক, আল-আলিয়্যু, আল-কাবির একসাথে; তাঁর উচ্চতার পাশে মিথ্যা অসার।" },
      { ref: "42:4", noteEn: "Wa Huwa-l-Aliyy-ul-Azim — all creation belongs to Him; He is Most High and Most Great above His creation.", noteBn: "ওয়া হুওয়াল-আলিয়্যুল-আযিম — সমস্ত সৃষ্টি তাঁর; তিনি সৃষ্টির উপরে সর্বোচ্চ ও সর্বমহান।" }
    ]},
  { n: 37, ar: "الْكَبِيرُ", translit: "Al-Kabīr", meanings: { en: "The Most Great", bn: "সুমহান", fr: "Le Très Grand", id: "Yang Maha Besar", ur: "سب سے بڑا", tr: "Pek Büyük", ar: "الكبير المتعال" , zh: '偉大者', ja: '偉大なる者'},
    explain: { en: "Al-Kabir describes a greatness inherent in Allah's being — not greatness measured against something else, but self-subsisting divine magnificence. The Quran (13:9) pairs Al-Kabir with Al-Muta'al: 'the Most Great, the Most High.' Human greatness is relative and borrowed; Allah's greatness is absolute and self-originating. Recognising Al-Kabir helps the servant calibrate all other greatness: every king, nation, and star is infinitesimally small before Al-Kabir.", bn: "আল-কাবির আল্লাহর সত্তার অন্তর্নিহিত মহত্ত্ব বর্ণনা করে — অন্য কিছুর বিপরীতে পরিমাপ করা মহত্ত্ব নয়, বরং স্বনির্ভর ঐশ্বরিক মহিমা। কুরআন (১৩:৯) আল-কাবিরকে আল-মুতাআলের সাথে জুড়ে দেয়।" } ,
    quranicRefs: [
      { ref: "13:9", noteEn: "Alim-ul-ghaybi wal-shahada Al-Kabir-ul-Muta'al — Knower of the unseen and seen, Most Great, Most Exalted.", noteBn: "আলিমুল-গায়বি ওয়াশ-শাহাদাতিল-কাবিরুল-মুতাআল — অদৃশ্য ও দৃশ্যের জ্ঞানী, মহান, সর্বোচ্চ।" },
      { ref: "22:62", noteEn: "Wa anna-llaha Huwa-l-Aliyy-ul-Kabir — Allah is Most High and Most Great; all worshipped besides Him is falsehood.", noteBn: "ওয়া আন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — আল্লাহ সর্বোচ্চ ও মহান; তাঁর পরিবর্তে যা পূজা হয় মিথ্যা।" },
      { ref: "31:30", noteEn: "Wa anna-llaha Huwa-l-Aliyy-ul-Kabir — divine truth versus falsehood; Al-Kabir affirms absolute greatness.", noteBn: "ওয়া আন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — ঐশ্বরিক সত্য বনাম মিথ্যা; আল-কাবির পরম মহত্ত্ব নিশ্চিত করে।" },
      { ref: "34:23", noteEn: "Inna-llaha Huwa-l-Aliyy-ul-Kabir — intercession avails only with His permission; His greatness is ultimate.", noteBn: "ইন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — তাঁর অনুমতি ছাড়া কোনো সুপারিশ কাজে আসে না।" },
      { ref: "40:12", noteEn: "Dhalika bi-anna-llaha Huwa-l-Aliyy-ul-Kabir — the final verdict on the Day of Judgement affirms His supreme greatness.", noteBn: "যালিকা বিআন্নাল্লাহা হুওয়াল-আলিয়্যুল-কাবির — কিয়ামতের চূড়ান্ত রায় তাঁর সর্বোচ্চ মহত্ত্ব নিশ্চিত করে।" }
    ]},
  { n: 38, ar: "الْحَفِيظُ", translit: "Al-Ḥafīẓ", meanings: { en: "The Preserver", bn: "মহারক্ষক", fr: "Le Gardien", id: "Yang Maha Menjaga", ur: "حفاظت کرنے والا", tr: "Koruyup Gözeten", ar: "الحافظ لكل شيء" , zh: '保護者', ja: '管理せし者'},
    explain: { en: "Al-Hafiz preserves everything — the Quran from corruption, the universe from disintegration, the righteous from ruin, and the deeds of every person for the reckoning. The Quran (86:4) states: 'There is no soul but that it has over it a protector.' Prophet Ya'qub (Jacob, peace be upon him) entrusted his sons to 'Khayru-l-Hafizin' (the Best of Preservers, Quran 12:64) when sending them to Egypt. Knowing this name builds reliance on Allah's protection above all human precautions.", bn: "আল-হাফিজ সবকিছু সংরক্ষণ করেন — কুরআনকে বিকৃতি থেকে, মহাবিশ্বকে ভাঙন থেকে, ধার্মিকদের ধ্বংস থেকে। কুরআন (৮৬:৪) বলে: 'এমন কোনো আত্মা নেই যার উপর একজন রক্ষক নেই।'" } ,
    quranicRefs: [
      { ref: "11:57", noteEn: "Inna Rabbi ala kulli shay'in Hafiz — My Lord is Preserver over all things; Hud's declaration of divine guardianship.", noteBn: "ইন্না রাব্বি আলা কুল্লি শায়িন হাফিজ — আমার প্রভু সব কিছুর হাফিজ; হুদের ঐশ্বরিক অভিভাবকত্বের ঘোষণা।" },
      { ref: "12:64", noteEn: "fa-Allahu Khayru Hafizin — Allah is the Best of Preservers; Ya'qub entrusts his sons to Al-Hafiz.", noteBn: "ফাল্লাহু খায়রুন হাফিজান — আল্লাহ সর্বোত্তম হাফিজ; ইয়াকুব তার পুত্রদের আল-হাফিজের কাছে সমর্পণ করেন।" },
      { ref: "34:21", noteEn: "Wa Rabbuka ala kulli shay'in Hafiz — Your Lord is Preserver of all; affirmed regarding Shaytan's limited power.", noteBn: "ওয়া রাব্বুকা আলা কুল্লি শায়িন হাফিজ — তোমার প্রভু সব কিছুর হাফিজ; শয়তানের সীমিত ক্ষমতার প্রসঙ্গে।" },
      { ref: "86:4", noteEn: "In kullu nafsin lamma alayha hafizun — over every soul there is a Preserver; divine guardianship is universal.", noteBn: "ইন কুল্লু নাফসিন লাম্মা আলায়হা হাফিজুন — প্রতিটি আত্মার উপরে একজন হাফিজ; ঐশ্বরিক অভিভাবকত্ব সর্বজনীন।" }
    ]},
  { n: 39, ar: "الْمُقِيتُ", translit: "Al-Muqīt", meanings: { en: "The Sustainer", bn: "আহারদাতা", fr: "Le Nourricier", id: "Yang Maha Pemberi Kecukupan", ur: "روزی پہنچانے والا", tr: "Azık Veren", ar: "المتكفل بالأقوات" , zh: '給養者', ja: '栄養を与えし者'},
    explain: { en: "Al-Muqit means the One who provides the specific sustenance (qut) each creature needs — physical food for the body, spiritual nourishment for the soul, knowledge for the intellect. The root qawt refers to the minimum necessary sustenance, suggesting Allah provides precisely what each being needs. Al-Ghazali notes that Al-Muqit is more specific than Ar-Razzaq: while Ar-Razzaq is the general Provider, Al-Muqit is the precise Sustainer who tailors each provision.", bn: "আল-মুকিত অর্থ যিনি প্রতিটি সৃষ্টির প্রয়োজনীয় নির্দিষ্ট রিজিক (কুত) সরবরাহ করেন — শরীরের জন্য শারীরিক খাদ্য, আত্মার জন্য আধ্যাত্মিক পুষ্টি, বুদ্ধির জন্য জ্ঞান। আল-গাজালী মন্তব্য করেন যে আল-মুকিত আর-রাজ্জাকের চেয়ে আরও নির্দিষ্ট।" } ,
    quranicRefs: [
      { ref: "4:85", noteEn: "Wa kana-llahu ala kulli shay'in Muqita — Allah is Muqit over all things; the only explicit Quranic mention.", noteBn: "ওয়া কানাল্লাহু আলা কুল্লি শায়িন মুকিতান — আল্লাহ সব কিছুর মুকিত; কুরআনে একমাত্র সরাসরি উল্লেখ।" }
    ]},
  { n: 40, ar: "الْحَسِيبُ", translit: "Al-Ḥasīb", meanings: { en: "The Reckoner", bn: "মহাহিসাবগ্রহণকারী", fr: "Celui qui compte", id: "Yang Maha Membuat Perhitungan", ur: "حساب لینے والا", tr: "Hesaba Çeken", ar: "الكافي المحاسِب" , zh: '計算者', ja: '計算する者'},
    explain: { en: "Al-Hasib has two connected meanings: the Reckoner who takes the most precise account of all deeds on the Day of Judgement, and the Sufficient One who suffices His servants and fulfills all their needs. Quran 4:6 says 'and Allah is sufficient as a Reckoner.' The believer who says 'hasbiyallah' (Allah is sufficient for me) is invoking Al-Hasib: the One whose account is perfect and whose sufficiency is complete.", bn: "আল-হাসিব-এর দুটি সংযুক্ত অর্থ আছে: যিনি কিয়ামতের দিন সমস্ত কাজের নিখুঁত হিসাব নেন, এবং যিনি তাঁর বান্দাদের জন্য যথেষ্ট। 'হাসবিয়াল্লাহ' (আল্লাহ আমার জন্য যথেষ্ট) বলার সময় আল-হাসিবকে ডাকা হয়।" },
    invoke: { en: "When overwhelmed by worry — about enemies, finances, or the future — say 'Hasbiyallahu la ilaha illa Huwa, 'alayhi tawakkaltu wa Huwa Rabb al-'Arsh al-'Azim' (Quran 9:129). This was the du'a of the Prophet (peace be upon him) in his most difficult moments.", bn: "যখন শত্রু, অর্থ বা ভবিষ্যৎ নিয়ে উদ্বেগ অভিভূত করে, বলুন: 'হাসবিয়াল্লাহু লা ইলাহা ইল্লা হুওয়া, আলায়হি তাওয়াক্কালতু ওয়া হুওয়া রাব্বুল আরশিল আযিম' (কুরআন ৯:১২৯)।" } ,
    quranicRefs: [
      { ref: "4:6", noteEn: "Wa kafa billahi Hasiba — Allah suffices as Reckoner for the distribution of orphans' wealth.", noteBn: "ওয়া কাফা বিল্লাহি হাসিবা — এতিমদের সম্পদ বিতরণে আল্লাহ হাসিব হিসেবে যথেষ্ট।" },
      { ref: "4:86", noteEn: "Inna-llaha kana ala kulli shay'in Hasiba — Allah is Hasib over all things; even responding to a greeting is accounted.", noteBn: "ইন্নাল্লাহা কানা আলা কুল্লি শায়িন হাসিবান — আল্লাহ সব কিছুর হাসিব; সালামের জবাবও হিসাব করা হয়।" },
      { ref: "17:14", noteEn: "Iqra kitabaka kafa bi-nafsika-l-yawm alayka Hasiba — read your record; you suffice today as Hasib against yourself.", noteBn: "ইকরা কিতাবাকা কাফা বিনাফসিকাল-ইয়াওমা আলায়কা হাসিবা — নথি পড়ো; আজকে তুমিই তোমার বিরুদ্ধে হাসিব।" },
      { ref: "33:39", noteEn: "Wa kafa billahi Hasiba — those who convey Allah's messages need fear only Him as the ultimate Hasib.", noteBn: "ওয়া কাফা বিল্লাহি হাসিবা — যারা আল্লাহর বার্তা পৌঁছায় তাদের কেবল পরম হাসিব আল্লাহকে ভয়।" }
    ]},
  { n: 41, ar: "الْجَلِيلُ", translit: "Al-Jalīl", meanings: { en: "The Majestic", bn: "মহামহিমান্বিত", fr: "Le Majestueux", id: "Yang Maha Luhur", ur: "بزرگی والا", tr: "Ululuk Sahibi", ar: "ذو الجلال والعظمة" , zh: '至尊者', ja: '雄大なる者'},
    explain: { en: "Al-Jalil describes divine majesty — the combination of supreme power, absolute transcendence, and infinite grandeur that inspires profound awe and reverence. It differs from Al-Kabir (greatness of size) and Al-'Azim (greatness of magnitude): Al-Jalil is the majesty that overwhelms the heart. The Quran ends Surah ar-Rahman (55:27) with 'Dhul-Jalali wal-Ikram' — Lord of Majesty and Honour — as a summarising title for all the blessings enumerated. True jalal (majesty) is Allah's alone.", bn: "আল-জালিল ঐশ্বরিক মহিমা বর্ণনা করে — সর্বোচ্চ ক্ষমতা, পরম অতীন্দ্রিয়তা এবং অসীম মহিমার সমন্বয় যা গভীর শ্রদ্ধা অনুপ্রাণিত করে। কুরআনের সূরা আর-রাহমান (৫৫:২৭) 'যুল-জালালি ওয়াল-ইকরাম' দিয়ে শেষ হয়।" } ,
    quranicRefs: [
      { ref: "55:27", noteEn: "Wa yabqa Wajhu Rabbika Dhu-l-Jalali wal-Ikram — the Face of your Lord, Owner of Jalal and Ikram, will remain.", noteBn: "ওয়া ইয়াবকা ওয়াজহু রাব্বিকা যুল-জালালি ওয়াল-ইকরাম — তোমার প্রভুর মুখমণ্ডল থাকবে।" },
      { ref: "55:78", noteEn: "Tabaraka-smu Rabbika Dhi-l-Jalali wal-Ikram — blessed is the name of your Lord, Owner of Jalal; closes Surah ar-Rahman.", noteBn: "তাবারাকাসমু রাব্বিকা যিল-জালালি ওয়াল-ইকরাম — তোমার প্রভুর নাম মুবারক; সূরা আর-রাহমান শেষ করে।" }
    ]},
  { n: 42, ar: "الْكَرِيمُ", translit: "Al-Karīm", meanings: { en: "The Generous", bn: "মহাঅনুগ্রহশীল", fr: "Le Généreux", id: "Yang Maha Pemurah", ur: "کرم کرنے والا", tr: "Cömert", ar: "الجواد المعطي" , zh: '慷慨者', ja: '寛大なる者'},
    explain: { en: "Al-Karim is generosity without limit, without condition, and without any expectation of return. Human generosity diminishes the giver; Allah's generosity increases Him in nothing but gives His servants everything. The Quran (82:6) addresses mankind: 'O mankind, what has deceived you concerning your Lord, Al-Karim?' — the very generosity that surrounds you should lead to gratitude, not ingratitude. Al-Ghazali writes that Al-Karim gives even before being asked, gives more than what is asked, and never mentions the gift afterwards.", bn: "আল-কারিম হলো সীমাহীন, শর্তহীন এবং প্রতিদানের কোনো প্রত্যাশা ছাড়া উদারতা। কুরআন (৮২:৬) মানবজাতিকে সম্বোধন করে: 'হে মানুষ, কী তোমাকে তোমার প্রভু আল-কারিম সম্পর্কে প্রতারিত করেছে?'" } ,
    hadith: { en: "The Prophet ﷺ said: 'Indeed your Lord is Modest and Most Generous (Hayyiyyun Karim); He is shy, when a man raises his hands to Him, to turn them back empty and disappointed.'", bn: "নবী ﷺ বলেন: 'নিশ্চয়ই তোমাদের রব লজ্জাশীল ও মহাদানশীল (হাইয়িয়্যুন কারিম); বান্দা যখন তাঁর দিকে হাত তোলে, তখন সেই হাত খালি ও নিরাশ ফিরিয়ে দিতে তিনি লজ্জাবোধ করেন।'", src: "Sunan Abi Dawud 1488; Jami' at-Tirmidhi 3556" },
    quranicRefs: [
      { ref: "27:40", noteEn: "Inna Rabbi Ghani-yun Karim — My Lord is Self-Sufficient and Al-Karim; Sulayman's gratitude for the brought throne.", noteBn: "ইন্না রাব্বি গানিয়্যুন কারিম — আমার প্রভু স্বনির্ভর ও আল-কারিম; আনা সিংহাসনে সুলায়মানের কৃতজ্ঞতা।" },
      { ref: "82:6", noteEn: "Ya ayyuha-l-insanu ma gharraka bi-Rabbika-l-Karim — what deceived you about your Lord, Al-Karim?", noteBn: "ইয়া আয়্যুহাল-ইনসানু মা গার্রাকা বিরাব্বিকাল-কারিম — কী তোমাকে প্রভু আল-কারিম সম্পর্কে প্রতারিত করেছে?" }
    ]},
  { n: 43, ar: "الرَّقِيبُ", translit: "Ar-Raqīb", meanings: { en: "The Watchful", bn: "সদা পর্যবেক্ষক", fr: "Le Vigilant", id: "Yang Maha Mengawasi", ur: "نگران", tr: "Gözetleyen", ar: "المطّلع على كل شيء" , zh: '鑒察者', ja: '用心深きもの'},
    explain: { en: "Ar-Raqib is the Watcher who never sleeps, never blinks, and never turns away — every action, thought, and intention is under His constant surveillance. Quran 4:1 ends with 'Indeed Allah is ever Watchful (Raqiban) over you,' and Quran 5:117 records Jesus (Isa, peace be upon him) saying 'You were the Watcher over them' to Allah. Al-Ghazali writes that internalising this name produces authentic muraqabah (spiritual watchfulness) — the highest station of worship.", bn: "আর-রাকিব হলেন সেই পর্যবেক্ষক যিনি কখনো ঘুমান না, কখনো পলক ফেলেন না। কুরআন ৪:১ শেষ হয় 'নিশ্চয়ই আল্লাহ তোমাদের উপর রাকিব' দিয়ে। আল-গাজালী লিখেছেন যে এই নামকে অভ্যন্তরীণ করা মুরাকাবা (আধ্যাত্মিক পর্যবেক্ষণ) উৎপন্ন করে।" },
    hadith: { en: "Worship Allah as though you see Him, and if you do not see Him, know that He sees you.", bn: "আল্লাহর ইবাদত করো যেন তুমি তাঁকে দেখছ, আর যদি তুমি তাঁকে না দেখো তাহলে জেনে রাখো যে তিনি তোমাকে দেখছেন।", src: "Sahih al-Bukhari 50; Sahih Muslim 8 (Hadith Jibril)" } ,
    quranicRefs: [
      { ref: "4:1", noteEn: "Inna-llaha kana alaykum Raqiba — Allah has been Watchful over you; affirmed in the verse on family rights.", noteBn: "ইন্নাল্লাহা কানা আলায়কুম রাকিবা — আল্লাহ তোমাদের উপর রাকিব; পারিবারিক অধিকারের আয়াতে নিশ্চিত।" },
      { ref: "5:117", noteEn: "Isa says: kunta Anta-r-Raqib alayhim — You were the Watcher over them after my departure.", noteBn: "ঈসা বলেন: কুনতা আনতার-রাকিবা আলায়হিম — আমার প্রস্থানের পরে আপনি তাদের উপর রাকিব ছিলেন।" },
      { ref: "33:52", noteEn: "Wa kana-llahu ala kulli shay'in Raqiba — Allah is Watchful over all things; affirmed for proper conduct.", noteBn: "ওয়া কানাল্লাহু আলা কুল্লি শায়িন রাকিবান — আল্লাহ সব কিছুর রাকিব; উপযুক্ত আচরণ প্রসঙ্গে।" }
    ]},
  { n: 44, ar: "الْمُجِيبُ", translit: "Al-Mujīb", meanings: { en: "The Responsive", bn: "দুআ কবুলকারী", fr: "Celui qui exauce", id: "Yang Maha Mengabulkan", ur: "دعا قبول کرنے والا", tr: "Duaları Kabul Eden", ar: "المجيب للدعاء" , zh: '答覆者', ja: '信頼できる者'},
    explain: { en: "Al-Mujib is the Responder who always answers — though not always in the manner or timing we expect. The Quran (2:186) says: 'And when My servants ask you concerning Me, I am indeed near. I respond to the call of the caller when he calls on Me.' The Prophet (peace be upon him) guaranteed: either the du'a is granted as asked, or equivalent harm is averted, or a reward is stored for the Hereafter. Al-Mujib never ignores a sincere call.", bn: "আল-মুজিব হলেন সাড়াদানকারী যিনি সর্বদা উত্তর দেন। কুরআন (২:১৮৬) বলে: 'আমার বান্দারা যখন তোমার কাছে আমার সম্পর্কে জিজ্ঞেস করে — আমি কাছে। আহ্বানকারী যখন আমাকে ডাকে আমি তার ডাকে সাড়া দিই।'" },
    invoke: { en: "Before making any du'a, address Allah as 'Ya Mujib' to strengthen your trust. The du'a of the Prophet Yunus (as) from the whale's belly — 'La ilaha illa Anta, Subhanaka, inni kuntu min al-zalimin' (21:87) — was answered because Al-Mujib heard it. Persist: the door is never closed.", bn: "যেকোনো দু'আ করার আগে 'ইয়া মুজিব' বলে সম্বোধন করুন। নবী ইউনুস (আ.)-এর দু'আ মাছের পেট থেকে — 'লা ইলাহা ইল্লা আনতা, সুবহানাকা, ইন্নি কুনতু মিনাজ-জালিমিন' (২১:৮৭) — উত্তর পেয়েছিল কারণ আল-মুজিব শুনেছিলেন।" } ,
    hadith: { en: "Allah the Exalted says: 'I am as My servant expects Me to be, and I am with him when he calls upon Me.'", bn: "আল্লাহ তাআলা বলেন: 'আমি আমার বান্দার ধারণা অনুযায়ী (তার সাথে আচরণ করি) এবং সে যখন আমাকে ডাকে আমি তার সাথে থাকি।'", src: "Sahih al-Bukhari 7405; Sahih Muslim 2675 (Hadith Qudsi)" },
    quranicRefs: [
      { ref: "2:186", noteEn: "Ujib-u da'wata-d-da'i idha da'ani — I respond to the call of the caller when he calls Me; the definitive promise of Al-Mujib.", noteBn: "উজিবু দাওয়াতাদ-দাই ইযা দাআনি — আহ্বানকারী ডাকলে আমি সাড়া দিই; আল-মুজিবের নির্ধারক প্রতিশ্রুতি।" },
      { ref: "11:61", noteEn: "Inna Rabbi Qarib-un Mujib — My Lord is Near and Responsive; Salih's affirmation when inviting his people.", noteBn: "ইন্না রাব্বি কারিবুন মুজিব — আমার প্রভু নিকটবর্তী ও মুজিব; জনগণকে আহ্বানে সালিহের নিশ্চিতকরণ।" }
    ]},
  { n: 45, ar: "الْوَاسِعُ", translit: "Al-Wāsiʿ", meanings: { en: "The All-Encompassing", bn: "সর্বব্যাপী", fr: "L'Ample", id: "Yang Maha Luas", ur: "وسعت والا", tr: "İlmi ve Rahmeti Geniş", ar: "الواسع الغني" , zh: '宽恩者', ja: '広大なる者、すべてを包み込みしもの'},
    explain: { en: "Al-Wasi' describes Allah's all-encompassing nature — His knowledge, mercy, generosity, and power have no boundary or limit. The Quran (2:115) says: 'Wherever you turn, there is the face of Allah; Indeed, Allah is All-Encompassing and All-Knowing.' No matter where a person turns in prayer, supplication, or need, they cannot be outside the sphere of Al-Wasi'. His mercy encloses and exceeds the cosmos itself.", bn: "আল-ওয়াসি আল্লাহর সর্বব্যাপী প্রকৃতি বর্ণনা করে। কুরআন (২:১১৫) বলে: 'তুমি যেদিকেই মুখ ফেরাও, সেখানেই আল্লাহর মুখ; নিশ্চয়ই আল্লাহ ওয়াসি, সর্বজ্ঞ।' কোনো দিকেই কোনো ব্যক্তি আল-ওয়াসি-এর পরিধির বাইরে যেতে পারে না।" } ,
    quranicRefs: [
      { ref: "2:115", noteEn: "Inna-llaha Wasi'un Alim — wherever you turn there is Allah's face; He is All-Encompassing and All-Knowing.", noteBn: "ইন্নাল্লাহা ওয়াসিউন আলিম — যেদিকে মুখ ফেরাও আল্লাহর মুখ; তিনি সর্বব্যাপী ও সর্বজ্ঞ।" },
      { ref: "2:261", noteEn: "Wa-llahu Wasi'un Alim — after charity multiplied 700-fold; Al-Wasi's encompassing generosity.", noteBn: "ওয়াল্লাহু ওয়াসিউন আলিম — দাতব্য ৭০০ গুণ বৃদ্ধির পরে; আল-ওয়াসির ব্যাপক উদারতা।" },
      { ref: "2:268", noteEn: "Wa-llahu Wasi'un Alim — Shaytan promises poverty, Allah promises forgiveness; His encompassing mercy surpasses fear.", noteBn: "ওয়াল্লাহু ওয়াসিউন আলিম — শয়তান দারিদ্র্যের প্রতিশ্রুতি দেয়, আল্লাহ ক্ষমার; তাঁর ব্যাপক রহমত ভয়কে ছাড়িয়ে।" },
      { ref: "3:73", noteEn: "Wa-llahu Wasi'un Alim — guidance and Allah's bounty are for whom He wills; His knowledge is encompassing.", noteBn: "ওয়াল্লাহু ওয়াসিউন আলিম — হেদায়েত ও অনুগ্রহ যাকে চান তার জন্য; তাঁর জ্ঞান সর্বব্যাপী।" },
      { ref: "5:54", noteEn: "Wa-llahu Wasi'un Alim — when He replaces the unfaithful with those He loves; divine encompassment chooses the sincere.", noteBn: "ওয়াল্লাহু ওয়াসিউন আলিম — অবিশ্বস্তদের প্রেমিকদের দিয়ে প্রতিস্থাপনে; ঐশ্বরিক সর্বব্যাপিতা আন্তরিকদের বেছে নেয়।" }
    ]},
  { n: 46, ar: "الْحَكِيمُ", translit: "Al-Ḥakīm", meanings: { en: "The All-Wise", bn: "মহাপ্রজ্ঞাময়", fr: "Le Sage", id: "Yang Maha Bijaksana", ur: "حکمت والا", tr: "Hikmet Sahibi", ar: "الحكيم في تدبيره" , zh: '睿智者', ja: '賢い者'},
    explain: { en: "Al-Hakim is the source of all wisdom (hikmah) — perfect knowledge perfectly applied. In the Quran, Al-Hakim is the second most frequently appearing name after Al-'Alim, often paired together: 'and Allah is All-Knowing, All-Wise.' This pairing shows that Allah's power of knowing (Al-'Alim) is always channeled through wisdom (Al-Hakim) — He does nothing arbitrary. Ibn al-Qayyim writes that accepting difficult divine decrees becomes easier when you trust that behind every decree is infinite wisdom.", bn: "আল-হাকিম সমস্ত প্রজ্ঞার উৎস — নিখুঁত জ্ঞান নিখুঁতভাবে প্রয়োগ। কুরআনে আল-হাকিম দ্বিতীয় সর্বাধিক আসা নাম, প্রায়ই আল-আলিমের সাথে জোড়ায়। ইবনুল কাইয়িম লিখেছেন যে কঠিন ঐশ্বরিক ফয়সালা গ্রহণ করা সহজ হয় যখন আপনি বিশ্বাস করেন যে প্রতিটি ফয়সালার পেছনে অসীম প্রজ্ঞা আছে।" },
    hadith: { en: "He whom Allah wills good for, He gives him understanding (fiqh) of the religion.", bn: "আল্লাহ যার জন্য ভালো চান, তাকে দ্বীনের গভীর বোঝাপড়া (ফিকহ) দেন।", src: "Sahih al-Bukhari 71; Sahih Muslim 1037" } ,
    quranicRefs: [
      { ref: "2:32", noteEn: "Inna-ka Anta-l-Alim-ul-Hakim — You are Al-Alim and Al-Hakim; the angels recognise these names as defining divine knowledge.", noteBn: "ইন্নাকা আনতাল-আলিমুল-হাকিম — আপনি আল-আলিম ও আল-হাকিম; ফেরেশতারা ঐশ্বরিক জ্ঞানের সংজ্ঞা হিসেবে।" },
      { ref: "3:62", noteEn: "Wa inna-llaha la-Huwa-l-Aziz-ul-Hakim — after the Isa narrative: power always paired with wisdom.", noteBn: "ওয়া ইন্নাল্লাহা লা-হুওয়াল-আযিযুল-হাকিম — ঈসার বর্ণনার পরে: শক্তি সর্বদা প্রজ্ঞার সাথে।" },
      { ref: "4:26", noteEn: "Wa-llahu Alimun Hakim — Allah wills to make guidance clear; He is Alim and Hakim in His legislation.", noteBn: "ওয়াল্লাহু আলিমুন হাকিম — আল্লাহ হেদায়েত স্পষ্ট করতে চান; তিনি আলিম ও হাকিম।" },
      { ref: "45:37", noteEn: "Wa Huwa-l-Aziz-ul-Hakim — His majesty fills the heavens and earth; He is Al-Aziz and Al-Hakim.", noteBn: "ওয়া হুওয়াল-আযিযুল-হাকিম — তাঁর মহিমা আকাশ-পৃথিবীতে; তিনি আল-আযিয ও আল-হাকিম।" },
      { ref: "46:2", noteEn: "Tanzil-ul-Kitab mina-llahi-l-Aziz-il-Hakim — the Quran is revealed from Allah, Al-Aziz and Al-Hakim; wisdom underlies every verse.", noteBn: "তানযিলুল-কিতাবি মিনাল্লাহিল-আযিযিল-হাকিম — কুরআন আল-আযিয আল-হাকিমের কাছ থেকে; প্রতিটি আয়াতে প্রজ্ঞা।" }
    ]},
  { n: 47, ar: "الْوَدُودُ", translit: "Al-Wadūd", meanings: { en: "The Loving", bn: "প্রেমময়", fr: "L'Aimant", id: "Yang Maha Mengasihi", ur: "محبت کرنے والا", tr: "Çok Seven", ar: "المحب لعباده" , zh: '仁慈者', ja: '愛しき者'},
    explain: { en: "Al-Wadud is divine love (wudd) — an affectionate, warm, tender love that is not dependent on the worthiness of the beloved. While Ar-Rahman and Ar-Rahim describe mercy, Al-Wadud describes love. The Quran (11:90) calls Allah both 'Ghafur' and 'Wadud' — forgiving AND loving, together. Ibn al-Qayyim in Madarij al-Salikin writes at length about Allah's love for His servants, noting that Allah's love is active: He shows it through protection, guidance, and elevation of the beloved.", bn: "আল-ওয়াদুদ হলো ঐশ্বরিক ভালোবাসা — একটি স্নেহপূর্ণ, উষ্ণ, কোমল ভালোবাসা যা প্রিয়জনের যোগ্যতার উপর নির্ভরশীল নয়। কুরআন (১১:৯০) আল্লাহকে 'গাফুর' এবং 'ওয়াদুদ' উভয়ই বলে — ক্ষমাশীল এবং ভালোবাসাময়, একসাথে।" },
    hadith: { en: "Allah says: 'My servant does not draw near to Me with anything more beloved to Me than the religious duties I have made obligatory. My servant continues to draw near to Me with supererogatory acts until I love him.'", bn: "আল্লাহ বলেন: 'আমার বান্দা আমার কাছে আমার ফরজ করা ইবাদত পালনের চেয়ে বেশি প্রিয় কোনো কিছু দিয়ে নিকটবর্তী হয় না। আমার বান্দা নফল ইবাদত দিয়ে আমার নিকটবর্তী হতে থাকে যতক্ষণ না আমি তাকে ভালোবাসি।'", src: "Sahih al-Bukhari 6502 (Hadith Qudsi)" } ,
    quranicRefs: [
      { ref: "11:90", noteEn: "Inna Rabbi Rahimun Wadud — My Lord is Merciful and Loving; Shuayb declares divine love for those who repent.", noteBn: "ইন্না রাব্বি রাহিমুন ওয়াদুদ — আমার প্রভু রাহিম ও ওয়াদুদ; তওবাকারীদের জন্য ঐশ্বরিক ভালোবাসার ঘোষণা।" },
      { ref: "85:14", noteEn: "Wa Huwa-l-Ghafur-ul-Wadud — He is the All-Forgiving and the Loving; forgiveness and love are inseparable divine qualities.", noteBn: "ওয়া হুওয়াল-গাফুরুল-ওয়াদুদ — তিনি গাফুর ও ওয়াদুদ; ক্ষমা ও ভালোবাসা অবিচ্ছেদ্য ঐশ্বরিক গুণ।" }
    ]},
  { n: 48, ar: "الْمَجِيدُ", translit: "Al-Majīd", meanings: { en: "The Glorious", bn: "মহাগৌরবময়", fr: "Le Glorieux", id: "Yang Maha Mulia", ur: "بزرگ شان والا", tr: "Şanı Yüce", ar: "العظيم الشأن" , zh: '榮耀者', ja: '全ての栄光ある者'},
    explain: { en: "Al-Majid combines supreme majesty (jalal) with supreme generosity and honour (karam). The root majd means glory, honour, and nobility of character. The salutations on the Prophet (Ibrahim's prayer, Quran 11:73) address Allah as 'Hamid, Majid' — the Praiseworthy and Glorious. This combination appears in the closing of Salawat Ibrahim (the Abrahamic salutation) recited in every prayer: 'innaka Hamidun Majid' — You are the Praiseworthy, the Glorious.", bn: "আল-মাজিদ সর্বোচ্চ মহিমা এবং সর্বোচ্চ উদারতাকে একত্রিত করে। কুরআন ১১:৭৩-এ আল্লাহকে 'হামিদ, মাজিদ' বলে সম্বোধন করা হয়। এই সমন্বয় প্রতিটি নামাজে পঠিত সালাওয়াত ইব্রাহিমের সমাপ্তিতে আসে।" } ,
    quranicRefs: [
      { ref: "11:73", noteEn: "Inna-hu Hamidun Majid — declared by the angels at Ibrahim's home; glory and praise in divine announcement.", noteBn: "ইন্নাহু হামিদুন মাজিদ — ইব্রাহিমের গৃহে ফেরেশতাদের ঘোষণা; ঐশ্বরিক বার্তায় গৌরব ও প্রশংসা একসাথে।" },
      { ref: "85:15", noteEn: "Dhu-l-Arsh-il-Majid — Owner of the Glorious Throne; the Throne's glory reflects the Owner's majesty.", noteBn: "যুল-আরশিল-মাজিদ — মহিমান্বিত আরশের মালিক; আরশের গৌরব তার মালিকের মহিমা প্রতিফলিত করে।" }
    ]},
  { n: 49, ar: "الْبَاعِثُ", translit: "Al-Bāʿith", meanings: { en: "The Resurrector", bn: "পুনরুত্থানকারী", fr: "Celui qui ressuscite", id: "Yang Maha Membangkitkan", ur: "اٹھانے والا", tr: "Dirilten", ar: "الباعث بعد الموت" , zh: '亡人喚醒者', ja: '死をもたらす者'},
    explain: { en: "Al-Ba'ith is the One who will resurrect all creation after death for the Day of Judgement — a central article of Islamic faith. The Quran (36:51-52) describes the moment: the trumpet will sound and people will rise from their graves saying 'Who has raised us from our sleeping place?' Al-Ba'ith also means the One who sends forth Prophets and Messengers as divine envoys. Both meanings point to divine initiative: Allah is the One who awakens — whether from physical death or spiritual heedlessness.", bn: "আল-বাইছ হলেন যিনি কিয়ামতের দিনের জন্য মৃত্যুর পরে সমস্ত সৃষ্টিকে পুনরুত্থিত করবেন। কুরআন (৩৬:৫১-৫২) সেই মুহূর্ত বর্ণনা করে: শিঙা বাজবে এবং মানুষ তাদের কবর থেকে উঠে বলবে 'কে আমাদের ঘুম থেকে জাগিয়েছে?'" } ,
    quranicRefs: [
      { ref: "3:9", noteEn: "Inna-ka jami'u-n-nasi li-yawmin la rayba fih — You will gather all mankind for a Day of which there is no doubt.", noteBn: "ইন্নাকা জামিউন-নাসি লিইয়াওমিন লা রায়বা ফিহ — আপনি মানবজাতিকে সেই দিনে জমা করবেন যে দিনে কোনো সন্দেহ নেই।" },
      { ref: "22:7", noteEn: "Wa anna-s-Sa'ata atiyatun la rayba fiha wa anna-llaha yab'athu man fi-l-qubur — Allah will resurrect those in the graves.", noteBn: "ওয়া আন্নাস-সাআতা আতিয়াতুন লা রায়বা ফিহা ওয়া আন্নাল্লাহা ইয়াবআছু মান ফিল-কুবুর — আল্লাহ কবরে যারা আছে তাদের পুনরুত্থিত করবেন।" },
      { ref: "6:36", noteEn: "Innama yastajib-u-lladhina yasma'un wa-l-mawta yab'athu-hum-u-llah — the dead Allah will resurrect; He is Al-Ba'ith.", noteBn: "ইন্নামা ইয়াস্তাজিবুল্লাযিনা ইয়াসমাউন ওয়াল-মাওতা ইয়াবআছুহুমুল্লাহ — মৃতদের আল্লাহ পুনরুত্থিত করবেন।" }
    ]},
  { n: 50, ar: "الشَّهِيدُ", translit: "Ash-Shahīd", meanings: { en: "The Witness", bn: "সর্বসাক্ষী", fr: "Le Témoin", id: "Yang Maha Menyaksikan", ur: "گواہ", tr: "Her Şeye Şahit", ar: "الشاهد على كل شيء" , zh: '見證者', ja: '立会人'},
    explain: { en: "Ash-Shahid is the All-Witness who bears testimony to everything that has ever happened or been said, with the most complete and unbiased testimony imaginable. On the Day of Judgement, Allah will be the ultimate witness, and the record will be infallible. The Quran (10:61) says: 'And you are not engaged in any matter or recite any of the Quran, and you do not do any deed except that We are witness over you.' This name should make every Muslim mindful that their private actions are not private from Allah.", bn: "আশ-শাহিদ হলেন সর্বসাক্ষী যিনি সর্বাধিক সম্পূর্ণ ও পক্ষপাতহীন সাক্ষ্য দিয়ে যা কিছু ঘটেছে বা বলা হয়েছে সব কিছুর সাক্ষ্য দেন। কুরআন (১০:৬১) বলে: 'তুমি যে কোনো বিষয়ে নিয়োজিত হও বা কুরআনের যে কোনো অংশ পাঠ করো... আমরা তোমাদের উপর সাক্ষী।'" } ,
    hadith: { en: "On the Farewell Pilgrimage, after asking the people whether he had conveyed the message and they affirmed, the Prophet ﷺ raised his finger and said thrice: 'O Allah, bear witness (Allahumma-shhad).'", bn: "বিদায় হজে নবী ﷺ লোকদের জিজ্ঞেস করলেন তিনি বার্তা পৌঁছে দিয়েছেন কিনা, তারা সম্মতি দিলে তিনি আঙুল তুলে তিনবার বললেন: 'হে আল্লাহ, আপনি সাক্ষী থাকুন (আল্লাহুম্মাশহাদ)।'", src: "Sahih Muslim 1218" },
    quranicRefs: [
      { ref: "4:166", noteEn: "Wa-llahu Shahid-un anna-hu anzala ilayhi bi-'ilmihi — Allah is Shahid that He revealed it with His knowledge.", noteBn: "ওয়াল্লাহু শাহিদুন আন্নাহু আনযালা ইলায়হি বিইলমিহি — আল্লাহ সাক্ষী যে তিনি তাঁর জ্ঞানে এটি অবতীর্ণ করেছেন।" },
      { ref: "10:46", noteEn: "Thumma-llahu Shahid-un ala ma yaf'alun — then Allah is Ash-Shahid over all they do; He witnesses every deed.", noteBn: "ছুম্মাল্লাহু শাহিদুন আলা মা ইয়াফআলুন — তারপর আল্লাহ তারা যা করে তার সাক্ষী।" },
      { ref: "22:17", noteEn: "Inna-llaha ala kulli shay'in Shahid — Allah is Ash-Shahid over all things; He witnesses all religious communities.", noteBn: "ইন্নাল্লাহা আলা কুল্লি শায়িন শাহিদ — আল্লাহ সব কিছুর সাক্ষী; তিনি সমস্ত ধর্মীয় সম্প্রদায় প্রত্যক্ষ করেন।" },
      { ref: "48:28", noteEn: "Wa kafa billahi Shahida — Allah suffices as Ash-Shahid to His messenger's mission and its truth.", noteBn: "ওয়া কাফা বিল্লাহি শাহিদান — আল্লাহ তাঁর রাসূলের মিশন ও তার সত্যতার সাক্ষী হিসেবে যথেষ্ট।" }
    ]},
  { n: 51, ar: "الْحَقُّ", translit: "Al-Ḥaqq", meanings: { en: "The Truth", bn: "চিরসত্য", fr: "Le Vrai", id: "Yang Maha Benar", ur: "برحق", tr: "Gerçeğin Kendisi", ar: "الثابت الذي لا يزول" , zh: '真實者', ja: '真実'},
    explain: { en: "Al-Haqq is not merely truthful — He IS Truth itself. His existence is the only necessary and self-subsisting existence; everything else's existence is borrowed and contingent. The Quran (22:6) declares: 'That is because Allah is the Truth, and that what they call upon besides Him is falsehood.' Every truth in the cosmos — mathematical, moral, or physical — is a reflection of and derived from Al-Haqq. Falsehood (batil) has no independent existence; it is merely the absence or distortion of haqq.", bn: "আল-হাক্ক কেবল সত্যবাদী নন — তিনি নিজেই সত্য। তাঁর অস্তিত্বই একমাত্র প্রয়োজনীয় ও স্বনির্ভর অস্তিত্ব। কুরআন (২২:৬) ঘোষণা করে: 'এটা এজন্য যে আল্লাহ সত্য, এবং তারা আল্লাহ ব্যতীত যা ডাকে তা মিথ্যা।'" },
    hadith: { en: "The most truthful statement a poet ever said is the statement of Labid: 'Verily, everything except Allah is vain (batil).'", bn: "একজন কবির বলা সবচেয়ে সত্য উক্তি হলো লাবিদের কথা: 'নিশ্চয়ই, আল্লাহ ছাড়া সবকিছু বাতিল (মিথ্যা)।'", src: "Sahih al-Bukhari 3841" } ,
    quranicRefs: [
      { ref: "6:62", noteEn: "Thummma ruddu ila-llahi Mawla-hum-ul-Haqq — they are returned to Allah, their Master, Al-Haqq.", noteBn: "ছুম্মা রুদ্দু ইলাল্লাহি মাওলাহুমুল-হাক্ক — তারা আল্লাহর কাছে ফিরিয়ে দেওয়া হয়, তাদের মাওলা আল-হাক্ক।" },
      { ref: "18:44", noteEn: "Hunak-al-walayatu lillahi-l-Haqq — authority belongs to Allah, Al-Haqq; wealth and children avail nothing before truth.", noteBn: "হুনাকাল-ওয়ালায়াতু লিল্লাহিল-হাক্ক — কর্তৃত্ব আল্লাহ আল-হাক্কের; সত্যের সামনে সম্পদ ও সন্তান অসার।" },
      { ref: "22:6", noteEn: "Dhalika bi-anna-llaha Huwa-l-Haqq wa anna-hu yuhyi-l-mawta — Allah is Al-Haqq and He gives life to the dead.", noteBn: "যালিকা বিআন্নাল্লাহা হুওয়াল-হাক্ক ওয়া আন্নাহু ইউহয়িল-মাওতা — আল্লাহ আল-হাক্ক ও মৃতদের জীবন দেন।" },
      { ref: "22:62", noteEn: "Dhalika bi-anna-llaha Huwa-l-Haqq... Al-Aliyy-ul-Kabir — truth, highness and greatness affirmed together.", noteBn: "যালিকা বিআন্নাল্লাহা হুওয়াল-হাক্ক... আল-আলিয়্যুল-কাবির — সত্য, উচ্চতা ও মহত্ত্ব একসাথে।" },
      { ref: "31:30", noteEn: "Dhalika bi-anna-llaha Huwa-l-Haqq — Al-Haqq is why all falsehood is vain and all truth points to Him.", noteBn: "যালিকা বিআন্নাল্লাহা হুওয়াল-হাক্ক — আল-হাক্কই কারণ সমস্ত মিথ্যা অসার এবং সব সত্য তাঁর দিকে।" }
    ]},
  { n: 52, ar: "الْوَكِيلُ", translit: "Al-Wakīl", meanings: { en: "The Trustee", bn: "মহানির্ভরযোগ্য", fr: "Le Garant", id: "Yang Maha Mewakili", ur: "کارساز", tr: "Güvenilir Vekil", ar: "المتكفل بأمور عباده" , zh: '可信賴者', ja: '管理者、信頼できる者'},
    explain: { en: "Al-Wakil is the Trustee and Disposer of Affairs — the One to whom all matters can safely be entrusted, knowing they will be managed with perfect knowledge, power, and care. The formula 'hasbunallah wa ni'ma-l-wakil' (Allah is sufficient for us and what an excellent Trustee!) was said by Prophet Ibrahim (as) when thrown into fire and by Prophet Muhammad (peace be upon him) when told that enemies had gathered against him (Quran 3:173). In both cases, the result was divine protection.", bn: "আল-ওয়াকিল হলেন সেই বিশ্বস্ত ও বিষয় পরিচালনাকারী — যাঁর কাছে সমস্ত বিষয় নিরাপদে সমর্পণ করা যায়। 'হাসবুনাল্লাহ ওয়া নি'মাল-ওয়াকিল' সূত্রটি ইব্রাহিম (আ.) আগুনে নিক্ষিপ্ত হওয়ার সময় এবং নবী (সা.) শত্রু সংগ্রহের সংবাদ পেয়ে বলেছিলেন (কুরআন ৩:১৭৩)।" },
    invoke: { en: "In moments of helplessness — when you have done all you can and the matter is beyond you — say 'Tawakkaltu 'ala Allah' (I place my trust in Allah) and 'hasbunallah wa ni'ma-l-wakil.' This is tawakkul: not passivity, but entrusting outcomes to Al-Wakil after exhausting your means.", bn: "অসহায় মুহূর্তে — যখন আপনি যা করার করেছেন এবং বিষয়টি আপনার নাগালের বাইরে — বলুন 'তাওয়াক্কালতু আলাল্লাহ' এবং 'হাসবুনাল্লাহ ওয়া নি'মাল-ওয়াকিল।' এটি তাওয়াক্কুল: নিষ্ক্রিয়তা নয়, বরং উপায় নিঃশেষ করার পরে ফলাফল আল-ওয়াকিলের কাছে সমর্পণ।" } ,
    hadith: { en: "'Hasbunallahu wa ni'ma-l-Wakil' (Allah is sufficient for us, and what an excellent Trustee) — Ibrahim said it when cast into the fire, and Muhammad ﷺ said it when told the enemy had gathered against him.", bn: "'হাসবুনাল্লাহু ওয়া নি'মাল-ওয়াকিল' (আল্লাহই আমাদের জন্য যথেষ্ট, আর কতই না উত্তম কর্মবিধায়ক) — ইব্রাহিম (আঃ) আগুনে নিক্ষিপ্ত হওয়ার সময় এটি বলেছিলেন, আর মুহাম্মদ ﷺ শত্রুরা একত্র হওয়ার সংবাদে এটি বলেছিলেন।", src: "Sahih al-Bukhari 4563" },
    quranicRefs: [
      { ref: "3:173", noteEn: "Hasbuna-llahu wa ni'ma-l-Wakil — Allah is sufficient and what an excellent Trustee; said when facing gathered enemies.", noteBn: "হাসবুনাল্লাহু ওয়া নিআমাল-ওয়াকিল — আল্লাহ যথেষ্ট ও কতই না উত্তম ওয়াকিল; শত্রু সমাবেশের মুখে।" },
      { ref: "4:81", noteEn: "Tawakkal ala-llahi wa kafa billahi Wakila — put trust in Allah; He suffices as Trustee, the command of complete reliance.", noteBn: "তাওয়াক্কাল আলাল্লাহি ওয়া কাফা বিল্লাহি ওয়াকিলা — আল্লাহর উপর ভরসা করো; তিনি ওয়াকিল হিসেবে যথেষ্ট।" },
      { ref: "6:102", noteEn: "La ilaha illa Huwa... fa-ubudu-hu wa Huwa ala kulli shay'in Wakil — no deity but Him; worship Him, He is Wakil over all.", noteBn: "লা ইলাহা ইল্লা হুওয়া... ফাউবুদুহু ওয়া হুওয়া আলা কুল্লি শায়িন ওয়াকিল — তিনি ছাড়া কেউ নেই; তাঁর ইবাদত করো।" },
      { ref: "39:62", noteEn: "Allahu Khaliqu kulli shay' wa Huwa ala kulli shay'in Wakil — Creator and Trustee: the fullest statement of divine oversight.", noteBn: "আল্লাহু খালিকু কুল্লি শায় ওয়া হুওয়া আলা কুল্লি শায়িন ওয়াকিল — স্রষ্টা ও ওয়াকিল: ঐশ্বরিক তদারকির সম্পূর্ণ বিবৃতি।" },
      { ref: "73:9", noteEn: "Rabb-ul-mashriq wal-maghrib... fa-ttakhidh-hu Wakila — Lord of East and West; take Him as your Wakil.", noteBn: "রাব্বুল-মাশরিকি ওয়াল-মাগরিবি... ফাত্তাখিযহু ওয়াকিলা — পূর্ব-পশ্চিমের প্রভু; তাঁকে তোমার ওয়াকিল বানাও।" }
    ]},
  { n: 53, ar: "الْقَوِيُّ", translit: "Al-Qawiyy", meanings: { en: "The All-Strong", bn: "মহাশক্তিধর", fr: "Le Fort", id: "Yang Maha Kuat", ur: "بڑی قوت والا", tr: "Pek Güçlü", ar: "صاحب القوة التامة" , zh: '至強者', ja: '強きもの'},
    explain: { en: "Al-Qawiyy is the Absolutely Strong whose strength has no weakness, fatigue, diminishment, or limit. The Quran (22:74) says: 'Indeed, Allah is All-Strong, All-Powerful.' Every physical and spiritual strength in creation is derivative from Al-Qawiyy. Al-Ghazali notes that the believer who turns to Al-Qawiyy in weakness finds strength not through self-reliance but through divine empowerment — 'la hawla wa la quwwata illa billah' (there is no power or strength except through Allah).", bn: "আল-কাওয়িয়্যু হলেন যাঁর শক্তিতে কোনো দুর্বলতা, ক্লান্তি বা সীমা নেই। কুরআন (২২:৭৪) বলে: 'নিশ্চয়ই আল্লাহ কাওয়িয়্যু, শক্তিমান।' আল-গাজালী লক্ষ্য করেন যে দুর্বলতায় আল-কাওয়িয়্যুর দিকে মুখ ফেরানো 'লা হাওলা ওয়ালা কুওয়াতা ইল্লা বিল্লাহ' এর মাধ্যমে শক্তি পাওয়ার পথ।" } ,
    quranicRefs: [
      { ref: "8:52", noteEn: "Wa anna-llaha Qawiyyun shadid-ul-iqab — Allah is Al-Qawiyy, severe in punishment for those who deny His messengers.", noteBn: "ওয়া আন্নাল্লাহা কাওয়িয়্যুন শাদিদুল-ইকাব — আল্লাহ আল-কাওয়িয়্যু, রাসূল অস্বীকারকারীদের শাস্তিতে কঠোর।" },
      { ref: "22:40", noteEn: "Inna-llaha la-Qawiyyun Aziz — Allah is Al-Qawiyy and Al-Aziz; divine strength defends places of worship.", noteBn: "ইন্নাল্লাহা লা-কাওয়িয়্যুন আযিয — আল্লাহ আল-কাওয়িয়্যু ও আল-আযিয; ঐশ্বরিক শক্তি ইবাদতের স্থান রক্ষা করে।" },
      { ref: "22:74", noteEn: "Inna-llaha Qawiyyun Aziz — those who belittle Allah have not measured Him rightly; He is immeasurably strong.", noteBn: "ইন্নাল্লাহা কাওয়িয়্যুন আযিয — যারা আল্লাহকে ছোট করে তারা সঠিক মাপ করেনি।" },
      { ref: "42:19", noteEn: "Wa Huwa-l-Qawiyy-ul-Aziz — paired with Al-Latif; gentle provision combined with absolute strength.", noteBn: "ওয়া হুওয়াল-কাওয়িয়্যুল-আযিয — আল-লাতিফের সাথে জুটি; কোমল রিজিক ও পরম শক্তির সমন্বয়।" },
      { ref: "57:25", noteEn: "Inna-llaha Qawiyyun Aziz — in the context of sending iron and the balance; divine strength upholds justice.", noteBn: "ইন্নাল্লাহা কাওয়িয়্যুন আযিয — লোহা ও মিজান পাঠানোর প্রসঙ্গে; ঐশ্বরিক শক্তি ন্যায় বজায় রাখে।" }
    ]},
  { n: 54, ar: "الْمَتِينُ", translit: "Al-Matīn", meanings: { en: "The Firm", bn: "সুদৃঢ়", fr: "L'Inébranlable", id: "Yang Maha Kokoh", ur: "مضبوط", tr: "Sarsılmaz Güç Sahibi", ar: "الشديد القوي" , zh: '堅定者', ja: '堅固なる者、忠誠なる者'},
    explain: { en: "Al-Matin describes divine firmness and solidity — strength that is not just powerful but absolutely stable, immovable, and consistent. The Quran (51:58) combines this name with Ar-Razzaq: 'Indeed, Allah is the Provider, Owner of Power (Quwwa), the Firm (Matin).' While Al-Qawiyy describes the intensity of divine strength, Al-Matin describes its unshakeable durability. Nothing can shift Allah's plan, exhaust His strength, or destabilise His decrees.", bn: "আল-মাতিন ঐশ্বরিক দৃঢ়তা বর্ণনা করে — শক্তি যা কেবল শক্তিশালী নয় বরং একেবারে স্থিতিশীল, অচল ও সামঞ্জস্যপূর্ণ। কুরআন (৫১:৫৮) এই নামকে আর-রাজ্জাকের সাথে যুক্ত করে।" } ,
    quranicRefs: [
      { ref: "51:58", noteEn: "Inna-llaha Huwa-r-Razzaq Dhu-l-Quwwati-l-Matin — the only verse naming Al-Matin; firmness is inseparable from provision.", noteBn: "ইন্নাল্লাহা হুওয়ার-রাজ্জাকু যুল-কুওয়্যাতিল-মাতিন — আল-মাতিনের নামকরণ করা একমাত্র আয়াত; দৃঢ়তা রিজিক থেকে অবিচ্ছেদ্য।" }
    ]},
  { n: 55, ar: "الْوَلِيُّ", translit: "Al-Waliyy", meanings: { en: "The Protecting Friend", bn: "অভিভাবক", fr: "L'Allié", id: "Yang Maha Melindungi", ur: "دوست و مددگار", tr: "Dost ve Yardımcı", ar: "الناصر المتولي" , zh: '親切的朋友', ja: '自らを守ってくれる友'},
    explain: { en: "Al-Waliyy is the Protecting Friend and Guardian who takes charge of those who believe and guides them out of darkness into light (Quran 2:257). To have Allah as your Wali is the ultimate protection — no enemy can truly harm one who is under divine walayah (friendship/guardianship). The Quran (45:19) says: 'And Allah is the Wali of the believers.' Al-Ghazali distinguishes this from mere protection: Allah as Wali is actively engaged in nurturing and guiding His protected ones.", bn: "আল-ওয়ালিয়্যু হলেন সেই সংরক্ষণকারী বন্ধু ও অভিভাবক যিনি বিশ্বাসীদের দায়িত্ব নেন এবং অন্ধকার থেকে আলোর দিকে পরিচালিত করেন (কুরআন ২:২৫৭)।" },
    invoke: { en: "When you feel alone, abandoned, or unprotected, call upon 'Ya Waliyy, Ya Nasir' (O Protecting Friend, O Helper). Recite Quran 2:286 in your du'a: 'Anta Mawlana fansurna 'ala-l-qawm il-kafirin' (You are our Protector, so help us against the disbelieving people).", bn: "যখন একা, পরিত্যক্ত বা অরক্ষিত অনুভব করেন, 'ইয়া ওয়ালিয়্যু, ইয়া নাসির' বলুন। কুরআন ২:২৮৬ দু'আয় পড়ুন: 'আনতা মাওলানা ফানসুরনা আলাল-কাওমিল-কাফিরিন।'" } ,
    quranicRefs: [
      { ref: "2:257", noteEn: "Allahu Waliyy-u-lladhina amanu yukhrijuhum mina-z-zulumati ila-n-nur — Allah brings believers from darkness to light.", noteBn: "আল্লাহু ওয়ালিয়্যুল্লাযিনা আমানু ইউখরিজুহুম মিনায-যুলুমাতি ইলান-নুর — আল্লাহ বিশ্বাসীদের অন্ধকার থেকে আলোতে আনেন।" },
      { ref: "3:68", noteEn: "Wa-llahu Waliyy-u-l-mu'minin — Allah is the Waliyy of the believers; His friendship is the truest protection.", noteBn: "ওয়াল্লাহু ওয়ালিয়্যুল-মুমিনিন — আল্লাহ বিশ্বাসীদের ওয়ালিয়্যু; তাঁর বন্ধুত্বই সত্যিকারের সুরক্ষা।" },
      { ref: "4:45", noteEn: "Wa-llahu akbar-u Waliyyan wa kafa billahi Nasira — Allah is the greatest Waliyy and sufficient as Helper.", noteBn: "ওয়াল্লাহু আকবারু ওয়ালিয়্যান ওয়া কাফা বিল্লাহি নাসিরা — আল্লাহ সর্বোচ্চ ওয়ালিয়্যু এবং সাহায্যকারী হিসেবে যথেষ্ট।" },
      { ref: "42:9", noteEn: "Fa-llahu Huwa-l-Waliyy — have they taken protectors besides Him? Allah alone is Al-Waliyy; no other walayah avails.", noteBn: "ফাল্লাহু হুওয়াল-ওয়ালিয়্যু — তারা কি তাঁর পরিবর্তে অভিভাবক নিয়েছে? আল্লাহই একমাত্র আল-ওয়ালিয়্যু।" },
      { ref: "45:19", noteEn: "Wa-llahu Waliyy-u-l-muttaqin — Allah is Waliyy of the God-fearing; taqwa draws one into divine friendship.", noteBn: "ওয়াল্লাহু ওয়ালিয়্যুল-মুত্তাকিন — আল্লাহ মুত্তাকিদের ওয়ালিয়্যু; তাকওয়া ঐশ্বরিক বন্ধুত্বে টেনে আনে।" }
    ]},
  { n: 56, ar: "الْحَمِيدُ", translit: "Al-Ḥamīd", meanings: { en: "The Praiseworthy", bn: "সর্বপ্রশংসিত", fr: "Le Digne de louange", id: "Yang Maha Terpuji", ur: "تعریف کے لائق", tr: "Övgüye Lâyık", ar: "المستحق للحمد" , zh: '值得讚頌者', ja: '全ての称賛に値する'},
    explain: { en: "Al-Hamid is the One who is inherently and perfectly praiseworthy — not because He seeks praise, but because every one of His attributes and actions is objectively praise-worthy. The Quran opens with 'Alhamdulillah' — all praise belongs to Allah — establishing Al-Hamid as the primary context for all existence. Al-Ghazali writes that every 'hamd' (praise) in the universe ultimately belongs to Allah alone, because any praise of creation is ultimately praise of the Creator who made them excellent.", bn: "আল-হামিদ হলেন যিনি স্বাভাবিকভাবেই এবং নিখুঁতভাবে প্রশংসার যোগ্য। কুরআন 'আলহামদুলিল্লাহ' দিয়ে শুরু হয় — সমস্ত প্রশংসা আল্লাহর — যা আল-হামিদকে সমস্ত অস্তিত্বের প্রাথমিক প্রেক্ষাপট হিসেবে প্রতিষ্ঠিত করে।" } ,
    hadith: { en: "Allah is pleased with His servant who, upon eating food, praises Him (says Alhamdulillah), and upon drinking, praises Him.", bn: "আল্লাহ সেই বান্দার প্রতি সন্তুষ্ট হন যে খাবার খেয়ে আলহামদুলিল্লাহ বলে এবং পানীয় পান করেও আলহামদুলিল্লাহ বলে।", src: "Sahih Muslim 2734" },
    quranicRefs: [
      { ref: "2:267", noteEn: "Wa-llahu Ghani-yun Hamid — Allah is Self-Sufficient and Praiseworthy; He accepts only wholesome charity.", noteBn: "ওয়াল্লাহু গানিয়্যুন হামিদ — আল্লাহ স্বনির্ভর ও হামিদ; তিনি কেবল উত্তম দাতব্য গ্রহণ করেন।" },
      { ref: "14:8", noteEn: "Inna-llaha la-Ghani-yun Hamid — if all people were ungrateful, Allah is Self-Sufficient and Praiseworthy.", noteBn: "ইন্নাল্লাহা লা-গানিয়্যুন হামিদ — সবাই অকৃতজ্ঞ হলেও আল্লাহ স্বনির্ভর ও হামিদ।" },
      { ref: "22:64", noteEn: "Wa inna-llaha Huwa-l-Ghani-yul-Hamid — He owns all in heavens and earth; He is Al-Ghaniyy and Al-Hamid.", noteBn: "ওয়া ইন্নাল্লাহা হুওয়াল-গানিয়্যুল-হামিদ — আকাশ-পৃথিবীর সব তাঁর; তিনি আল-গানিয়্যু ও আল-হামিদ।" },
      { ref: "31:12", noteEn: "Fa-inna-llaha Ghani-yun Hamid — whoever is ungrateful, Allah is Self-Sufficient and Praiseworthy; gratitude benefits the giver.", noteBn: "ফাইন্নাল্লাহা গানিয়্যুন হামিদ — অকৃতজ্ঞ হলেও আল্লাহ গানিয়্যু ও হামিদ; কৃতজ্ঞতা দাতাকেই উপকার করে।" },
      { ref: "41:42", noteEn: "Min Hakim-in Hamid — the Quran comes from One Wise and Praiseworthy; every word of the Book is from Al-Hamid.", noteBn: "মিন হাকিমিন হামিদ — কুরআন প্রজ্ঞাবান ও হামিদের কাছ থেকে; কিতাবের প্রতিটি শব্দ আল-হামিদের।" }
    ]},
  { n: 57, ar: "الْمُحْصِي", translit: "Al-Muḥṣī", meanings: { en: "The Enumerator", bn: "সর্বগণনাকারী", fr: "Celui qui dénombre", id: "Yang Maha Menghitung", ur: "شمار کرنے والا", tr: "Her Şeyi Sayan", ar: "المحصي لكل شيء" , zh: '清算者', ja: '答える者'},
    explain: { en: "Al-Muhsi is the One who has counted and catalogued every single thing — every grain of sand, every raindrop, every leaf, every breath taken, every word spoken, every heartbeat. Quran 36:12 says: 'We have counted everything in a clear register.' No number is too large, no quantity too small, no fleeting moment too brief. On the Day of Judgement, Al-Muhsi's account will be presented in full: the Quran (99:7-8) says an atom's weight of good or evil will be shown.", bn: "আল-মুহসি হলেন যিনি প্রতিটি একক বস্তু গণনা ও নিবন্ধ করেছেন। কুরআন ৩৬:১২ বলে: 'আমরা একটি স্পষ্ট নথিতে সবকিছু গণনা করেছি।' কিয়ামতের দিন আল-মুহসির হিসাব পূর্ণরূপে উপস্থাপন করা হবে।" } ,
    quranicRefs: [
      { ref: "19:94", noteEn: "Laqad ahsa-hum wa adda-hum adda — He has counted them and numbered them with precision; Al-Muhsi's count is exact.", noteBn: "লাকাদ আহসাহুম ওয়া আদ্দাহুম আদ্দা — তিনি তাদের গণনা করেছেন এবং সঠিকভাবে সংখ্যা নির্ধারণ করেছেন।" },
      { ref: "36:12", noteEn: "Wa kulla shay'in ahsayna-hu fi Imam-in Mubin — We have enumerated everything in a clear register; the divine catalogue is complete.", noteBn: "ওয়া কুল্লা শায়িন আহসায়নাহু ফি ইমামিন মুবিন — আমরা সব কিছু স্পষ্ট নথিতে গণনা করেছি; ঐশ্বরিক তালিকা সম্পূর্ণ।" }
    ]},
  { n: 58, ar: "الْمُبْدِئُ", translit: "Al-Mubdi'", meanings: { en: "The Initiator", bn: "সূচনাকারী", fr: "Celui qui commence", id: "Yang Maha Memulai", ur: "پہلی بار پیدا کرنے والا", tr: "İlkin Yaratan", ar: "المبدئ للخلق" , zh: '首創萬物者', ja: '創造主'},
    explain: { en: "Al-Mubdi' is the One who initiates creation from absolute nothingness — the Originator who starts existence itself. This name appears paired with Al-Mu'id (the Restorer) in classical theology: just as He began creation, He will end and recreate it. Quran 85:13 says 'He originates (yubdi') and restores (yu'id).' Ibn al-Qayyim writes that reflecting on Al-Mubdi' counters the argument of those who deny resurrection: the One who initiated creation from nothing can certainly restore it.", bn: "আল-মুবদি হলেন যিনি পরম শূন্য থেকে সৃষ্টি শুরু করেন। এই নাম ধ্রুপদী ধর্মতত্ত্বে আল-মুইদের সাথে জোড়ায় আসে। কুরআন ৮৫:১৩ বলে 'তিনি সূচনা করেন ও পুনরুদ্ধার করেন।'" } ,
    quranicRefs: [
      { ref: "10:34", noteEn: "Qul hal min shuraka'ikum man yabda'u-l-khalqa thumma yu'idu-hu, quli-llahu yabda'u-l-khalqa — Allah initiates creation.", noteBn: "কুল হাল মিন শুরাকাইকুম মান ইয়াবদাউল-খালকা ছুম্মা ইউইদুহু, কুলিল্লাহু ইয়াবদাউল-খালকা — আল্লাহ সৃষ্টির সূচনা করেন।" },
      { ref: "85:13", noteEn: "Inna-hu Huwa yubdi'u wa yu'id — He originates and He restores; the paired names Al-Mubdi and Al-Mu'id in one verse.", noteBn: "ইন্নাহু হুওয়া ইউবদিউ ওয়া ইউইদ — তিনি সূচনা করেন ও পুনরুদ্ধার করেন; একটি আয়াতে আল-মুবদি ও আল-মুইদ।" }
    ]},
  { n: 59, ar: "الْمُعِيدُ", translit: "Al-Muʿīd", meanings: { en: "The Restorer", bn: "পুনঃসৃষ্টিকারী", fr: "Celui qui redonne", id: "Yang Maha Mengembalikan", ur: "دوبارہ پیدا کرنے والا", tr: "Yeniden Dirilten", ar: "المعيد للخلق" , zh: '恢復福祉者', ja: '全てを還す者'},
    explain: { en: "Al-Mu'id is the One who restores and recreates — primarily referring to the resurrection on the Day of Judgement. The Quran (10:34) challenges: 'Who originates creation and then repeats it?' Then answers: 'Allah.' To those who doubt resurrection, the Quran (36:78-79) replies that the One who created from bones the first time can restore them with even greater ease. Al-Mu'id also reassures that lost faith, broken hearts, and corrupted souls can be restored.", bn: "আল-মুইদ হলেন যিনি পুনরুদ্ধার করেন ও পুনঃসৃষ্টি করেন। কুরআন (১০:৩৪) চ্যালেঞ্জ করে: 'কে সৃষ্টির সূচনা করে তারপর পুনরাবৃত্তি করে?' তারপর উত্তর দেয়: 'আল্লাহ।'" } ,
    quranicRefs: [
      { ref: "10:34", noteEn: "Thumma yu'idu-hu — then He restores it; Al-Mu'id is the inevitable answer to those who doubt resurrection.", noteBn: "ছুম্মা ইউইদুহু — তারপর তিনি পুনরুদ্ধার করেন; পুনরুত্থান সন্দেহকারীদের জন্য আল-মুইদ অনিবার্য উত্তর।" },
      { ref: "85:13", noteEn: "Inna-hu Huwa yubdi'u wa yu'id — He originates and He restores; paired with Al-Mubdi in the same verse.", noteBn: "ইন্নাহু হুওয়া ইউবদিউ ওয়া ইউইদ — তিনি সূচনা ও পুনরুদ্ধার করেন; আল-মুবদির সাথে একই আয়াতে।" }
    ]},
  { n: 60, ar: "الْمُحْيِي", translit: "Al-Muḥyī", meanings: { en: "The Giver of Life", bn: "জীবনদাতা", fr: "Celui qui fait vivre", id: "Yang Maha Menghidupkan", ur: "زندگی دینے والا", tr: "Hayat Veren", ar: "المحيي للخلق" , zh: '賜予生命者', ja: '生命を与える者'},
    explain: { en: "Al-Muhyi is the Giver of Life in every sense — the One who breathed life into Adam from clay (Quran 15:29), who sends rain to revive dead land (Quran 30:50), and who will restore life to the dead on the Day of Resurrection (Quran 2:260). The Quran also uses ihya' (enlivening) metaphorically for spiritual life: a heart awakened by guidance is 'brought to life' by Al-Muhyi. Life — physical, ecological, and spiritual — has one single source.", bn: "আল-মুহয়ি হলেন প্রতিটি অর্থে জীবনদাতা — যিনি মাটি থেকে আদমে জীবন ফুঁকে দিলেন (কুরআন ১৫:২৯), যিনি মৃত ভূমি পুনরুজ্জীবিত করতে বৃষ্টি পাঠান (কুরআন ৩০:৫০), এবং যিনি কিয়ামতের দিন মৃতদের জীবন ফিরিয়ে দেবেন।" } ,
    hadith: { en: "On waking the Prophet ﷺ would say: 'Al-hamdu lillahi-lladhi ahyana ba'da ma amatana wa ilayhi-n-nushur' (Praise be to Allah who gave us life after causing us to die, and to Him is the resurrection).", bn: "ঘুম থেকে জেগে নবী ﷺ বলতেন: 'আলহামদু লিল্লাহিল্লাযি আহইয়ানা বা'দা মা আমাতানা ওয়া ইলাইহিন-নুশুর' (সকল প্রশংসা সেই আল্লাহর, যিনি মৃত্যুর পর আমাদের জীবিত করলেন, আর তাঁরই দিকে পুনরুত্থান)।", src: "Sahih al-Bukhari 6312" },
    quranicRefs: [
      { ref: "2:258", noteEn: "Allah yuhyi wa yumit — Allah gives life and causes death; Ibrahim's argument to Namrud about Al-Muhyi.", noteBn: "আল্লাহু ইউহয়ি ওয়া ইউমিত — আল্লাহ জীবন দেন ও মৃত্যু ঘটান; নমরুদের বিরুদ্ধে ইব্রাহিমের যুক্তি।" },
      { ref: "30:50", noteEn: "fa-unzur ila athari rahmati-llah kayfa yuhyi-l-ard ba'da mawtiha — see how Allah revives the earth after its death.", noteBn: "ফাউনযুর ইলা আছারি রাহমাতিল্লাহ কায়ফা ইউহয়িল-আরদা বাআদা মাওতিহা — দেখো কীভাবে আল্লাহ মৃত্যুর পরে পৃথিবী পুনরুজ্জীবিত করেন।" },
      { ref: "41:39", noteEn: "Inna-lladhi ahyaha la-Muhyi-l-mawta — He who revived it is indeed Al-Muhyi of the dead; rain over dead earth proves resurrection.", noteBn: "ইন্নাল্লাযি আহয়াহা লা-মুহয়িল-মাওতা — যিনি তা পুনরুজ্জীবিত করেছেন তিনি মৃতদের আল-মুহয়ি; মৃত মাটিতে বৃষ্টি পুনরুত্থানের প্রমাণ।" }
    ]},
  { n: 61, ar: "الْمُمِيتُ", translit: "Al-Mumīt", meanings: { en: "The Bringer of Death", bn: "মৃত্যুদাতা", fr: "Celui qui fait mourir", id: "Yang Maha Mematikan", ur: "موت دینے والا", tr: "Öldüren", ar: "المميت للأحياء" , zh: '賜死者、毀滅者', ja: '死をもたらす者、破壊者'},
    explain: { en: "Al-Mumit is the One who causes death — not as a tragedy but as a transition, and not arbitrarily but at the precisely appointed time. The Quran (3:185) says: 'Every soul will taste death.' Death in Islamic theology is not the end but the gateway: Al-Mumit and Al-Muhyi work together to form the cycle of existence. Al-Ghazali writes that meditating on Al-Mumit purifies the heart of love for the world and attachments that lead to heedlessness.", bn: "আল-মুমিত হলেন যিনি মৃত্যু ঘটান — ট্র্যাজেডি হিসেবে নয় বরং রূপান্তর হিসেবে, এবং খামখেয়ালীভাবে নয় বরং নির্ধারিত সময়ে। কুরআন (৩:১৮৫) বলে: 'প্রতিটি আত্মা মৃত্যুর স্বাদ গ্রহণ করবে।'" },
    hadith: { en: "Remember often the destroyer of pleasures — death.", bn: "আনন্দের ধ্বংসকারী মৃত্যুকে বারবার স্মরণ করো।", src: "Sunan ibn Majah 4258; Sunan al-Tirmidhi 2307 (Hasan)" } ,
    quranicRefs: [
      { ref: "2:258", noteEn: "Allah yuhyi wa yumit — Allah gives life and causes death; the divine pair Al-Muhyi and Al-Mumit stated together.", noteBn: "আল্লাহু ইউহয়ি ওয়া ইউমিত — আল্লাহ জীবন দেন ও মৃত্যু ঘটান; আল-মুহয়ি ও আল-মুমিত একসাথে।" },
      { ref: "3:156", noteEn: "Wa-llahu yuhyi wa yumit — Allah gives life and causes death; those who fall in battle are in Allah's care.", noteBn: "ওয়াল্লাহু ইউহয়ি ওয়া ইউমিত — আল্লাহ জীবন দেন ও মৃত্যু ঘটান; যুদ্ধে পতিতরা আল্লাহর যত্নে।" },
      { ref: "7:158", noteEn: "Wa Huwa yuhyi wa yumit — He gives life and causes death; the Prophet commands belief in Al-Muhyi Al-Mumit.", noteBn: "ওয়া হুওয়া ইউহয়ি ওয়া ইউমিত — তিনি জীবন দেন ও মৃত্যু ঘটান; নবী আল-মুহয়ি আল-মুমিতে বিশ্বাসের আদেশ করেন।" }
    ]},
  { n: 62, ar: "الْحَيُّ", translit: "Al-Ḥayy", meanings: { en: "The Ever-Living", bn: "চিরঞ্জীব", fr: "Le Vivant", id: "Yang Maha Hidup", ur: "ہمیشہ زندہ", tr: "Diri Olan", ar: "الحي الذي لا يموت" , zh: '永生者', ja: '永久に生きる者'},
    explain: { en: "Al-Hayy is the Ever-Living whose life is perfect, beginningless, endless, and uncaused — requiring nothing to sustain it. All life in creation is borrowed from Al-Hayy: every creature lives only because Al-Hayy wills it and sustains it. Ayat al-Kursi opens: 'Allah — there is no deity except Him, Al-Hayy, Al-Qayyum' (2:255), establishing this as the foundational statement of divine reality. Ibn al-Qayyim writes that Al-Hayy encompasses all attributes of perfection, because a dead being has no attributes.", bn: "আল-হাইয়্যু হলেন চিরঞ্জীব যাঁর জীবন নিখুঁত, আদিহীন, অন্তহীন ও অকারণ। সৃষ্টিতে সমস্ত জীবন আল-হাইয়্যু থেকে ধার করা। আয়াতুল কুরসি শুরু হয়: 'আল্লাহ — তিনি ছাড়া কোনো উপাস্য নেই, আল-হাইয়্যু, আল-কাইয়্যুম' (২:২৫৫)।" },
    hadith: { en: "The Prophet (peace be upon him) used to say when distressed: 'Ya Hayyu Ya Qayyum, bi-rahmatika astaghith' — O Ever-Living, O Self-Sustaining, by Your mercy I seek help.", bn: "নবী (সা.) বিপদের সময় বলতেন: 'ইয়া হাইয়্যু ইয়া কাইয়্যুম, বিরাহমাতিকা আস্তাগিছ' — হে চিরঞ্জীব, হে স্বনির্ভর, তোমার রহমতে আমি সাহায্য চাই।", src: "Sunan al-Tirmidhi 3524; al-Hakim (Sahih)" },
    invoke: { en: "In moments of deep distress or spiritual darkness, call upon 'Ya Hayyu Ya Qayyum, bi-rahmatika astaghith, wa aslih li sha'ni kullahu wa la takilni ila nafsi tarfata 'ayn' (O Ever-Living, O Sustainer, by Your mercy I seek help; set right all my affairs and do not entrust me to myself even for a blink). This was the Prophet's own du'a.", bn: "গভীর সংকট বা আধ্যাত্মিক অন্ধকারের মুহূর্তে ডাকুন: 'ইয়া হাইয়্যু ইয়া কাইয়্যুম, বিরাহমাতিকা আস্তাগিছ, ওয়া আসলিহ লি শানি কুল্লাহু ওয়ালা তাকিলনি ইলা নাফসি তারফাতা আইন।' এটি নবী (সা.)-এর নিজের দু'আ।" } ,
    quranicRefs: [
      { ref: "2:255", noteEn: "Allahu la ilaha illa Huwa-l-Hayy-ul-Qayyum — Ayat al-Kursi opens with Al-Hayy; the Ever-Living who never sleeps.", noteBn: "আল্লাহু লা ইলাহা ইল্লা হুওয়াল-হাইয়্যুল-কাইয়্যুম — আয়াতুল কুরসি আল-হাইয়্যু দিয়ে খোলে; কখনো ঘুমান না।" },
      { ref: "3:2", noteEn: "Allahu la ilaha illa Huwa-l-Hayy-ul-Qayyum — opens Surah Ali Imran, anchoring the revelation in divine life.", noteBn: "আল্লাহু লা ইলাহা ইল্লা হুওয়াল-হাইয়্যুল-কাইয়্যুম — সূরা আলি ইমরান খোলে, ওহিকে ঐশ্বরিক জীবনে নোঙর করে।" },
      { ref: "20:111", noteEn: "Wa akhada-t-ul-wujuhu li-l-Hayy-il-Qayyum — faces bow before Al-Hayy Al-Qayyum on the Day of Resurrection.", noteBn: "ওয়া আখাদাতিল-উজুহু লিল-হাইয়্যিল-কাইয়্যুম — কিয়ামতে মুখমণ্ডল আল-হাইয়্যু আল-কাইয়্যুমের সামনে নত।" },
      { ref: "25:58", noteEn: "Wa tawakkal ala-l-Hayy-illadhi la yamut — put trust in Al-Hayy who never dies; He alone is worthy of ultimate trust.", noteBn: "ওয়া তাওয়াক্কাল আলাল-হাইয়্যিল্লাযি লা ইয়ামুত — চিরঞ্জীবের উপর ভরসা করো যিনি কখনো মরেন না।" },
      { ref: "40:65", noteEn: "Huwa-l-Hayy la ilaha illa Huwa fa-d'u-hu mukhlisin — He is Al-Hayy, call upon Him with pure sincerity.", noteBn: "হুওয়াল-হাইয়্যু লা ইলাহা ইল্লা হুওয়া ফাদউহু মুখলিসিন — তিনি আল-হাইয়্যু, বিশুদ্ধ ঈমানে তাঁকে ডাকো।" }
    ]},
  { n: 63, ar: "الْقَيُّومُ", translit: "Al-Qayyūm", meanings: { en: "The Sustainer of All", bn: "চিরপ্রতিষ্ঠিত", fr: "L'Immuable", id: "Yang Maha Berdiri Sendiri", ur: "سب کو قائم رکھنے والا", tr: "Her Şeyi Ayakta Tutan", ar: "القائم على كل شيء" , zh: '維持萬物者、自我擁有者', ja: 'すべてのものを自分で守るもの'},
    explain: { en: "Al-Qayyum is the Self-Subsisting Sustainer of all creation — the One who needs nothing to exist and without whom nothing else can exist. Every atom in the universe is sustained moment to moment by Al-Qayyum; if He were to withdraw His sustaining power for an instant, all creation would cease. Ibn al-Qayyim (whose very name is derived from this attribute) writes that Al-Qayyum is the name that all other divine names 'return to' as their foundation and the most comprehensive name after Allah Himself.", bn: "আল-কাইয়্যুম হলেন স্বনির্ভর সমস্ত সৃষ্টির রক্ষাকর্তা। মহাবিশ্বের প্রতিটি পরমাণু মুহূর্তে মুহূর্তে আল-কাইয়্যুম দ্বারা টিকে আছে। ইবনুল কাইয়িম (যার নাম এই গুণ থেকে) লিখেছেন যে আল-কাইয়্যুম সেই নাম যার কাছে অন্য সকল ঐশ্বরিক নাম তাদের ভিত্তি হিসেবে ফিরে আসে।" } ,
    hadith: { en: "When something distressed him the Prophet ﷺ would say: 'Ya Hayyu Ya Qayyum, bi-rahmatika astaghith' (O Ever-Living, O Sustainer of all, by Your mercy I seek relief).", bn: "কোনো কিছু নবী ﷺ-কে চিন্তিত করলে তিনি বলতেন: 'ইয়া হাইয়ু ইয়া কাইয়ুম, বিরাহমাতিকা আস্তাগিস' (হে চিরঞ্জীব, হে সর্বপ্রতিষ্ঠাকারী, আপনার রহমতের উসিলায় আমি সাহায্য চাই)।", src: "Jami' at-Tirmidhi 3524" },
    quranicRefs: [
      { ref: "2:255", noteEn: "Allahu la ilaha illa Huwa-l-Hayy-ul-Qayyum — Ayat al-Kursi: Al-Qayyum sustains all creation without weariness.", noteBn: "আল্লাহু লা ইলাহা ইল্লা হুওয়াল-হাইয়্যুল-কাইয়্যুম — আয়াতুল কুরসি: আল-কাইয়্যুম ক্লান্তি ছাড়া সমস্ত সৃষ্টি টিকিয়ে রাখেন।" },
      { ref: "3:2", noteEn: "Allahu la ilaha illa Huwa-l-Hayy-ul-Qayyum — opens Surah Ali Imran; Al-Qayyum as the sustaining ground of all revelation.", noteBn: "আল্লাহু লা ইলাহা ইল্লা হুওয়াল-হাইয়্যুল-কাইয়্যুম — সূরা আলি ইমরান খোলে; আল-কাইয়্যুম ওহির সব কিছুর ভিত্তি।" },
      { ref: "20:111", noteEn: "Wa akhada-t-ul-wujuhu li-l-Hayy-il-Qayyum — faces bow before Al-Qayyum on the Day of Resurrection.", noteBn: "ওয়া আখাদাতিল-উজুহু লিল-হাইয়্যিল-কাইয়্যুম — কিয়ামতে মুখমণ্ডল আল-কাইয়্যুমের সামনে নত হবে।" }
    ]},
  { n: 64, ar: "الْوَاجِدُ", translit: "Al-Wājid", meanings: { en: "The Finder", bn: "সর্বপ্রাপক", fr: "Celui qui trouve", id: "Yang Maha Menemukan", ur: "پانے والا", tr: "Dilediğini Bulan", ar: "الغني الذي لا يفتقر" , zh: '搜查者', ja: '見つけし者'},
    explain: { en: "Al-Wajid means the One who finds and the One who is never in want — the root wajada carries both meanings. He is never deprived of anything He wishes to find; His resources never run short. Al-Ghazali links this name to divine richness (ghina'): since Allah needs nothing and lacks nothing, His giving is truly from abundance. Reflecting on Al-Wajid reminds the servant that all scarcity is on the human side, never on Allah's side.", bn: "আল-ওয়াজিদ অর্থ যিনি খুঁজে পান এবং যিনি কখনো অভাবী নন — মূল ওয়াজাদার উভয় অর্থ আছে। তিনি কখনো কোনো কিছু থেকে বঞ্চিত হন না। আল-গাজালী এই নামকে ঐশ্বরিক সম্পদের সাথে যুক্ত করেছেন: যেহেতু আল্লাহর কোনো অভাব নেই, তাঁর দান সত্যিকার প্রাচুর্য থেকে।" } ,
    quranicRefs: [
      { ref: "93:6", noteEn: "Alam yajidka yatiman fa-awa — Did He not find you (from the root wajada) an orphan and shelter you? The One who finds is never in want.", noteBn: "আলাম ইয়াজিদকা ইয়াতিমান ফা-আওয়া — তিনি কি তোমাকে (ওয়াজাদা মূল থেকে) এতিম পাননি ও আশ্রয় দেননি? যিনি খুঁজে পান তিনি কখনো অভাবী নন।" },
      { ref: "93:7", noteEn: "Wa wajadaka dallan fa-hada — and He found you unaware and guided you; nothing He seeks eludes Him.", noteBn: "ওয়া ওয়াজাদাকা দাল্লান ফা-হাদা — এবং তিনি তোমাকে পথহারা পেয়ে পথ দেখিয়েছেন; তিনি যা খোঁজেন তা তাঁকে এড়ায় না।" },
      { ref: "35:15", noteEn: "Wa-llahu Huwa-l-Ghaniyy-ul-Hamid — Allah is Free of all need; the Finder never lacks what He wills.", noteBn: "ওয়াল্লাহু হুওয়াল-গানিয়্যুল-হামিদ — আল্লাহ অভাবমুক্ত; আল-ওয়াজিদ যা চান তার অভাব হয় না।" },
      { ref: "47:38", noteEn: "Wa-llahu-l-Ghaniyy wa antumu-l-fuqara' — Allah is Free of need while you are the needy; scarcity is only on the human side.", noteBn: "ওয়াল্লাহুল-গানিয়্যু ওয়া আনতুমুল-ফুকারা — আল্লাহ অভাবমুক্ত আর তোমরা মুখাপেক্ষী; অভাব কেবল মানুষের দিকে।" }
    ]},
  { n: 65, ar: "الْمَاجِدُ", translit: "Al-Mājid", meanings: { en: "The Noble", bn: "মহিমান্বিত", fr: "Le Noble", id: "Yang Maha Mulia Sifatnya", ur: "بزرگی والا", tr: "Şerefi Yüce", ar: "الماجد الكريم" , zh: '卓越者', ja: '高貴なる者'},
    explain: { en: "Al-Majid describes nobility of character (majd) — the combination of generosity, honour, and magnificence. While Al-Majid (name 48) refers to external glory, Al-Majid here (as distinguished in classical scholarship) emphasises inner nobility of divine character. Allah's generosity is of the noblest kind: He gives to those who oppose Him, He delays punishment for those who deserve it, and He rewards beyond what is deserved.", bn: "আল-মাজিদ চরিত্রের মহানুভবতা বর্ণনা করে — উদারতা, সম্মান এবং মহিমার সমন্বয়। আল্লাহর উদারতা সবচেয়ে মহৎ ধরনের: তিনি তাঁকে বিরোধিতাকারীদেরও দান করেন এবং যোগ্যতার চেয়ে বেশি পুরস্কৃত করেন।" } ,
    quranicRefs: [
      { ref: "11:73", noteEn: "Innahu Hamidun Majid — Indeed He is Praiseworthy, Glorious (Majid); spoken of the household of Ibrahim.", noteBn: "ইন্নাহু হামিদুন মাজিদ — নিশ্চয় তিনি প্রশংসিত, মহিমান্বিত (মাজিদ); ইবরাহিমের পরিবার সম্পর্কে বলা।" },
      { ref: "85:15", noteEn: "Dhu-l-'Arshi-l-Majid — Lord of the Glorious Throne; His majd (nobility) is supreme.", noteBn: "যুল-আরশিল-মাজিদ — মহিমান্বিত আরশের অধিপতি; তাঁর মাজদ (মহানুভবতা) সর্বোচ্চ।" },
      { ref: "85:21", noteEn: "Bal huwa Qur'anun Majid — rather it is a Glorious Quran, reflecting the majesty of its Author.", noteBn: "বাল হুওয়া কুরআনুন মাজিদ — বরং এটি মহিমান্বিত কুরআন, যা এর প্রেরকের মহিমা প্রতিফলিত করে।" },
      { ref: "50:1", noteEn: "Qaf, wa-l-Qur'ani-l-Majid — by the Glorious Quran; the same attribute of majd.", noteBn: "কাফ, ওয়াল-কুরআনিল-মাজিদ — মহিমান্বিত কুরআনের শপথ; একই মাজদ গুণ।" }
    ]},
  { n: 66, ar: "الْوَاحِدُ", translit: "Al-Wāḥid", meanings: { en: "The One", bn: "একক", fr: "L'Unique", id: "Yang Maha Esa", ur: "یکتا", tr: "Tek Olan", ar: "الواحد بلا شريك" , zh: '獨一者', ja: '唯一無二の者'},
    explain: { en: "Al-Wahid is the numerical One — there is only one God, no second, no partner, no assistant, no rival. The Quran (14:48) speaks of the Day when people will 'come before Allah, the One, Al-Qahhar.' This name is the foundation of tawhid (monotheism): acknowledging Al-Wahid is the first and fundamental obligation. Al-Ghazali notes that Al-Wahid guards against the subtle forms of shirk (associating partners with Allah) including making goals and fears subservient to anything other than Allah.", bn: "আল-ওয়াহিদ হলো সংখ্যাগত এক — একটিমাত্র আল্লাহ, কোনো দ্বিতীয় নেই, কোনো অংশীদার নেই। কুরআন (১৪:৪৮) সেই দিনের কথা বলে যখন মানুষ 'আল্লাহ, আল-ওয়াহিদ, আল-কাহহারের সামনে উপস্থিত হবে।'" } ,
    quranicRefs: [
      { ref: "13:16", noteEn: "Allahu Khaliq-u kulli shay' wa Huwa-l-Wahid-ul-Qahhar — Creator of all and the One, the Subduer.", noteBn: "আল্লাহু খালিকু কুল্লি শায় ওয়া হুওয়াল-ওয়াহিদুল-কাহহার — সব কিছুর স্রষ্টা এবং আল-ওয়াহিদ, আল-কাহহার।" },
      { ref: "14:48", noteEn: "Wa barazu-llahi-l-Wahid-il-Qahhar — they stand before Allah Al-Wahid Al-Qahhar; His oneness is undeniable at the Reckoning.", noteBn: "ওয়া বারাযু লিল্লাহিল-ওয়াহিদিল-কাহহার — তারা আল্লাহ আল-ওয়াহিদ আল-কাহহারের সামনে দাঁড়াবে।" },
      { ref: "39:4", noteEn: "Subhana-hu Huwa-llahu-l-Wahid-ul-Qahhar — Glory be to Him, He is Allah, the One, the Subduer; absolute oneness.", noteBn: "সুবহানাহু হুওয়াল্লাহুল-ওয়াহিদুল-কাহহার — পবিত্রতা তাঁর, তিনি আল্লাহ, আল-ওয়াহিদ, আল-কাহহার।" },
      { ref: "38:65", noteEn: "Qul innama ana nadhir wa ma min ilahin illa-llahu-l-Wahid-ul-Qahhar — there is no deity except Allah Al-Wahid.", noteBn: "কুল ইন্নামা আনা নাযির ওয়ামা মিন ইলাহিন ইল্লাল্লাহুল-ওয়াহিদুল-কাহহার — আল্লাহ আল-ওয়াহিদ ছাড়া কোনো উপাস্য নেই।" }
    ]},
  { n: 67, ar: "الْأَحَدُ", translit: "Al-Aḥad", meanings: { en: "The Indivisible One", bn: "অদ্বিতীয়", fr: "L'Un", id: "Yang Maha Tunggal", ur: "اکیلا", tr: "Bir Olan", ar: "الأحد الفرد" , zh: '不可分割者', ja: '唯一者'},
    explain: { en: "Al-Ahad is uniquely applied only to Allah, denoting an indivisible, incomparable oneness that cannot be shared, divided, multiplied, or compared. While Al-Wahid is the number 'one' (which implies the possibility of a 'two'), Al-Ahad is the absolute, unique singularity that transcends counting altogether. It appears in Surah al-Ikhlas (112:1), which the Prophet said is worth one-third of the Quran. Ibn al-Qayyim says Al-Ahad is the name that most completely negates every form of polytheism.", bn: "আল-আহাদ একমাত্র আল্লাহর জন্যই ব্যবহৃত, এমন একটি অবিভাজ্য, তুলনাহীন একত্ব বোঝায় যা ভাগ করা, বিভক্ত বা তুলনা করা যায় না। এটি সূরা আল-ইখলাসে (১১২:১) আসে যা নবী (সা.) বলেছেন কুরআনের এক-তৃতীয়াংশের সমতুল্য।" } ,
    hadith: { en: "The Prophet ﷺ heard a man supplicate: 'O Allah, I ask You by my testifying that You are Allah, there is no god but You, Al-Ahad (the One), As-Samad...' and said he had asked Allah by His Greatest Name.", bn: "নবী ﷺ এক ব্যক্তিকে দু'আ করতে শুনলেন: 'হে আল্লাহ, আমি এই সাক্ষ্যের উসিলায় চাই যে আপনিই আল্লাহ, আপনি ছাড়া কোনো ইলাহ নেই, আপনি আল-আহাদ (একক), আস-সামাদ...' তিনি বললেন সে আল্লাহকে তাঁর মহত্তম নামে ডেকেছে।", src: "Sunan Abi Dawud 1493; Jami' at-Tirmidhi 3475" },
    quranicRefs: [
      { ref: "112:1", noteEn: "Qul Huwa-llahu Ahad — Say: He is Allah, Al-Ahad; the name's only Quranic appearance, distilling the entire doctrine of tawhid.", noteBn: "কুল হুওয়াল্লাহু আহাদ — বলো: তিনি আল্লাহ, আল-আহাদ; নামটির একমাত্র কুরআনিক উপস্থিতি, তাওহিদের সমগ্র মতবাদ পাতন।" }
    ]},
  { n: 68, ar: "الصَّمَدُ", translit: "Aṣ-Ṣamad", meanings: { en: "The Eternal Refuge", bn: "অমুখাপেক্ষী", fr: "L'Absolu", id: "Yang Maha Dibutuhkan", ur: "بے نیاز", tr: "Her Şey O'na Muhtaç", ar: "المقصود في الحوائج" , zh: '自給自足者', ja: '永遠に続くもの'},
    explain: { en: "As-Samad is one of the most profound names — the Eternal Refuge to whom all creation turns in need, who is Himself in need of nothing. The root samada means to head toward, to depend upon. Al-Samad is self-contained, self-sufficient, and the destination of all need. Surah al-Ikhlas gives both dimensions: 'Allah, As-Samad. He neither begets nor was begotten, nor is there to Him any equivalent' (112:2-4). Al-Ghazali writes that every creature in need is, in reality, turning to As-Samad whether they know it or not.", bn: "আস-সামাদ সবচেয়ে গভীর নামগুলির একটি — সেই চিরন্তন আশ্রয় যার দিকে সমস্ত সৃষ্টি প্রয়োজনে মুখ ফেরায়, যিনি নিজে কোনো কিছুর মুখাপেক্ষী নন। সূরা আল-ইখলাস উভয় মাত্রা দেয়: 'আল্লাহ, আস-সামাদ। তিনি জন্ম দেননি এবং জন্মিতও হননি' (১১২:২-৪)।" },
    invoke: { en: "The two names Al-Ahad and As-Samad from Surah al-Ikhlas form the most complete declaration of tawhid. Recite this surah 3 times daily — the Prophet said it is equivalent to reciting one-third of the Quran (Bukhari 6643). When you feel needy, helpless, or looking for ultimate support, turn to As-Samad.", bn: "সূরা আল-ইখলাসের দুই নাম আল-আহাদ ও আস-সামাদ তাওহিদের সবচেয়ে সম্পূর্ণ ঘোষণা তৈরি করে। এই সূরাটি প্রতিদিন ৩ বার পাঠ করুন — নবী (সা.) বলেছেন এটি কুরআনের এক-তৃতীয়াংশ পাঠের সমতুল্য (বুখারী ৬৬৪৩)।" } ,
    hadith: { en: "The Prophet ﷺ said of a man who supplicated 'You are Al-Ahad, As-Samad, who begets not nor is begotten...' that he had asked Allah by His Greatest Name, by which when He is asked He gives.", bn: "যে ব্যক্তি দু'আ করেছিল 'আপনি আল-আহাদ, আস-সামাদ, যিনি কাউকে জন্ম দেননি ও কেউ তাঁকে জন্ম দেয়নি...', তার সম্পর্কে নবী ﷺ বললেন সে আল্লাহকে তাঁর মহত্তম নামে ডেকেছে, যে নামে চাইলে তিনি দান করেন।", src: "Sunan Abi Dawud 1493; Jami' at-Tirmidhi 3475" },
    quranicRefs: [
      { ref: "112:2", noteEn: "Allahu-s-Samad — Allah is As-Samad; the entire surah then explains this name: uncreated, unbegotten, incomparable.", noteBn: "আল্লাহুস-সামাদ — আল্লাহ আস-সামাদ; পুরো সূরা তারপর এই নাম ব্যাখ্যা করে: অসৃষ্ট, অজন্মা, তুলনাহীন।" }
    ]},
  { n: 69, ar: "الْقَادِرُ", translit: "Al-Qādir", meanings: { en: "The Capable", bn: "সর্বশক্তিমান", fr: "Le Puissant", id: "Yang Maha Kuasa", ur: "قدرت والا", tr: "Kudret Sahibi", ar: "القادر على كل شيء" , zh: '全能者', ja: '全能'},
    explain: { en: "Al-Qadir is the One who is capable of all things — not limited by physics, logic (from creation's perspective), time, space, or circumstance. The Quran repeatedly asserts: 'Indeed, Allah is over all things competent (Qadir).' While Al-Muqtadir emphasises actively exercising and demonstrating power, Al-Qadir emphasises the inherent and perfect capacity for power. The believer who trusts in Al-Qadir finds that no situation is hopeless, no obstacle is final, and no door is permanently closed.", bn: "আল-কাদির হলেন যিনি সব কিছুতে সক্ষম — পদার্থবিদ্যা, সময়, স্থান বা পরিস্থিতি দ্বারা সীমিত নন। কুরআন বারবার বলে: 'নিশ্চয়ই আল্লাহ সব কিছুতে কাদির।' যে বিশ্বাসী আল-কাদিরকে বিশ্বাস করেন তার কাছে কোনো পরিস্থিতি আশাহীন নয়।" },
    invoke: { en: "When you face what seems impossible — an illness, a debt, a door shut in your face — call upon Al-Qadir. Say 'Ya Qadir' and ask with certainty, for the One capable of all things can change any situation in an instant.", bn: "যখন অসম্ভব মনে হয় এমন কিছুর মুখোমুখি হন — অসুস্থতা, ঋণ, বন্ধ দরজা — আল-কাদিরকে ডাকুন। 'ইয়া কাদির' বলে দৃঢ় বিশ্বাসে চান, কারণ যিনি সব কিছুতে সক্ষম তিনি এক নিমেষে যেকোনো পরিস্থিতি বদলে দিতে পারেন।" } ,
    hadith: { en: "The Prophet ﷺ taught the istikharah: 'O Allah, I seek Your decree by Your power (astaqdiruka bi-qudratika), for You are able and I am not able (fa-innaka taqdiru wa la aqdir), and You know and I know not.'", bn: "নবী ﷺ ইস্তিখারার দু'আ শেখান: 'হে আল্লাহ, আমি আপনার কুদরতের মাধ্যমে সামর্থ্য প্রার্থনা করি, কারণ আপনি সক্ষম, আমি সক্ষম নই (ফাইন্নাকা তাকদিরু ওয়া লা আকদির), আর আপনি জানেন, আমি জানি না।'", src: "Sahih al-Bukhari 1166" },
    quranicRefs: [
      { ref: "6:65", noteEn: "Qul Huwa-l-Qadiru 'ala an yab'atha 'alaykum 'adhaban — Say: He is Al-Qadir, able to send punishment upon you.", noteBn: "কুল হুওয়াল-কাদিরু আলা আন ইয়াবআসা আলাইকুম আযাবান — বলো: তিনি আল-কাদির, তোমাদের উপর শাস্তি পাঠাতে সক্ষম।" },
      { ref: "46:33", noteEn: "Qadirin 'ala an yuhyiya-l-mawta — He is Able to give life to the dead; nothing lies beyond His power.", noteBn: "কাদিরিন আলা আন ইউহইয়াল-মাওতা — তিনি মৃতকে জীবন দিতে সক্ষম; কিছুই তাঁর ক্ষমতার বাইরে নয়।" },
      { ref: "75:40", noteEn: "Alaysa dhalika bi-Qadirin 'ala an yuhyiya-l-mawta — Is not that One Able to give life to the dead?", noteBn: "আলাইসা যালিকা বি-কাদিরিন আলা আন ইউহইয়াল-মাওতা — সেই সত্তা কি মৃতকে জীবন দিতে সক্ষম নন?" },
      { ref: "2:20", noteEn: "Inna-llaha 'ala kulli shay'in Qadir — indeed Allah is over all things competent (Qadir).", noteBn: "ইন্নাল্লাহা আলা কুল্লি শাইইন কাদির — নিশ্চয় আল্লাহ সব কিছুতে সক্ষম (কাদির)।" }
    ]},
  { n: 70, ar: "الْمُقْتَدِرُ", translit: "Al-Muqtadir", meanings: { en: "The Omnipotent", bn: "মহাক্ষমতাবান", fr: "Le Tout-Puissant", id: "Yang Maha Berkuasa", ur: "بڑی قدرت والا", tr: "Mutlak Kudret Sahibi", ar: "التام القدرة" , zh: '掌控者', ja: '決定するもの'},
    explain: { en: "Al-Muqtadir refers to power actively exercised in full measure — omnipotence displayed and demonstrated. The Quran (54:42) states in the context of destroyed civilisations: 'We seized them with the seizure of One Exalted in Power and Capable (Muqtadir).' This is power that cannot be defied; it carries out its will without let or hindrance. For the oppressed, this name is a source of hope; for the unjust, a warning.", bn: "আল-মুক্তাদির পূর্ণ পরিমাণে সক্রিয়ভাবে প্রয়োগ করা ক্ষমতাকে বোঝায়। কুরআন (৫৪:৪২) ধ্বংস হওয়া সভ্যতার প্রসঙ্গে বলে: 'আমরা তাদের শক্তিশালী ও মুক্তাদিরের পাকড়াও দিয়ে পাকড়াও করলাম।'" } ,
    hadith: { en: "In the istikharah the Prophet ﷺ taught: 'astaqdiruka bi-qudratika' (I seek ability from Your power), 'for You have power and I have none (fa-innaka taqdiru wa la aqdir)' — affirming Allah's absolute, prevailing power.", bn: "নবী ﷺ ইস্তিখারায় শেখান: 'আসতাকদিরুকা বিকুদরাতিকা' (আমি আপনার কুদরত থেকে সামর্থ্য চাই), 'কারণ আপনি ক্ষমতাবান, আমি ক্ষমতাহীন (ফাইন্নাকা তাকদিরু ওয়া লা আকদির)' — আল্লাহর পরিপূর্ণ ও প্রবল ক্ষমতার স্বীকৃতি।", src: "Sahih al-Bukhari 1166" },
    quranicRefs: [
      { ref: "54:42", noteEn: "Akhadhna-hum akhdha 'Azizin Muqtadir — We seized them with the seizure of One Exalted, Perfect in Ability (Muqtadir).", noteBn: "আখাযনাহুম আখযা আজিযিন মুক্তাদির — আমরা তাদের পাকড়াও করলাম মহাপরাক্রমশালী, পূর্ণক্ষমতাবান (মুক্তাদির)-এর পাকড়াও দিয়ে।" },
      { ref: "54:55", noteEn: "'Inda Malikin Muqtadir — with a Sovereign, Perfect in Ability; the righteous are honoured before Him.", noteBn: "ইনদা মালিকিন মুক্তাদির — এক সার্বভৌম, পূর্ণক্ষমতাবানের নিকট; সৎকর্মশীলরা তাঁর সামনে সম্মানিত।" },
      { ref: "18:45", noteEn: "Wa kana-llahu 'ala kulli shay'in Muqtadira — Allah is ever, over all things, Perfectly Able.", noteBn: "ওয়া কানাল্লাহু আলা কুল্লি শাইইন মুক্তাদিরা — আল্লাহ সব কিছুর উপর পূর্ণক্ষমতাবান।" },
      { ref: "43:42", noteEn: "Fa-inna 'alayhim Muqtadirun — indeed We are fully Able to carry out Our will upon them.", noteBn: "ফা-ইন্না আলাইহিম মুক্তাদিরুন — নিশ্চয় আমরা তাদের উপর আমাদের ইচ্ছা কার্যকর করতে পূর্ণক্ষম।" }
    ]},
  { n: 71, ar: "الْمُقَدِّمُ", translit: "Al-Muqaddim", meanings: { en: "The Expediter", bn: "অগ্রসরকারী", fr: "Celui qui avance", id: "Yang Maha Mendahulukan", ur: "آگے کرنے والا", tr: "Öne Alan", ar: "المقدِّم لما يشاء" , zh: '促進者', ja: '前身せし者を支えし者'},
    explain: { en: "Al-Muqaddim is the One who advances, promotes, and brings forward what He wills — in rank, time, priority, or position. This name always pairs with Al-Mu'akhkhir (the Delayer): together they express that Allah alone determines the timing and order of all events. Nothing happens before its appointed time, and nothing is delayed past its appointed time. Al-Ghazali notes that accepting this pairing liberates the servant from frustration at timing that seems wrong.", bn: "আল-মুকাদ্দিম হলেন যিনি তিনি যা চান তা এগিয়ে দেন — মর্যাদা, সময়, অগ্রাধিকার বা অবস্থানে। এই নাম সর্বদা আল-মুআখখিরের সাথে জোড়ায় আসে, প্রকাশ করে যে আল্লাহ একাই সকল ঘটনার সময় ও ক্রম নির্ধারণ করেন।" } ,
    quranicRefs: [
      { ref: "16:61", noteEn: "La yasta'khiruna sa'atan wa la yastaqdimun — they can neither delay nor advance their term an hour; He alone brings forward.", noteBn: "লা ইয়াসতাখিরুনা সাআতান ওয়া লা ইয়াসতাকদিমুন — তারা তাদের নির্ধারিত সময় এক ঘণ্টাও এগিয়ে বা পিছিয়ে নিতে পারে না; একমাত্র তিনিই অগ্রসর করেন।" },
      { ref: "7:34", noteEn: "Idha ja'a ajaluhum la yasta'khiruna sa'atan wa la yastaqdimun — when the appointed term comes, none advances or delays it.", noteBn: "ইযা জাআ আজালুহুম লা ইয়াসতাখিরুনা সাআতান ওয়া লা ইয়াসতাকদিমুন — নির্ধারিত সময় এলে কেউ তা এগোতে বা পিছোতে পারে না।" },
      { ref: "6:2", noteEn: "Thumma qada ajalan wa ajalun musamman 'indahu — He decreed a term; the ordering and timing of all lies with Him.", noteBn: "সুম্মা কাদা আজালান ওয়া আজালুন মুসাম্মান ইনদাহু — তিনি একটি মেয়াদ নির্ধারণ করেছেন; সব কিছুর ক্রম ও সময় তাঁরই কাছে।" }
    ]},
  { n: 72, ar: "الْمُؤَخِّرُ", translit: "Al-Mu'akhkhir", meanings: { en: "The Delayer", bn: "বিলম্বকারী", fr: "Celui qui recule", id: "Yang Maha Mengakhirkan", ur: "پیچھے کرنے والا", tr: "Geriye Bırakan", ar: "المؤخِّر لما يشاء" , zh: '延遲者', ja: '遠くへ押しやる遅延者'},
    explain: { en: "Al-Mu'akhkhir is the One who delays and postpones what He wills — in punishment (giving sinners time to repent), in reward (teaching patience), or in timing of events (arranging the perfect moment). This name paired with Al-Muqaddim teaches that there is no such thing as 'too early' or 'too late' in divine decree — only perfectly timed. The believer who has not received what they prayed for should trust in Al-Mu'akhkhir: the delay is wisdom.", bn: "আল-মুআখখির হলেন যিনি তিনি যা চান তা বিলম্বিত করেন — শাস্তিতে (পাপীদের তওবার সুযোগ দিয়ে), পুরস্কারে (ধৈর্য শেখানো), বা ঘটনার সময়ে। এই নাম শেখায় যে ঐশ্বরিক ফয়সালায় 'অনেক আগে' বা 'অনেক দেরি' বলে কিছু নেই।" } ,
    quranicRefs: [
      { ref: "14:42", noteEn: "Innama yu'akhkhiruhum li-yawmin tashkhasu fihi-l-absar — He only delays them to a Day; the deferral is by wisdom, not neglect.", noteBn: "ইন্নামা ইউআখখিরুহুম লি-ইয়াওমিন তাশখাসু ফিহিল-আবসার — তিনি তাদের কেবল একটি দিন পর্যন্ত বিলম্বিত করেন; বিলম্ব প্রজ্ঞাবশত, অবহেলায় নয়।" },
      { ref: "71:4", noteEn: "Yu'akhkhirkum ila ajalin musamma — He will delay you to an appointed term; the Delayer defers life itself.", noteBn: "ইউআখখিরকুম ইলা আজালিন মুসাম্মা — তিনি তোমাদের এক নির্ধারিত মেয়াদ পর্যন্ত বিলম্বিত করবেন; আল-মুআখখির জীবনকেও পিছিয়ে দেন।" },
      { ref: "16:61", noteEn: "Yu'akhkhiruhum ila ajalin musamma — He defers them to a stated term, granting respite to repent.", noteBn: "ইউআখখিরুহুম ইলা আজালিন মুসাম্মা — তিনি তাদের এক নির্ধারিত মেয়াদ পর্যন্ত অবকাশ দেন, তওবার সুযোগ দিয়ে।" },
      { ref: "63:11", noteEn: "Wa lan yu'akhkhira-llahu nafsan idha ja'a ajaluha — Allah will delay no soul once its term has come.", noteBn: "ওয়া লান ইউআখখিরাল্লাহু নাফসান ইযা জাআ আজালুহা — আল্লাহ কোনো প্রাণকে বিলম্বিত করবেন না যখন তার মেয়াদ এসে যায়।" }
    ]},
  { n: 73, ar: "الْأَوَّلُ", translit: "Al-Awwal", meanings: { en: "The First", bn: "সর্বপ্রথম", fr: "Le Premier", id: "Yang Maha Awal", ur: "سب سے پہلا", tr: "İlk", ar: "الأول بلا بداية" , zh: '至先者', ja: '最初'},
    explain: { en: "Al-Awwal is the First with no beginning before Him — He existed before time, before space, before the very concept of 'before.' Quran 57:3 presents four complementary names: 'He is Al-Awwal and Al-Akhir, Az-Zahir and Al-Batin' — the First, the Last, the Manifest, the Hidden. The Prophet (peace be upon him) used this verse in his bedtime supplication, saying: 'O Allah, You are Al-Awwal: there is nothing before You.'", bn: "আল-আওয়াল হলেন প্রথম যাঁর আগে কোনো শুরু নেই। কুরআন ৫৭:৩ চারটি পরিপূরক নাম উপস্থাপন করে: 'তিনি আল-আওয়াল ও আল-আখির, আজ-জাহির ও আল-বাতিন।' নবী (সা.) ঘুমানোর দু'আয় বলতেন: 'হে আল্লাহ, আপনি আল-আওয়াল: আপনার আগে কিছু নেই।'" },
    hadith: { en: "O Allah, You are the First (Al-Awwal): there is nothing before You. And You are the Last (Al-Akhir): there is nothing after You. And You are the Manifest (Az-Zahir): there is nothing above You. And You are the Hidden (Al-Batin): there is nothing beyond You.", bn: "হে আল্লাহ, আপনি আল-আওয়াল: আপনার আগে কিছু নেই। আপনি আল-আখির: আপনার পরে কিছু নেই। আপনি আজ-জাহির: আপনার উপরে কিছু নেই। আপনি আল-বাতিন: আপনার ওপারে কিছু নেই।", src: "Sahih Muslim 2713" } ,
    quranicRefs: [
      { ref: "57:3", noteEn: "Huwa-l-Awwal wa-l-Akhir wa-z-Zahir wa-l-Batin — the four complementary names; Al-Awwal: nothing before Him.", noteBn: "হুওয়াল-আওয়ালু ওয়াল-আখিরু ওয়াজ-জাহিরু ওয়াল-বাতিনু — চারটি পরিপূরক নাম; আল-আওয়াল: তাঁর আগে কিছু নেই।" }
    ]},
  { n: 74, ar: "الْآخِرُ", translit: "Al-Ākhir", meanings: { en: "The Last", bn: "সর্বশেষ", fr: "Le Dernier", id: "Yang Maha Akhir", ur: "سب سے آخر", tr: "Son", ar: "الآخر بلا نهاية" , zh: '末後者', ja: '最後'},
    explain: { en: "Al-Akhir is the Last with no end after Him — He will remain when all creation has ceased. The Quran (55:26-27) declares: 'Whoever is on [the earth] will perish, and the Face of your Lord of Majesty and Honor will remain.' The pairing with Al-Awwal is perfect: what existed without beginning will persist without end. This name is a source of comfort: even after death, the soul returns to Al-Akhir, and at the end of time, only He remains.", bn: "আল-আখির হলেন শেষ যাঁর পরে কোনো শেষ নেই। কুরআন (৫৫:২৬-২৭) ঘোষণা করে: 'পৃথিবীতে যা আছে সব ধ্বংস হবে, এবং আপনার মহিমা ও সম্মানের প্রভুর মুখমণ্ডল থাকবে।'" } ,
    hadith: { en: "The Prophet ﷺ would say at bedtime: 'You are Al-Awwal, there is nothing before You; and You are Al-Akhir (the Last), there is nothing after You.'", bn: "নবী ﷺ ঘুমানোর সময় বলতেন: 'আপনি আল-আউয়াল (প্রথম), আপনার পূর্বে কিছু নেই; আর আপনি আল-আখির (সর্বশেষ), আপনার পরে কিছু নেই।'", src: "Sahih Muslim 2713" },
    quranicRefs: [
      { ref: "57:3", noteEn: "Huwa-l-Awwal wa-l-Akhir — Al-Akhir: nothing after Him; when all creation ends He remains, the Last without end.", noteBn: "হুওয়াল-আওয়ালু ওয়াল-আখিরু — আল-আখির: তাঁর পরে কিছু নেই; সমস্ত সৃষ্টি শেষ হলেও তিনি থাকেন।" }
    ]},
  { n: 75, ar: "الظَّاهِرُ", translit: "Aẓ-Ẓāhir", meanings: { en: "The Manifest", bn: "প্রকাশ্য", fr: "L'Apparent", id: "Yang Maha Nyata", ur: "ظاہر", tr: "Aşikâr Olan", ar: "الظاهر فوق كل شيء" , zh: '明显者', ja: 'すべてを勝利に導くもの'},
    explain: { en: "Az-Zahir is the Manifest — He is known and evident through His signs, creation, and divine attributes manifested everywhere. The heavens, earth, the human body, and every phenomenon are signs (ayat) pointing to Az-Zahir. Yet He is also Al-Batin (the Hidden), transcending and existing beyond all that is manifest. This pair teaches that evidence of Allah is everywhere (zahir) yet His essence remains beyond our grasp (batin).", bn: "আজ-জাহির হলেন প্রকাশ্য — তিনি তাঁর নিদর্শন, সৃষ্টি এবং সর্বত্র প্রকাশিত ঐশ্বরিক গুণাবলীর মাধ্যমে জ্ঞাত ও সুস্পষ্ট। আকাশ, পৃথিবী, মানব শরীর আজ-জাহিরের দিকে নির্দেশকারী আয়াত।" } ,
    hadith: { en: "The Prophet ﷺ would say: 'You are Az-Zahir (the Manifest), there is nothing above You; and You are Al-Batin, there is nothing beneath You.'", bn: "নবী ﷺ বলতেন: 'আপনি আয-যাহির (প্রকাশ্য), আপনার ঊর্ধ্বে কিছু নেই; আর আপনি আল-বাতিন (গুপ্ত), আপনার অগোচরে কিছু নেই।'", src: "Sahih Muslim 2713" },
    quranicRefs: [
      { ref: "57:3", noteEn: "Huwa-z-Zahir — He is Az-Zahir; His signs fill creation, making Him the most manifest of the manifest.", noteBn: "হুওয়াজ-জাহিরু — তিনি আজ-জাহির; তাঁর নিদর্শন সৃষ্টিতে পরিপূর্ণ, তিনিই সবচেয়ে প্রকাশ্য।" }
    ]},
  { n: 76, ar: "الْبَاطِنُ", translit: "Al-Bāṭin", meanings: { en: "The Hidden", bn: "গুপ্ত", fr: "Le Caché", id: "Yang Maha Tersembunyi", ur: "پوشیدہ", tr: "Gizli Olan", ar: "العالم بالخفايا" , zh: '隱微者', ja: '隠されし者'},
    explain: { en: "Al-Batin is the Hidden — His essence transcends all perception and conceptualisation. No eye has seen Him, no mind has encompassed Him, no description can adequately capture Him. Yet Al-Batin is not distant: He is closer to the servant than their jugular vein (Quran 50:16). The pairing Az-Zahir/Al-Batin captures the paradox of divine immanence and transcendence: everywhere manifest in His signs, yet transcending all comprehension in His essence.", bn: "আল-বাতিন হলেন গোপন — তাঁর সত্তা সমস্ত উপলব্ধি ও ধারণার অতীত। তবুও আল-বাতিন দূরে নন: তিনি বান্দার গলার শিরার চেয়েও কাছে (কুরআন ৫০:১৬)।" } ,
    hadith: { en: "The Prophet ﷺ would supplicate: 'You are Az-Zahir, there is nothing above You; and You are Al-Batin (the Hidden), there is nothing beneath You. Settle our debt and free us from want.'", bn: "নবী ﷺ দু'আ করতেন: 'আপনি আয-যাহির, আপনার ঊর্ধ্বে কিছু নেই; আর আপনি আল-বাতিন (গুপ্ত), আপনার অগোচরে কিছু নেই। আমাদের ঋণ পরিশোধ করুন ও অভাবমুক্ত করুন।'", src: "Sahih Muslim 2713" },
    quranicRefs: [
      { ref: "57:3", noteEn: "Huwa-l-Batin — He is Al-Batin; despite being Manifest, His essence remains beyond all grasp — the Hidden.", noteBn: "হুওয়াল-বাতিনু — তিনি আল-বাতিন; প্রকাশ্য হওয়া সত্ত্বেও তাঁর সত্তা সকলের নাগালের বাইরে — গুপ্ত।" }
    ]},
  { n: 77, ar: "الْوَالِي", translit: "Al-Wālī", meanings: { en: "The Governor", bn: "মহাপরিচালক", fr: "Le Gérant", id: "Yang Maha Memerintah", ur: "حاکم و والی", tr: "İşleri Yöneten", ar: "المتولي للأمور" , zh: '保護的朋友', ja: '後援者'},
    explain: { en: "Al-Wali (Governor) is the One who has complete authority over and governs all of creation — the universe operates according to His administration, and nothing falls outside His governance. This differs from Al-Waliyy (the Protecting Friend, name 55): Al-Wali is governance and sovereignty, while Al-Waliyy is friendship and protection. The Quran (13:11) states: 'Allah does not change a people's condition until they change what is within themselves' — showing that Al-Wali's governance is responsive to human choices.", bn: "আল-ওয়ালি (পরিচালক) হলেন যিনি সমস্ত সৃষ্টির উপর সম্পূর্ণ কর্তৃত্ব রাখেন ও পরিচালনা করেন। এটি আল-ওয়ালিয়্যু (সংরক্ষণকারী বন্ধু, নাম ৫৫) থেকে আলাদা: আল-ওয়ালি হলো শাসন ও সার্বভৌমত্ব।" } ,
    quranicRefs: [
      { ref: "13:11", noteEn: "Wa ma lahum min dunihi min wal — they have no governor or protector besides Him; all authority is His.", noteBn: "ওয়া মা লাহুম মিন দুনিহি মিন ওয়াল — তিনি ছাড়া তাদের কোনো অভিভাবক বা রক্ষক নেই; সমস্ত কর্তৃত্ব তাঁর।" },
      { ref: "42:9", noteEn: "Fa-llahu Huwa-l-Waliyy — Allah, He alone is the Protecting Guardian who governs His creation's affairs.", noteBn: "ফাল্লাহু হুওয়াল-ওয়ালিয়্যু — আল্লাহ, একমাত্র তিনিই অভিভাবক যিনি সৃষ্টির সব কাজ পরিচালনা করেন।" },
      { ref: "42:28", noteEn: "Wa Huwa-l-Waliyy-ul-Hamid — He is the Protector, the Praiseworthy, who sends mercy and manages all.", noteBn: "ওয়া হুওয়াল-ওয়ালিয়্যুল-হামিদ — তিনি অভিভাবক, প্রশংসিত, যিনি রহমত পাঠান ও সব পরিচালনা করেন।" },
      { ref: "4:45", noteEn: "Wa kafa bi-llahi Waliyya — Allah suffices as a Protector and Governor over His servants.", noteBn: "ওয়া কাফা বিল্লাহি ওয়ালিয়্যা — অভিভাবক ও পরিচালক হিসেবে আল্লাহই যথেষ্ট।" }
    ]},
  { n: 78, ar: "الْمُتَعَالِي", translit: "Al-Mutaʿālī", meanings: { en: "The Most Exalted", bn: "সর্বোন্নত", fr: "Le Sublime", id: "Yang Maha Tinggi Derajat", ur: "سب سے برتر", tr: "Pek Yüce Olan", ar: "المتعالي عن النقائص" , zh: '至高者', ja: '自己を高揚するもの'},
    explain: { en: "Al-Muta'ali is the One who is Most Exalted, supremely above all limitations, defects, and comparisons — far beyond what any mind can imagine or any creation can resemble. The Quran (13:9) places Al-Muta'ali after Al-Kabir, showing escalating ascent. Al-Ghazali notes that Al-'Aliyy refers to transcendence in essence; Al-Muta'ali refers to transcendence that is continuously and actively maintained — He is always becoming 'more exalted' in relation to whatever is being described.", bn: "আল-মুতাআলি হলেন যিনি সর্বোচ্চ, সমস্ত সীমাবদ্ধতা ও তুলনার অনেক উপরে। কুরআন (১৩:৯) আল-মুতাআলিকে আল-কাবিরের পরে রাখে। আল-গাজালী লক্ষ্য করেন যে আল-আলিয়্যু সত্তায় অতীন্দ্রিয়তা বোঝায়; আল-মুতাআলি ক্রমাগত ও সক্রিয়ভাবে বজায় রাখা অতীন্দ্রিয়তা বোঝায়।" } ,
    quranicRefs: [
      { ref: "13:9", noteEn: "'Alimu-l-ghaybi wa-sh-shahadati-l-Kabiru-l-Muta'al — the Great, the Most Exalted (Al-Muta'al); the name appears directly.", noteBn: "আলিমুল-গাইবি ওয়াশ-শাহাদাতিল-কাবিরুল-মুতাআল — অদৃশ্য ও দৃশ্যের জ্ঞাতা, মহান, সর্বোন্নত (আল-মুতাআল); নামটি সরাসরি এসেছে।" },
      { ref: "20:114", noteEn: "Fa-Ta'ala-llahu-l-Maliku-l-Haqq — Exalted is Allah, the Sovereign, the Truth, above all deficiency.", noteBn: "ফা-তাআলাল্লাহুল-মালিকুল-হাক্ক — সর্বোচ্চ আল্লাহ, প্রকৃত অধিপতি, সমস্ত ত্রুটির ঊর্ধ্বে।" },
      { ref: "23:92", noteEn: "'Alimi-l-ghaybi wa-sh-shahadati fa-Ta'ala 'amma yushrikun — Exalted far above what they associate with Him.", noteBn: "আলিমিল-গাইবি ওয়াশ-শাহাদাতি ফা-তাআলা আম্মা ইউশরিকুন — তারা যা শরিক করে তার বহু ঊর্ধ্বে তিনি।" },
      { ref: "27:63", noteEn: "Ta'ala-llahu 'amma yushrikun — High is Allah above the partners they ascribe.", noteBn: "তাআলাল্লাহু আম্মা ইউশরিকুন — তারা যা শরিক করে তার ঊর্ধ্বে আল্লাহ সমুন্নত।" }
    ]},
  { n: 79, ar: "الْبَرُّ", translit: "Al-Barr", meanings: { en: "The Source of Goodness", bn: "পরম উপকারী", fr: "Le Bon", id: "Yang Maha Baik", ur: "نیکی والا", tr: "İyilik Sahibi", ar: "كثير الإحسان" , zh: '至善者', ja: '最も親切で正しい者'},
    explain: { en: "Al-Barr is the Source of all goodness, kindness, and beneficence — His goodness is inherent to His being, not a response to external factors. The Quran (52:28) has the people of paradise say: 'We used to supplicate to Him before; He is Al-Barr, Al-Rahim.' This name encompasses both tenderness (birr) and righteousness — the goodness that flows outward to all creation. Ibn al-Qayyim notes that the righteous (abrar) take their name from this divine attribute.", bn: "আল-বার্র হলেন সমস্ত ভালোত্ব ও কল্যাণের উৎস। কুরআন (৫২:২৮) এ জান্নাতবাসীরা বলে: 'আমরা আগে থেকে তাঁকে ডাকতাম; তিনি আল-বার্র, আর-রাহিম।'" } ,
    quranicRefs: [
      { ref: "52:28", noteEn: "Inna-hu Huwa-l-Barr-ur-Rahim — He is Al-Barr and Ar-Rahim; the people of Paradise acknowledge His goodness.", noteBn: "ইন্নাহু হুওয়াল-বার্রুর-রাহিম — তিনি আল-বার্র ও আর-রাহিম; জান্নাতের অধিবাসীরা তাঁর কল্যাণ স্বীকার করে।" }
    ]},
  { n: 80, ar: "التَّوَّابُ", translit: "At-Tawwāb", meanings: { en: "The Acceptor of Repentance", bn: "তাওবা কবুলকারী", fr: "L'Accueillant au repentir", id: "Yang Maha Penerima Tobat", ur: "توبہ قبول کرنے والا", tr: "Tövbeleri Kabul Eden", ar: "القابل للتوبة" , zh: '悔罪的接受者', ja: '還ること'},
    explain: { en: "At-Tawwab is the One who perpetually, repeatedly turns in acceptance toward the repentant servant — and the servant's tawbah (repentance) is only possible because Allah first turns toward them. The Quran (49:12) says: 'Indeed, Allah is At-Tawwab, the Merciful.' Al-Ghazali notes the reciprocal nature: Allah's 'turning' (tawbah in its divine sense) towards the servant enables the servant's 'turning' (tawbah in the human sense) towards Allah. This is one of the most intimate divine-human interactions.", bn: "আত-তাওওয়াব হলেন যিনি তওবাকারী বান্দার দিকে ক্রমাগত, বারবার গ্রহণযোগ্যতায় মুখ ফেরান। আল-গাজালী পারস্পরিক প্রকৃতি লক্ষ্য করেন: আল্লাহর 'ফেরা' বান্দার 'ফেরা' সক্ষম করে — এটি সবচেয়ে ঘনিষ্ঠ ঐশ্বরিক-মানবিক মিথস্ক্রিয়াগুলির মধ্যে একটি।" },
    hadith: { en: "Allah rejoices more at the repentance of His servant when he repents than one of you would rejoice if he were on his riding camel in the wilderness and it strayed from him, and he despaired of finding it, then it came to him.", bn: "আল্লাহ তাঁর বান্দার তওবায় তোমাদের মধ্যে সেই ব্যক্তির চেয়ে বেশি আনন্দিত হন, যে মরুভূমিতে তার সওয়ারিতে ছিল এবং তা হারিয়ে গেলে নিরাশ হয়ে পড়েছিল, তারপর সে আবার ফিরে আসে।", src: "Sahih al-Bukhari 6309; Sahih Muslim 2747" },
    invoke: { en: "When seeking repentance, say: 'Allahumma Anta At-Tawwab Al-Rahim, fa-tub 'alayy' (O Allah, You are At-Tawwab, the Most Merciful — so turn to me in repentance). The Prophet (peace be upon him) said that Allah rejoices more at a servant's repentance than a man who finds his lost camel in the desert (Bukhari 6309).", bn: "তওবা করতে বলুন: 'আল্লাহুম্মা আনতাত-তাওওয়াবুর-রাহিম, ফাতুব আলাইয়্যা।' নবী (সা.) বলেছেন আল্লাহ বান্দার তওবায় মরুভূমিতে হারানো উট খুঁজে পাওয়া মানুষের চেয়ে বেশি খুশি হন (বুখারী ৬৩০৯)।" } ,
    quranicRefs: [
      { ref: "2:37", noteEn: "Fa-taba-llahu alayhi... Inna-hu Huwa-t-Tawwab-ur-Rahim — Allah relented toward Adam; the first instance of At-Tawwab in human history.", noteBn: "ফাতাবাল্লাহু আলায়হি... ইন্নাহু হুওয়াত-তাওওয়াবুর-রাহিম — আল্লাহ আদমের প্রতি ফিরলেন; মানব ইতিহাসে আত-তাওওয়াবের প্রথম উদাহরণ।" },
      { ref: "2:54", noteEn: "Moses commands his people to repent... Inna-hu Huwa-t-Tawwab-ur-Rahim — collective repentance is accepted.", noteBn: "মূসা জনগণকে তওবার আদেশ দেন... ইন্নাহু হুওয়াত-তাওওয়াবুর-রাহিম — সমষ্টিগত তওবা কবুল হয়।" },
      { ref: "2:128", noteEn: "Ibrahim and Ismail: Wa tub alayna, Inna-ka Anta-t-Tawwab-ur-Rahim — the prophet-patriarch invokes At-Tawwab.", noteBn: "ইব্রাহিম ও ইসমাইল: ওয়া তুব আলায়না — ইন্নাকা আনতাত-তাওওয়াবুর-রাহিম; নবী-পিতৃপুরুষ আত-তাওওয়াবকে ডাকেন।" },
      { ref: "49:12", noteEn: "Wa tubu ila-llahi jami'an... Inna-llaha Tawwab-un Rahim — repent to Allah together; a communal invitation.", noteBn: "ওয়া তুবু ইলাল্লাহি জামিআন... ইন্নাল্লাহা তাওওয়াবুন রাহিম — সবাই আল্লাহর কাছে তওবা করো; সামষ্টিক আমন্ত্রণ।" },
      { ref: "110:3", noteEn: "Wa-staghfir-hu, inna-hu kana Tawwaba — seek His forgiveness; He has been At-Tawwab; even the Prophet is commanded to seek tawbah.", noteBn: "ওয়াস্তাগফিরহু, ইন্নাহু কানা তাওওয়াবা — ক্ষমা চাও; তিনি তাওওয়াব; এমনকি নবীকেও তওবা চাইতে বলা হয়েছে।" }
    ]},
  { n: 81, ar: "الْمُنْتَقِمُ", translit: "Al-Muntaqim", meanings: { en: "The Avenger", bn: "প্রতিশোধগ্রহণকারী", fr: "Le Vengeur", id: "Yang Maha Pembalas", ur: "بدلہ لینے والا", tr: "Suçluları Cezalandıran", ar: "المنتقم من العصاة" , zh: '復仇者', ja: '復讐せし者'},
    explain: { en: "Al-Muntaqim is the Avenger who exacts full retribution on those who persist in oppression and transgression. This name should not be misunderstood as vengeful in a petty sense; divine intiqam (retribution) is the just response to crimes against Allah's servants and divine rights. The Quran (32:22) says: 'And who is more unjust than one who is reminded of the signs of his Lord, then turns away? Indeed, We will take retribution from the criminals.' This name assures the oppressed that justice will prevail.", bn: "আল-মুনতাকিম হলেন সেই প্রতিশোধকারী যিনি অত্যাচার ও পাপে অবিচল থাকা লোকদের কাছ থেকে পূর্ণ প্রতিশোধ নেন। কুরআন (৩২:২২) বলে: 'আমরা অপরাধীদের কাছ থেকে প্রতিশোধ নেব।' এই নাম নিপীড়িতদের আশ্বস্ত করে যে ন্যায়বিচার বিজয়ী হবে।" } ,
    quranicRefs: [
      { ref: "32:22", noteEn: "Inna mina-l-mujrimina Muntaqimun — Indeed We will take retribution from the criminals who turn away.", noteBn: "ইন্না মিনাল-মুজরিমিনা মুনতাকিমুন — নিশ্চয় আমরা অপরাধীদের থেকে প্রতিশোধ নেব যারা মুখ ফিরিয়ে নেয়।" },
      { ref: "43:41", noteEn: "Fa-inna minhum Muntaqimun — We will surely exact retribution from them.", noteBn: "ফা-ইন্না মিনহুম মুনতাকিমুন — অবশ্যই আমরা তাদের থেকে প্রতিশোধ নেব।" },
      { ref: "44:16", noteEn: "Yawma nabtishu-l-batshata-l-kubra inna Muntaqimun — the Day We seize with the great seizure, indeed We will avenge.", noteBn: "ইয়াওমা নাবতিশুল-বাতশাতাল-কুবরা ইন্না মুনতাকিমুন — যেদিন আমরা কঠোরভাবে পাকড়াও করব, নিশ্চয় আমরা প্রতিশোধ নেব।" },
      { ref: "39:37", noteEn: "Alaysa-llahu bi-'Azizin dhi-ntiqam — Is not Allah Exalted in Might, Owner of Retribution?", noteBn: "আলাইসাল্লাহু বি-আজিযিন যিনতিকাম — আল্লাহ কি পরাক্রমশালী, প্রতিশোধের অধিকারী নন?" }
    ]},
  { n: 82, ar: "الْعَفُوُّ", translit: "Al-ʿAfuww", meanings: { en: "The Pardoner", bn: "মহাক্ষমাকারী", fr: "L'Indulgent", id: "Yang Maha Pemaaf", ur: "بہت معاف کرنے والا", tr: "Affedici", ar: "كثير العفو" , zh: '赦宥者', ja: '許す者'},
    explain: { en: "Al-'Afuww goes beyond forgiveness — 'afw means to erase and obliterate entirely, so that the sin leaves no trace in the divine record. Al-Ghafur covers the sin; Al-'Afuww erases it completely. The Prophet (peace be upon him) taught the famous Laylat al-Qadr du'a: 'Allahumma innaka 'Afuwwun tuhibbu al-'afwa fa'fu 'anni' (O Allah, You are Al-'Afuww, You love to pardon, so pardon me). This is the preferred du'a of the ten nights of Laylat al-Qadr.", bn: "আল-আফুওয়্যু ক্ষমার বাইরে যায় — 'আফু মানে সম্পূর্ণ মুছে ফেলা ও বিলুপ্ত করা, যাতে পাপ ঐশ্বরিক রেকর্ডে কোনো চিহ্ন না রাখে। নবী (সা.) লায়লাতুল কদরের বিখ্যাত দু'আ শেখিয়েছেন: 'আল্লাহুম্মা ইন্নাকা আফুওয়ুন তুহিব্বুল আফওয়া ফাআফু আন্নি।'" },
    hadith: { en: "Aisha (may Allah be pleased with her) said: I asked, 'O Messenger of Allah, if I know which night is Laylat al-Qadr, what should I say?' He replied: Say: Allahumma innaka 'Afuwwun tuhibbu al-'afwa fa'fu 'anni (O Allah, You are the Pardoner, You love to pardon, so pardon me).", bn: "আয়িশা (রা.) বললেন: আমি জিজ্ঞেস করলাম, 'হে আল্লাহর রাসূল, যদি আমি জানি কোন রাত লায়লাতুল কদর, তাহলে কী বলব?' তিনি বললেন: বলো: 'আল্লাহুম্মা ইন্নাকা আফুওয়ুন তুহিব্বুল আফওয়া ফাআফু আন্নি।'", src: "Sunan al-Tirmidhi 3513 (Sahih)" },
    invoke: { en: "Especially in the last ten nights of Ramadan (seeking Laylat al-Qadr), repeat: 'Allahumma innaka 'Afuwwun tuhibbu al-'afwa fa'fu 'anni.' Al-'Afuww erases the sin entirely — not just covering it but removing it from the record forever.", bn: "বিশেষত রমজানের শেষ দশ রাতে (লায়লাতুল কদর অন্বেষণে) বারবার বলুন: 'আল্লাহুম্মা ইন্নাকা আফুওয়ুন তুহিব্বুল আফওয়া ফাআফু আন্নি।' আল-আফুওয়্যু পাপ সম্পূর্ণ মুছে দেন।" } ,
    quranicRefs: [
      { ref: "4:43", noteEn: "Inna-llaha kana Afuww-an Ghafura — Allah is Al-Afuww and Al-Ghafur; mercy underlies the law of purification.", noteBn: "ইন্নাল্লাহা কানা আফুওয়্যান গাফুরা — আল্লাহ আল-আফুওয়্যু ও আল-গাফুর; পবিত্রতার আইনে রহমত মূলে।" },
      { ref: "4:99", noteEn: "Wa kana-llahu Afuww-an Ghafura — Allah is Al-Afuww and Al-Ghafur for those unable to migrate for His sake.", noteBn: "ওয়া কানাল্লাহু আফুওয়্যান গাফুরা — আল্লাহর পথে হিজরতে অক্ষমদের জন্য আল-আফুওয়্যু ও আল-গাফুর।" },
      { ref: "4:149", noteEn: "Fa-inna-llaha kana Afuww-an Qadira — Allah is Al-Afuww and Al-Qadir; He has power to punish yet pardons.", noteBn: "ফাইন্নাল্লাহা কানা আফুওয়্যান কাদিরা — আল্লাহ আল-আফুওয়্যু ও আল-কাদির; শাস্তির ক্ষমতা থাকলেও ক্ষমা করেন।" },
      { ref: "22:60", noteEn: "Inna-llaha la-Afuww-un Ghafur — in the ruling on just retaliation; divine pardon is greater than human justice.", noteBn: "ইন্নাল্লাহা লা-আফুওয়্যুন গাফুর — ন্যায্য প্রতিশোধের বিধানে; ঐশ্বরিক ক্ষমা মানবিক বিচারের চেয়ে মহান।" },
      { ref: "58:2", noteEn: "Wa inna-llaha la-Afuww-un Ghafur — even grave marital oaths are subject to Al-Afuww's mercy.", noteBn: "ওয়া ইন্নাল্লাহা লা-আফুওয়্যুন গাফুর — গুরুতর বৈবাহিক শপথও আল-আফুওয়্যুর রহমতের অধীন।" }
    ]},
  { n: 83, ar: "الرَّءُوفُ", translit: "Ar-Ra'ūf", meanings: { en: "The Most Kind", bn: "পরম স্নেহশীল", fr: "Le Compatissant", id: "Yang Maha Belas Kasih", ur: "نہایت شفیق", tr: "Çok Şefkatli", ar: "الرؤوف بعباده" , zh: '至慈者', ja: '哀れみ深き者'},
    explain: { en: "Ar-Ra'uf is from ra'fah — the deepest, most tender compassion, even more intense than rahmah. While Ar-Rahman is broad mercy for all, Ar-Ra'uf is intimate, gentle compassion especially for the vulnerable. The Quran (9:128) describes the Prophet (peace be upon him) as ra'uf and rahim — qualities he was given as a reflection of divine attributes. Ar-Ra'uf is the compassion that winces at the pain of others and is moved to help.", bn: "আর-রাউফ রাফা থেকে এসেছে — সবচেয়ে গভীর, কোমলতম সহানুভূতি, রাহমার চেয়েও তীব্র। যখন আর-রাহমান সকলের জন্য ব্যাপক রহমত, আর-রাউফ বিশেষত দুর্বলদের জন্য অন্তরঙ্গ, কোমল সহানুভূতি।" } ,
    quranicRefs: [
      { ref: "2:143", noteEn: "Inna-llaha bi-n-nasi la-Ra'uf-un Rahim — Allah is Ra'uf and Rahim toward people; affirmed in the change of qibla.", noteBn: "ইন্নাল্লাহা বিন-নাসি লা-রাউফুন রাহিম — আল্লাহ মানুষের প্রতি রাউফ ও রাহিম; কিবলা পরিবর্তনে নিশ্চিত।" },
      { ref: "3:30", noteEn: "Wa-llahu Ra'uf-un bil-ibad — Allah is Ra'uf toward His servants; affirmed in the context of divine reckoning.", noteBn: "ওয়াল্লাহু রাউফুন বিল-ইবাদ — আল্লাহ তাঁর বান্দাদের প্রতি রাউফ; ঐশ্বরিক হিসাবের প্রসঙ্গে নিশ্চিত।" },
      { ref: "9:117", noteEn: "Inna-hu bihim Ra'uf-un Rahim — Allah's tender compassion for those who followed the Prophet in his hour of hardship.", noteBn: "ইন্নাহু বিহিম রাউফুন রাহিম — কঠিন সময়ে নবীকে অনুসরণকারীদের প্রতি আল্লাহর কোমল সহানুভূতি।" },
      { ref: "9:128", noteEn: "Bi-l-mu'minina Ra'uf-un Rahim — the Prophet is described with Ra'uf and Rahim, divine qualities gifted to the mercy for mankind.", noteBn: "বিল-মুমিনিনা রাউফুন রাহিম — নবীকে রাউফ ও রাহিম বলা হয়েছে, মানবজাতির রহমতকে প্রদত্ত ঐশ্বরিক গুণ।" },
      { ref: "16:7", noteEn: "Inna Rabbakum la-Ra'uf-un Rahim — your Lord is indeed Ra'uf and Rahim; affirmed as He provides animals to carry burdens.", noteBn: "ইন্না রাব্বাকুম লা-রাউফুন রাহিম — তোমাদের প্রভু নিশ্চয়ই রাউফ ও রাহিম; প্রাণী দিয়ে বোঝা বহানোর প্রসঙ্গে।" }
    ]},
  { n: 84, ar: "مَالِكُ الْمُلْكِ", translit: "Mālik-ul-Mulk", meanings: { en: "Master of the Kingdom", bn: "রাজত্বের মালিক", fr: "Maître du Royaume", id: "Pemilik Kerajaan", ur: "ملک کا مالک", tr: "Mülkün Ebedî Sahibi", ar: "مالك الملك كله" , zh: '主權擁有者', ja: '全ての主権を持つ者'},
    explain: { en: "Malik-ul-Mulk is the Absolute Owner of all sovereignty — not just a king who rules, but the Owner who possesses the very concept of kingship itself. The Quran (3:26) quotes the invocation: 'O Allah, Master of the Kingdom, You give the kingdom to whom You will and take it from whom You will; You honor whom You will and humble whom You will.' No political power exists except by His permission, and all earthly kings are temporary trustees of what belongs to Malik-ul-Mulk.", bn: "মালিকুল-মুলক হলেন সমস্ত সার্বভৌমত্বের পরম মালিক। কুরআন (৩:২৬) এই আহ্বান উদ্ধৃত করে: 'হে আল্লাহ, রাজত্বের মালিক, আপনি যাকে চান রাজত্ব দেন এবং যার কাছ থেকে চান ছিনিয়ে নেন।'" },
    invoke: { en: "When seeking elevation in position, honour, or influence — or when facing those who wield unjust authority over you — recite Quran 3:26-27: 'Quli-l-Lahumma Malika-l-Mulki, tu'ti-l-mulka man tasha...' (Say: O Allah, Master of the Kingdom, You give kingdom to whom You will...). This du'a recognises that all power belongs to Allah.", bn: "অবস্থান, সম্মান বা প্রভাবে উন্নতির জন্য, বা যারা অন্যায়ভাবে ক্ষমতা ব্যবহার করে তাদের মুখোমুখি হলে, কুরআন ৩:২৬-২৭ পড়ুন: 'কুলিল্লাহুম্মা মালিকাল-মুলকি তুতিল-মুলকা মান তাশা...'।" } ,
    quranicRefs: [
      { ref: "3:26", noteEn: "Quli-llahumma Malik-al-Mulki tu'ti-l-mulka man tasha — O Allah, Master of the Kingdom, You give kingdom to whom You will.", noteBn: "কুলিল্লাহুম্মা মালিকাল-মুলকি তুতিল-মুলকা মান তাশা — হে আল্লাহ, রাজত্বের মালিক, যাকে চান রাজত্ব দেন।" }
    ]},
  { n: 85, ar: "ذُو الْجَلَالِ وَالْإِكْرَامِ", translit: "Dhul-Jalāli wal-Ikrām", meanings: { en: "Lord of Majesty and Honor", bn: "মহিমা ও সম্মানের অধিকারী", fr: "Détenteur de Majesté et de Générosité", id: "Pemilik Kebesaran dan Kemuliaan", ur: "جلال اور اکرام والا", tr: "Azamet ve İkram Sahibi", ar: "صاحب الجلال والإكرام" , zh: '尊榮之主', ja: '偉大にして高潔なる王'},
    explain: { en: "Dhul-Jalali wal-Ikram is one of the grandest composite names — combining Majesty (Jalal: awe-inspiring greatness, transcendence, power) with Honour/Generosity (Ikram: dignity, nobility, generous treatment of guests). The Prophet (peace be upon him) said: 'Hold fast to ya Dhul-Jalali wal-Ikram' (Tirmidhi 3524) — making this a frequently recommended name to call upon. Ibn al-Qayyim writes that jalal moves the heart to reverence and awe, while ikram moves the heart to hope and love — together they produce the complete worshipper.", bn: "যুল-জালালি ওয়াল-ইকরাম সবচেয়ে মহৎ যৌগিক নামগুলির একটি — মহিমা ও সম্মান/উদারতা একত্রিত করে। নবী (সা.) বলেছেন: 'ইয়া যুল-জালালি ওয়াল-ইকরামকে আঁকড়ে ধরো' (তিরমিযী ৩৫২৪)।" },
    hadith: { en: "Hold fast to 'Ya Dhul-Jalali wal-Ikram' (O Lord of Majesty and Honor).", bn: "'ইয়া যুল-জালালি ওয়াল-ইকরাম' (হে মহিমা ও সম্মানের প্রভু) কে আঁকড়ে ধরো।", src: "Sunan al-Tirmidhi 3524 (Hasan Sahih)" } ,
    quranicRefs: [
      { ref: "55:27", noteEn: "Wa yabqa Wajhu Rabbika Dhu-l-Jalali wal-Ikram — His Face of Majesty and Honor will remain when all else perishes.", noteBn: "ওয়া ইয়াবকা ওয়াজহু রাব্বিকা যুল-জালালি ওয়াল-ইকরাম — সব কিছু ধ্বংস হলেও তাঁর মহিমা ও সম্মানের মুখ থাকবে।" },
      { ref: "55:78", noteEn: "Tabaraka-smu Rabbika Dhi-l-Jalali wal-Ikram — the name of your Lord, Owner of Jalal and Ikram, is blessed.", noteBn: "তাবারাকাসমু রাব্বিকা যিল-জালালি ওয়াল-ইকরাম — তোমার প্রভুর নাম মুবারক, জালাল ও ইকরামের মালিক।" }
    ]},
  { n: 86, ar: "الْمُقْسِطُ", translit: "Al-Muqsiṭ", meanings: { en: "The Equitable", bn: "ন্যায়পরায়ণ", fr: "L'Équitable", id: "Yang Maha Memberi Keadilan", ur: "انصاف کرنے والا", tr: "Adaletle Hükmeden", ar: "العادل المنصف" , zh: '公正者', ja: '公平なる者'},
    explain: { en: "Al-Muqsit is the One who establishes and enacts perfect, balanced justice — justice that gives everyone their due without excess or deficiency. While Al-'Adl (name 29) describes the attribute of justice, Al-Muqsit describes its active exercise: Allah not only is just, He establishes justice. The Quran (3:18) affirms: 'Allah testifies that there is no deity except Him, as do the angels and those of knowledge, maintaining justice.' He is simultaneously the legislator, judge, and executor of justice.", bn: "আল-মুকসিত হলেন যিনি নিখুঁত, সুষম ন্যায়বিচার প্রতিষ্ঠা ও প্রয়োগ করেন। কুরআন (৩:১৮) নিশ্চিত করে: 'আল্লাহ সাক্ষ্য দেন যে তিনি ছাড়া কোনো উপাস্য নেই, ন্যায়বিচার প্রতিষ্ঠা করে।'" } ,
    quranicRefs: [
      { ref: "3:18", noteEn: "Shahida-llahu... qa'iman bi-l-qist — Allah bears witness, maintaining justice (qist); the root of Al-Muqsit.", noteBn: "শাহিদাল্লাহু... কাইমান বিল-কিসত — আল্লাহ সাক্ষ্য দেন, ন্যায়বিচার (কিসত) প্রতিষ্ঠিত রেখে; আল-মুকসিতের মূল।" },
      { ref: "21:47", noteEn: "Wa nada'u-l-mawazina-l-qista li-yawmi-l-qiyamah — We place the scales of justice for the Day of Resurrection.", noteBn: "ওয়া নাদাউল-মাওয়াযিনাল-কিসতা লি-ইয়াওমিল-কিয়ামাহ — কিয়ামতের দিনে আমরা ন্যায়ের দাঁড়িপাল্লা স্থাপন করব।" },
      { ref: "10:47", noteEn: "Qudiya baynahum bi-l-qist wa hum la yuzlamun — it is judged among them in justice, and they are not wronged.", noteBn: "কুদিয়া বাইনাহুম বিল-কিসত ওয়া হুম লা ইউযলামুন — তাদের মধ্যে ন্যায়ের সাথে ফয়সালা হবে, তারা অত্যাচারিত হবে না।" },
      { ref: "10:54", noteEn: "Wa qudiya baynahum bi-l-qist wa hum la yuzlamun — He judges between them with equity, none is oppressed.", noteBn: "ওয়া কুদিয়া বাইনাহুম বিল-কিসত ওয়া হুম লা ইউযলামুন — তিনি তাদের মধ্যে ন্যায়ের সাথে বিচার করেন, কেউ নিপীড়িত হয় না।" }
    ]},
  { n: 87, ar: "الْجَامِعُ", translit: "Al-Jāmiʿ", meanings: { en: "The Gatherer", bn: "একত্রকারী", fr: "Le Rassembleur", id: "Yang Maha Mengumpulkan", ur: "جمع کرنے والا", tr: "Toplayan", ar: "الجامع للخلق يوم القيامة" , zh: '統合者', ja: '収集する者'},
    explain: { en: "Al-Jami' is the Gatherer who assembles all creation on the Day of Resurrection for the final reckoning — the first and last humans, all simultaneously. The Quran (4:87) says: 'Allah — there is no deity except Him. He will surely assemble you for the Day of Resurrection, about which there is no doubt.' Al-Jami' also describes how Allah gathers and holds together the cosmos, the Quran, and all attributes of perfection within Himself without contradiction.", bn: "আল-জামি হলেন সমাবেশকারী যিনি চূড়ান্ত হিসাবের জন্য কিয়ামতের দিনে সমস্ত সৃষ্টিকে একত্রিত করেন। কুরআন (৪:৮৭) বলে: 'আল্লাহ — তিনি ছাড়া কোনো উপাস্য নেই। তিনি নিশ্চয়ই তোমাদের কিয়ামতের দিনে একত্রিত করবেন।'" } ,
    quranicRefs: [
      { ref: "3:9", noteEn: "Rabbana innaka Jami'u-n-nasi li-yawmin la rayba fih — You will gather mankind for a Day about which there is no doubt.", noteBn: "রাব্বানা ইন্নাকা জামিউন-নাসি লি-ইয়াওমিন লা রাইবা ফিহ — আপনি মানুষকে এমন এক দিনে একত্র করবেন যাতে কোনো সন্দেহ নেই।" },
      { ref: "4:140", noteEn: "Inna-llaha Jami'u-l-munafiqina wa-l-kafirina fi jahannama jami'a — Allah will gather the hypocrites and disbelievers all together.", noteBn: "ইন্নাল্লাহা জামিউল-মুনাফিকিনা ওয়াল-কাফিরিনা ফি জাহান্নামা জামিআ — আল্লাহ মুনাফিক ও কাফিরদের সবাইকে জাহান্নামে একত্র করবেন।" },
      { ref: "42:29", noteEn: "Wa Huwa 'ala jam'ihim idha yasha'u Qadir — He is Able to gather them whenever He wills.", noteBn: "ওয়া হুওয়া আলা জামইহিম ইযা ইয়াশাউ কাদির — তিনি যখন ইচ্ছা তাদের একত্র করতে সক্ষম।" },
      { ref: "64:9", noteEn: "Yawma yajma'ukum li-yawmi-l-jam' — the Day He gathers you for the Day of Assembly.", noteBn: "ইয়াওমা ইয়াজমাউকুম লি-ইয়াওমিল-জামই — যেদিন তিনি তোমাদের সমাবেশের দিনে একত্র করবেন।" }
    ]},
  { n: 88, ar: "الْغَنِيُّ", translit: "Al-Ghaniyy", meanings: { en: "The Self-Sufficient", bn: "অভাবমুক্ত", fr: "Le Riche", id: "Yang Maha Kaya", ur: "غنی", tr: "Zengin, Muhtaç Olmayan", ar: "الغني عن الخلق" , zh: '富有者', ja: '全ての裕福なる者'},
    explain: { en: "Al-Ghaniyy is completely self-sufficient, independent, and in need of nothing — not our worship, not our praise, not our repentance. The Quran (47:38) says: 'Allah is the Self-Sufficient, and you are the needy.' This is humbling: all our acts of worship are not for Allah's benefit but for ours. Al-Ghazali writes that understanding Al-Ghaniyy frees the servant from performing acts of worship for show (riya') or expecting gratitude from people — because Allah alone needs nothing, and only Allah's gratitude matters.", bn: "আল-গানিয়্যু সম্পূর্ণ স্বনির্ভর ও স্বাধীন — তাঁর আমাদের ইবাদত, প্রশংসা বা তওবার কোনো প্রয়োজন নেই। কুরআন (৪৭:৩৮) বলে: 'আল্লাহ স্বনির্ভর, আর তোমরা অভাবী।'" } ,
    hadith: { en: "Allah says: 'O My servants, all of you are hungry except those whom I feed, so ask food of Me and I will feed you. All of you are naked except those whom I clothe, so ask clothing of Me and I will clothe you.'", bn: "আল্লাহ বলেন: 'হে আমার বান্দারা, তোমরা সবাই ক্ষুধার্ত তারা ছাড়া যাদের আমি খাওয়াই, তাই আমার কাছে খাদ্য চাও আমি খাওয়াব। তোমরা সবাই বস্ত্রহীন তারা ছাড়া যাদের আমি পরাই, তাই আমার কাছে পোশাক চাও আমি পরাব।'", src: "Sahih Muslim 2577 (Hadith Qudsi)" },
    quranicRefs: [
      { ref: "35:15", noteEn: "Ya ayyuha-n-nasu antum-ul-fuqara ila-llah wa-llahu Huwa-l-Ghani-ul-Hamid — you are needy toward Allah; He is Al-Ghaniyy.", noteBn: "ইয়া আয়্যুহান-নাসু আনতুমুল-ফুকারাউ ইলাল্লাহ ওয়াল্লাহু হুওয়াল-গানিয়্যুল-হামিদ — তোমরা আল্লাহর মুখাপেক্ষী।" },
      { ref: "47:38", noteEn: "Antum-ul-fuqara wa-llahu Huwa-l-Ghani — you are the poor, and Allah is Al-Ghaniyy; self-sufficiency belongs to Him alone.", noteBn: "আনতুমুল-ফুকারাউ ওয়াল্লাহু হুওয়াল-গানিয়্যু — তোমরা অভাবী, আল্লাহ আল-গানিয়্যু; স্বনির্ভরতা একমাত্র তাঁর।" }
    ]},
  { n: 89, ar: "الْمُغْنِي", translit: "Al-Mughnī", meanings: { en: "The Enricher", bn: "অভাবমোচনকারী", fr: "Celui qui enrichit", id: "Yang Maha Memberi Kekayaan", ur: "غنی کرنے والا", tr: "Zenginlik Veren", ar: "المغني لعباده" , zh: '賜予財富者', ja: '豊かにする者'},
    explain: { en: "Al-Mughni is the One who enriches — not just materially but in every dimension of life: knowledge, contentment, relationships, and spiritual wealth. The Quran (9:28) refers to Allah making people self-sufficient from His bounty. The Prophet (peace be upon him) taught: 'Richness is not having many possessions, but richness is the contentment of the soul' (Bukhari 6446) — pointing to the inner enrichment that only Al-Mughni can provide.", bn: "আল-মুগনি হলেন যিনি সমৃদ্ধ করেন — কেবল বস্তুগতভাবে নয় বরং জীবনের প্রতিটি মাত্রায়। নবী (সা.) শেখিয়েছেন: 'সম্পদ অনেক মাল রাখা নয়, বরং সম্পদ হলো আত্মার সন্তুষ্টি' (বুখারী ৬৪৪৬)।" },
    invoke: { en: "In poverty or need, call upon Al-Mughni to enrich you — with provision, or better still with contentment and independence from creation. Ask Him to make you rich in heart, for the Prophet ﷺ said true wealth is the richness of the soul.", bn: "দারিদ্র্য বা প্রয়োজনে আল-মুগনিকে ডাকুন যেন তিনি আপনাকে সম্পদ দিয়ে, বা তার চেয়ে ভালো — পরিতৃপ্তি ও সৃষ্টির প্রতি নির্মুখাপেক্ষিতা দিয়ে অভাবমুক্ত করেন। অন্তরের ধনী হওয়ার দু'আ করুন, কারণ নবী ﷺ বলেছেন প্রকৃত সম্পদ হলো আত্মার সচ্ছলতা।" } ,
    quranicRefs: [
      { ref: "53:48", noteEn: "Wa annahu Huwa aghna wa aqna — and it is He who enriches (aghna) and grants possessions.", noteBn: "ওয়া আন্নাহু হুওয়া আগনা ওয়া আকনা — আর তিনিই অভাবমুক্ত করেন (আগনা) ও সম্পদ দান করেন।" },
      { ref: "93:8", noteEn: "Wa wajadaka 'a'ilan fa-aghna — He found you poor and enriched you; addressed to the Prophet ﷺ.", noteBn: "ওয়া ওয়াজাদাকা আইলান ফা-আগনা — তিনি তোমাকে অভাবী পেয়ে অভাবমুক্ত করেছেন; নবী ﷺ-কে সম্বোধন।" },
      { ref: "9:28", noteEn: "Fa-sawfa yughnikumu-llahu min fadlihi — Allah will enrich you from His bounty if He wills.", noteBn: "ফা-সাওফা ইউগনিকুমুল্লাহু মিন ফাদলিহি — আল্লাহ চাইলে তাঁর অনুগ্রহ থেকে তোমাদের অভাবমুক্ত করবেন।" },
      { ref: "24:32", noteEn: "In yakunu fuqara'a yughnihimu-llahu min fadlih — if they are poor, Allah will enrich them from His bounty.", noteBn: "ইন ইয়াকুনু ফুকারাআ ইউগনিহিমুল্লাহু মিন ফাদলিহ — তারা অভাবী হলে আল্লাহ তাদের তাঁর অনুগ্রহ থেকে অভাবমুক্ত করবেন।" }
    ]},
  { n: 90, ar: "الْمَانِعُ", translit: "Al-Māniʿ", meanings: { en: "The Preventer", bn: "প্রতিরোধকারী", fr: "Celui qui empêche", id: "Yang Maha Mencegah", ur: "روکنے والا", tr: "Engelleyen", ar: "المانع لما يشاء" , zh: '保護者', ja: '抑えし者'},
    explain: { en: "Al-Mani' is the One who prevents, withholds, and protects — always according to divine wisdom. Sometimes He prevents harm from reaching His servants (protective prevention); sometimes He withholds what servants desire for their own good (educative prevention). The Prophet (peace be upon him) said in his morning and evening dhikr: 'What You prevent, no one can give; and what You give, no one can prevent.' This teaches that al-Mani' and al-Mu'ti (the Giver) are two faces of the same perfect divine management.", bn: "আল-মানি হলেন যিনি প্রতিরোধ, আটকে রাখেন ও সুরক্ষা করেন — সর্বদা ঐশ্বরিক প্রজ্ঞা অনুযায়ী। নবী (সা.) সকাল-সন্ধ্যার যিকিরে বলতেন: 'আপনি যা আটকান কেউ দিতে পারে না; আর আপনি যা দেন কেউ আটকাতে পারে না।'" } ,
    quranicRefs: [
      { ref: "35:2", noteEn: "Ma yaftahi-llahu li-n-nasi min rahmatin fa-la mumsika laha wa ma yumsik fa-la mursila lahu — what He withholds none can release.", noteBn: "মা ইয়াফতাহিল্লাহু লিন-নাসি মিন রাহমাতিন ফা-লা মুমসিকা লাহা ওয়া মা ইউমসিক ফা-লা মুরসিলা লাহু — তিনি যা আটকান তা কেউ ছাড়তে পারে না।" },
      { ref: "39:38", noteEn: "In aradani bi-rahmatin hal hunna mumsikatu rahmatih — could any withhold His mercy? Only He grants and withholds.", noteBn: "ইন আরাদানি বি-রাহমাতিন হাল হুন্না মুমসিকাতু রাহমাতিহ — কেউ কি তাঁর রহমত আটকাতে পারে? একমাত্র তিনিই দেন ও আটকান।" },
      { ref: "67:21", noteEn: "Amman hadha-lladhi yarzuqukum in amsaka rizqah — who could provide for you if He withheld His provision?", noteBn: "আম্মান হাযাল-লাযি ইয়ারযুকুকুম ইন আমসাকা রিযকাহ — তিনি তাঁর রিযিক আটকে রাখলে কে তোমাদের রিযিক দেবে?" }
    ]},
  { n: 91, ar: "الضَّارُّ", translit: "Aḍ-Ḍārr", meanings: { en: "The Distresser", bn: "ক্ষতি সাধনকারী", fr: "Celui qui peut nuire", id: "Yang Maha Pemberi Mudarat", ur: "نقصان پہنچانے والا", tr: "Zarar Vermeye Kâdir", ar: "الضار بحكمته" , zh: '折磨者', ja: '苦悩するもの'},
    explain: { en: "Ad-Darr must be understood in its proper theological context: Allah can cause harm (darar) to whomever He wills, and this always appears paired with An-Nafi' (the Benefiter). This is not arbitrariness or cruelty — divine harm is always purposeful: as a test, a consequence of oppression, or a divine warning. Quran 10:107 states: 'If Allah afflicts you with harm, none can remove it except Him.' Recognising Ad-Darr teaches that harm and hardship ultimately come from a wisdom-driven divine plan.", bn: "আদ-দার্র বুঝতে হবে সঠিক ধর্মতাত্ত্বিক প্রেক্ষাপটে: আল্লাহ যাকে চান ক্ষতি করতে পারেন। কুরআন ১০:১০৭ বলে: 'আল্লাহ যদি তোমাকে কোনো ক্ষতিতে আক্রান্ত করেন, তিনি ছাড়া কেউ তা দূর করতে পারবে না।'" } ,
    quranicRefs: [
      { ref: "6:17", noteEn: "Wa in yamsaska-llahu bi-durrin fa-la kashifa lahu illa Huwa — if Allah touches you with harm, none can remove it but He.", noteBn: "ওয়া ইন ইয়ামসাসকাল্লাহু বি-দুররিন ফা-লা কাশিফা লাহু ইল্লা হুওয়া — আল্লাহ তোমাকে ক্ষতি দিয়ে স্পর্শ করলে তিনি ছাড়া কেউ তা দূর করতে পারে না।" },
      { ref: "10:107", noteEn: "Wa in yamsaska-llahu bi-durrin fa-la kashifa lahu illa Huwa — harm decreed by Him none can lift but Him.", noteBn: "ওয়া ইন ইয়ামসাসকাল্লাহু বি-দুররিন ফা-লা কাশিফা লাহু ইল্লা হুওয়া — তাঁর নির্ধারিত ক্ষতি তিনি ছাড়া কেউ দূর করতে পারে না।" },
      { ref: "48:11", noteEn: "Man yamliku lakum mina-llahi shay'an in arada bikum darran — who can avail you against Allah if He intends harm?", noteBn: "মান ইয়ামলিকু লাকুম মিনাল্লাহি শাইআন ইন আরাদা বিকুম দাররান — তিনি ক্ষতি চাইলে আল্লাহর বিরুদ্ধে কে তোমাদের রক্ষা করবে?" },
      { ref: "39:38", noteEn: "In aradani-llahu bi-durrin hal hunna kashifatu durrih — could any remove the harm He wills? None but He.", noteBn: "ইন আরাদানিয়াল্লাহু বি-দুররিন হাল হুন্না কাশিফাতু দুররিহ — তিনি যে ক্ষতি চান তা কি কেউ দূর করতে পারে? একমাত্র তিনি।" }
    ]},
  { n: 92, ar: "النَّافِعُ", translit: "An-Nāfiʿ", meanings: { en: "The Benefiter", bn: "কল্যাণকারী", fr: "Le Bienfaisant", id: "Yang Maha Pemberi Manfaat", ur: "نفع دینے والا", tr: "Fayda Veren", ar: "النافع بفضله" , zh: '創造善良者', ja: '慈悲深い者'},
    explain: { en: "An-Nafi' is the Benefiter — the One who alone can bring true benefit, good, and blessing. This name always pairs with Ad-Darr: together they establish that both harm and benefit are in Allah's hands alone. The Quran (10:107) states: 'If Allah wills good for you, none can repel His favor.' Al-Ghazali notes that recognising An-Nafi' as the exclusive source of benefit liberates the believer from seeking benefit through forbidden means or from those who have no power to truly benefit.", bn: "আন-নাফি হলেন উপকারকারী — একমাত্র যিনি সত্যিকারের উপকার, ভালো ও আশীর্বাদ আনতে পারেন। এই নাম সর্বদা আদ-দার্রের সাথে জোড়ায় আসে। কুরআন (১০:১০৭) বলে: 'আল্লাহ যদি তোমার ভালো চান কেউ তাঁর অনুগ্রহ প্রতিহত করতে পারে না।'" },
    invoke: { en: "Ask An-Nafi' to make beneficial for you your knowledge, wealth, health, and time, and to bring good to others through your hands. When something seems to benefit you, remember its benefit is only by His permission.", bn: "আন-নাফিকে ডাকুন যেন তিনি আপনার জ্ঞান, সম্পদ, স্বাস্থ্য ও সময়কে কল্যাণকর করেন এবং আপনার হাতে অন্যের উপকার আনেন। কোনো কিছু আপনার উপকার করলে মনে রাখুন তার উপকার কেবল তাঁরই অনুমতিতে।" } ,
    quranicRefs: [
      { ref: "48:11", noteEn: "Aw arada bikum naf'a — or if He intends benefit (naf') for you, none can prevent it.", noteBn: "আও আরাদা বিকুম নাফআ — অথবা তিনি তোমাদের কল্যাণ (নাফ) চাইলে কেউ তা রুখতে পারে না।" },
      { ref: "7:188", noteEn: "La amliku li-nafsi naf'an wa la darran illa ma sha'a-llah — I hold no benefit or harm for myself except as Allah wills.", noteBn: "লা আমলিকু লি-নাফসি নাফআন ওয়া লা দাররান ইল্লা মা শাআল্লাহ — আল্লাহ যা চান তা ছাড়া আমি নিজের কল্যাণ বা ক্ষতির মালিক নই।" },
      { ref: "10:49", noteEn: "Qul la amliku li-nafsi darran wa la naf'an illa ma sha'a-llah — benefit and harm belong to Allah alone.", noteBn: "কুল লা আমলিকু লি-নাফসি দাররান ওয়া লা নাফআন ইল্লা মা শাআল্লাহ — কল্যাণ ও ক্ষতি একমাত্র আল্লাহরই।" }
    ]},
  { n: 93, ar: "النُّورُ", translit: "An-Nūr", meanings: { en: "The Light", bn: "মহাজ্যোতি", fr: "La Lumière", id: "Yang Maha Bercahaya", ur: "نور", tr: "Nûr", ar: "نور السماوات والأرض" , zh: '光明者', ja: '光'},
    explain: { en: "An-Nur is the Light of the heavens and the earth — not light in the physical sense (photons) but the Divine Reality by which all existence is illuminated, known, and guided. Quran 24:35 gives the famous metaphor of a lamp in a niche, concluding: 'Allah is the Light of the heavens and the earth.' Ibn al-Qayyim devoted an entire work (Madarij al-Salikin) to the spiritual illumination that flows from An-Nur. Hearts are illuminated by faith, guided by the Quran, and see truly only through divine light.", bn: "আন-নুর হলেন আকাশমণ্ডল ও পৃথিবীর আলো। কুরআন ২৪:৩৫ বিখ্যাত রূপক দেয় একটি কুলুঙ্গিতে একটি প্রদীপের, উপসংহারে বলে: 'আল্লাহ আকাশ ও পৃথিবীর নুর।'" },
    hadith: { en: "O Allah, place light in my heart, light in my sight, light in my hearing, light on my right, light on my left, light above me, light below me, light in front of me, light behind me, and make me light.", bn: "হে আল্লাহ, আমার হৃদয়ে নুর রাখুন, দৃষ্টিতে নুর, শ্রবণে নুর, ডানে নুর, বামে নুর, উপরে নুর, নিচে নুর, সামনে নুর, পিছনে নুর, এবং আমাকে নুর করুন।", src: "Sahih al-Bukhari 6316; Sahih Muslim 763" } ,
    quranicRefs: [
      { ref: "24:35", noteEn: "Allahu Nuru-s-samawati wa-l-ard — Allah is the Light of the heavens and earth; the famous Light Verse with its profound parable.", noteBn: "আল্লাহু নুরুস-সামাওয়াতি ওয়াল-আরদ — আল্লাহ আকাশ ও পৃথিবীর নুর; গভীর রূপকসহ বিখ্যাত নুরের আয়াত।" }
    ]},
  { n: 94, ar: "الْهَادِي", translit: "Al-Hādī", meanings: { en: "The Guide", bn: "পথপ্রদর্শক", fr: "Le Guide", id: "Yang Maha Pemberi Petunjuk", ur: "ہدایت دینے والا", tr: "Hidayet Veren", ar: "الهادي إلى الحق" , zh: '引導者', ja: '導く者'},
    explain: { en: "Al-Hadi is the Guide who leads whomever He wills to truth, right action, and ultimate salvation. Guidance (hidayah) in Islamic theology has two dimensions: general guidance (showing the path to all through revelation) and specific guidance (enabling certain hearts to accept and act upon it). The Quran (22:54) says: 'And indeed, Allah is the Guide of those who have believed to a straight path.' The believer's greatest need is guidance (hidayah) — sought in every rakat of every prayer through Surah al-Fatiha.", bn: "আল-হাদি হলেন সেই পথনির্দেশক যিনি যাকে চান তাকে সত্য, সৎকর্ম এবং চূড়ান্ত মুক্তির দিকে পরিচালিত করেন। কুরআন (২২:৫৪) বলে: 'নিশ্চয়ই আল্লাহ যারা ঈমান এনেছে তাদের সরল পথে পথনির্দেশ করেন।'" },
    invoke: { en: "The most important du'a for guidance is in Surah al-Fatiha itself: 'Ihdina-s-sirat al-mustaqim' (Guide us to the straight path) — said at least 17 times daily in the five prayers. Additionally, recite: 'Allahumma Anta-l-Hadi, fa-dini wa-qawwim 'iwajaji' (O Allah, You are the Guide, so guide me and straighten my crookedness).", bn: "হেদায়েতের জন্য সবচেয়ে গুরুত্বপূর্ণ দু'আ সূরা আল-ফাতিহাতেই আছে: 'ইহদিনাস-সিরাতাল-মুস্তাকিম' — পাঁচ ওয়াক্ত নামাজে প্রতিদিন কমপক্ষে ১৭ বার বলা হয়।" } ,
    hadith: { en: "The Prophet ﷺ taught al-Hasan the du'a of Qunut: 'Allahumma-hdini fiman hadayt' (O Allah, guide me among those You have guided).", bn: "নবী ﷺ হাসান (রাঃ)-কে কুনুতের দু'আ শেখান: 'আল্লাহুম্মাহদিনি ফিমান হাদাইত' (হে আল্লাহ, যাদের আপনি হিদায়াত দিয়েছেন তাদের সাথে আমাকেও হিদায়াত দিন)।", src: "Sunan Abi Dawud 1425; Jami' at-Tirmidhi 464" },
    quranicRefs: [
      { ref: "22:54", noteEn: "Wa inna-llaha la-Hadi-lladhina amanu ila Sirat-in Mustaqim — Allah is the Guide of those who believe to the straight path.", noteBn: "ওয়া ইন্নাল্লাহা লা-হাদিল্লাযিনা আমানু ইলা সিরাতিন মুস্তাকিম — আল্লাহ বিশ্বাসীদের সরল পথের পথপ্রদর্শক।" },
      { ref: "25:31", noteEn: "Wa kafa bi-Rabbika Hadiyan wa Nasira — your Lord suffices as Guide and Helper against those who oppose the truth.", noteBn: "ওয়া কাফা বিরাব্বিকা হাদিয়ান ওয়া নাসিরা — তোমার প্রভু পথপ্রদর্শক ও সাহায্যকারী হিসেবে যথেষ্ট।" }
    ]},
  { n: 95, ar: "الْبَدِيعُ", translit: "Al-Badīʿ", meanings: { en: "The Incomparable Originator", bn: "অভিনব স্রষ্টা", fr: "L'Inventeur", id: "Yang Maha Pencipta Tanpa Contoh", ur: "بے مثال پیدا کرنے والا", tr: "Örneksiz Yaratan", ar: "المبدع بلا مثال" , zh: '無可比擬至先者', ja: '比類なき者'},
    explain: { en: "Al-Badi' is the incomparable Originator — He created the universe and everything in it without any prior model, blueprint, or precedent. The Quran (2:117) states: 'Creator (Badi') of the heavens and earth; when He decrees a matter, He only says: Be! — and it is.' Every atom, every galaxy, every human, every concept that exists is an unprecedented original creation from Al-Badi'. Human artists work from references; Al-Badi' has none.", bn: "আল-বাদি হলেন তুলনাহীন মৌলিক স্রষ্টা — কোনো পূর্ববর্তী মডেল, নকশা বা নজির ছাড়াই মহাবিশ্ব ও তার সবকিছু সৃষ্টি করেছেন। কুরআন (২:১১৭) বলে: 'আকাশমণ্ডল ও পৃথিবীর বাদি; যখন কোনো বিষয় ফয়সালা করেন তিনি কেবল বলেন: হও! এবং তা হয়ে যায়।'" } ,
    quranicRefs: [
      { ref: "2:117", noteEn: "Badi'u-s-samawati wa-l-ard — Originator of the heavens and earth without any prior model; the name appears directly.", noteBn: "বাদিউস-সামাওয়াতি ওয়াল-আরদ — আসমান ও যমীনের অভিনব স্রষ্টা, কোনো পূর্বনমুনা ছাড়াই; নামটি সরাসরি এসেছে।" },
      { ref: "6:101", noteEn: "Badi'u-s-samawati wa-l-ard, anna yakunu lahu walad — Originator of all; how could He have a son?", noteBn: "বাদিউস-সামাওয়াতি ওয়াল-আরদ, আন্না ইয়াকুনু লাহু ওয়ালাদ — সব কিছুর অভিনব স্রষ্টা; তাঁর সন্তান কীভাবে হবে?" },
      { ref: "21:104", noteEn: "Kama bada'na awwala khalqin nu'iduh — as We originated the first creation We will repeat it; unmatched creative power.", noteBn: "কামা বাদানা আওয়ালা খালকিন নুইদুহ — যেভাবে আমরা প্রথম সৃষ্টি শুরু করেছি তা আবার ফিরিয়ে আনব; অতুলনীয় সৃজনক্ষমতা।" },
      { ref: "35:1", noteEn: "Fatiri-s-samawati wa-l-ard — Originator of the heavens and earth, fashioning without precedent.", noteBn: "ফাতিরিস-সামাওয়াতি ওয়াল-আরদ — আসমান ও যমীনের স্রষ্টা, পূর্বনমুনা ছাড়াই গঠনকারী।" }
    ]},
  { n: 96, ar: "الْبَاقِي", translit: "Al-Bāqī", meanings: { en: "The Everlasting", bn: "চিরস্থায়ী", fr: "Le Permanent", id: "Yang Maha Kekal", ur: "ہمیشہ باقی رہنے والا", tr: "Bâki Olan", ar: "الباقي بعد فناء الخلق" , zh: '克制者、永生者', ja: '不朽にして不変なる者'},
    explain: { en: "Al-Baqi is the Everlasting who remains when all else perishes. The Quran (55:26-27) says: 'All that exists will perish, but the Face of your Lord, full of Majesty and Honor, will remain.' Al-Baqi is the complement of Al-Awwal and Al-Akhir: the First has no beginning, the Last has no end, and Al-Baqi is the One who persists throughout. For the believer who has lost someone or something, Al-Baqi is the anchor: what is truly good and true returns to Al-Baqi and is preserved with Him.", bn: "আল-বাকি হলেন চিরস্থায়ী যিনি সব কিছু ধ্বংস হওয়ার পরেও থাকেন। কুরআন (৫৫:২৬-২৭) বলে: 'যা কিছু আছে সব ধ্বংস হবে, কিন্তু আপনার মহিমা ও সম্মানপূর্ণ প্রভুর মুখমণ্ডল থাকবে।'" } ,
    quranicRefs: [
      { ref: "55:26", noteEn: "Kullu man 'alayha fan — everyone upon the earth will perish; the necessary counterpart to Al-Baqi.", noteBn: "কুল্লু মান আলাইহা ফান — পৃথিবীর সব কিছু বিলীন হবে; আল-বাকির অপরিহার্য প্রতিরূপ।" },
      { ref: "55:27", noteEn: "Wa yabqa wajhu Rabbika Dhu-l-Jalali wa-l-Ikram — the Face of your Lord, full of Majesty, will remain (yabqa).", noteBn: "ওয়া ইয়াবকা ওয়াজহু রাব্বিকা যুল-জালালি ওয়াল-ইকরাম — মহিমা ও সম্মানের অধিকারী তোমার প্রভুর চেহারা চিরস্থায়ী থাকবে (ইয়াবকা)।" },
      { ref: "20:73", noteEn: "Wa-llahu khayrun wa abqa — and Allah is better and more lasting (abqa) than all else.", noteBn: "ওয়াল্লাহু খাইরুন ওয়া আবকা — আর আল্লাহ সবকিছুর চেয়ে উত্তম ও চিরস্থায়ী (আবকা)।" },
      { ref: "28:88", noteEn: "Kullu shay'in halikun illa wajhah — everything will perish except His Face; He alone endures.", noteBn: "কুল্লু শাইইন হালিকুন ইল্লা ওয়াজহাহ — তাঁর চেহারা ছাড়া সব কিছু ধ্বংস হবে; একমাত্র তিনিই চিরস্থায়ী।" }
    ]},
  { n: 97, ar: "الْوَارِثُ", translit: "Al-Wārith", meanings: { en: "The Inheritor", bn: "চূড়ান্ত উত্তরাধিকারী", fr: "L'Héritier", id: "Yang Maha Mewarisi", ur: "سب کا وارث", tr: "Her Şeyin Vârisi", ar: "الوارث بعد فناء الخلق" , zh: '萬物繼承者', ja: '後継者、全てを受け継ぐ者'},
    explain: { en: "Al-Warith is the Ultimate Inheritor — when all creation ends and every 'owner' has perished, everything returns to Al-Warith, who was always the true owner. The Quran (15:23) says: 'And indeed, it is We who give life and cause death, and We are the Heir (Al-Warith).' The Prophet Zakariyya (Zechariah, peace be upon him) called to Al-Warith: 'You are the best of inheritors' (Quran 21:89). This name reframes possession: we never truly own anything; we are temporary custodians for Al-Warith.", bn: "আল-ওয়ারিছ হলেন পরম উত্তরাধিকারী — যখন সমস্ত সৃষ্টি শেষ হয় এবং প্রতিটি 'মালিক' মারা যায়, সবকিছু আল-ওয়ারিছের কাছে ফিরে আসে। কুরআন (১৫:২৩) বলে: 'নিশ্চয়ই আমরাই জীবন দিই ও মৃত্যু ঘটাই, এবং আমরা ওয়ারিছ।'" } ,
    hadith: { en: "Among the Prophet's ﷺ supplications: 'and make it the inheritor from us (wa-j'alhu-l-waritha minna)' — entrusting to Allah, the ultimate Inheritor, all that survives us.", bn: "নবী ﷺ-এর একটি দু'আ: 'ওয়াজ'আলহুল-ওয়ারিসা মিন্না' (আমার শক্তি-সামর্থ্যকে আমার উত্তরাধিকারী বানিয়ে দিন) — আমাদের পরে যা টিকে থাকে তা চূড়ান্ত উত্তরাধিকারী আল্লাহর হাতে সমর্পণ।", src: "Jami' at-Tirmidhi 3502" },
    quranicRefs: [
      { ref: "15:23", noteEn: "Wa Inna la-Nahnu nuhyi wa numumit wa Nahnu-l-Warithun — We give life and cause death, and We are the Inheritors.", noteBn: "ওয়া ইন্না লা-নাহনু নুহয়ি ওয়া নুমিতু ওয়া নাহনুল-ওয়ারিছুন — আমরা জীবন দিই, মৃত্যু ঘটাই এবং আমরা ওয়ারিছ।" },
      { ref: "19:40", noteEn: "Inna Nahnu narithu-l-ard wa man alayha — We will inherit the earth and all upon it; all returns to Al-Warith.", noteBn: "ইন্না নাহনু নারিছুল-আরদ ওয়ামান আলায়হা — আমরা পৃথিবী ও তার উপরের সব উত্তরাধিকার পাব।" },
      { ref: "21:89", noteEn: "Wa Anta khayru-l-Warithun — Zakariyya's prayer: You are the best of inheritors; Al-Warith receives all at the end.", noteBn: "ওয়া আনতা খায়রুল-ওয়ারিছিন — যাকারিয়ার দুআ: আপনি সর্বোত্তম ওয়ারিছ; আল-ওয়ারিছ সবকিছু শেষে ফিরে পান।" },
      { ref: "57:10", noteEn: "Wa lillahi miraathu-s-samawati wa-l-ard — and to Allah belongs the inheritance of the heavens and earth.", noteBn: "ওয়া লিল্লাহি মিরাছুস-সামাওয়াতি ওয়াল-আরদ — আকাশ ও পৃথিবীর উত্তরাধিকার আল্লাহরই।" }
    ]},
  { n: 98, ar: "الرَّشِيدُ", translit: "Ar-Rashīd", meanings: { en: "The Guide to the Right Path", bn: "সঠিক পথের নির্দেশক", fr: "Le Guide Parfait", id: "Yang Maha Pandai", ur: "رہنمائی کرنے والا", tr: "Doğru Yolu Gösteren", ar: "المرشد إلى الصواب" , zh: '指导者', ja: '導く者'},
    explain: { en: "Ar-Rashid is the One who guides all things to their proper end through the most right and correct path — His management of the universe proceeds by the most perfect wisdom and the most correct course. Al-Ghazali distinguishes this from Al-Hadi: while Al-Hadi guides the heart to faith, Ar-Rashid guides all of creation toward its destined purpose through the most righteous path. Nothing in Allah's decree is misguided; every event leads to its correct conclusion.", bn: "আর-রাশিদ হলেন যিনি সবকিছুকে সবচেয়ে সঠিক পথের মাধ্যমে তাদের যথাযথ লক্ষ্যে পরিচালিত করেন। আল-গাজালী আল-হাদি থেকে এটিকে আলাদা করেন: আল-হাদি হৃদয়কে ঈমানের দিকে পরিচালিত করেন, আর-রাশিদ সমস্ত সৃষ্টিকে সবচেয়ে ন্যায্য পথের মাধ্যমে তার নির্ধারিত উদ্দেশ্যে পরিচালিত করেন।" },
    invoke: { en: "When confused about a decision, recite the du'a of the youths of the cave: 'Rabbana atina min ladunka rahmatan wa hayyi' lana min amrina rashada' (18:10), asking Ar-Rashid to set your affair upon right guidance.", bn: "কোনো সিদ্ধান্তে দ্বিধাগ্রস্ত হলে গুহার যুবকদের দু'আ পড়ুন: 'রাব্বানা আতিনা মিন লাদুনকা রাহমাতান ওয়া হাইয়ি লানা মিন আমরিনা রাশাদা' (১৮:১০), আল-রশিদের কাছে আপনার কাজকে সঠিক পথে পরিচালিত করার প্রার্থনা করুন।" } ,
    quranicRefs: [
      { ref: "2:256", noteEn: "Qad tabayyana-r-rushdu mina-l-ghayy — right guidance (rushd) has become clear from error; Allah's guidance distinguishes truth.", noteBn: "কাদ তাবাইয়ানার-রুশদু মিনাল-গাইয় — সঠিক পথ (রুশদ) ভ্রান্তি থেকে স্পষ্ট হয়ে গেছে; আল্লাহর হিদায়াত সত্য পৃথক করে।" },
      { ref: "72:2", noteEn: "Yahdi ila-r-rushd fa-amanna bih — it guides to right conduct (rushd), so we believed in it.", noteBn: "ইয়াহদি ইলার-রুশদ ফা-আমান্না বিহ — এটি সঠিক পথের (রুশদ) দিকে পরিচালিত করে, তাই আমরা তাতে ঈমান আনলাম।" },
      { ref: "18:10", noteEn: "Wa hayyi' lana min amrina rashada — grant us right guidance (rashad) in our affair; du'a of the cave youths.", noteBn: "ওয়া হাইয়ি লানা মিন আমরিনা রাশাদা — আমাদের কাজে সঠিক পথ (রাশাদ) দাও; গুহার যুবকদের দু'আ।" },
      { ref: "40:38", noteEn: "Ittabi'uni ahdikum sabila-r-rashad — follow me; I will guide you to the way of right conduct.", noteBn: "ইত্তাবিউনি আহদিকুম সাবিলার-রাশাদ — আমাকে অনুসরণ করো; আমি তোমাদের সঠিক পথের দিকে পরিচালিত করব।" }
    ]},
  { n: 99, ar: "الصَّبُورُ", translit: "Aṣ-Ṣabūr", meanings: { en: "The Most Patient", bn: "মহাধৈর্যশীল", fr: "Le Très Patient", id: "Yang Maha Sabar", ur: "بڑا صابر", tr: "Çok Sabırlı", ar: "الذي لا يعاجل بالعقوبة" , zh: '耐心者', ja: '辛抱強き者'},
    explain: { en: "As-Sabur is the Most Patient — His patience (sabr) is not passive acceptance but active, purposeful forbearance: He delays punishment for the disobedient, allows time for the heedless to return, and withholds immediate retribution in His perfect wisdom. Al-Ghazali notes that As-Sabur concludes the list of the 99 Names, echoing Al-Halim (name 32): both reflect Allah's forbearance, but As-Sabur represents the highest degree of that forbearance which encompasses all creation. The hadith of Bukhari 2736 — 'Whoever memorises and acts upon them enters Paradise' — begins and ends with this complete list.", bn: "আস-সাবুর হলেন মহাধৈর্যশীল — তাঁর ধৈর্য (সবর) নিষ্ক্রিয় সহ্য নয় বরং সক্রিয়, উদ্দেশ্যমূলক সহিষ্ণুতা: তিনি অবাধ্যদের জন্য শাস্তি বিলম্বিত করেন, গাফিলদের ফিরে আসার সময় দেন। আস-সাবুর ৯৯ নামের তালিকা শেষ করে — এবং বুখারী ২৭৩৬ হাদিস যে কেউ এগুলো মুখস্থ করবে জান্নাতে প্রবেশ করবে — এই সম্পূর্ণ তালিকাটি শুরু ও শেষ করে।" },
    invoke: { en: "As-Sabur teaches us to bear trials without complaint or haste. When tested, say 'Ya Sabur' and ask Allah for patience — remembering that His own forbearance delays the punishment we deserve, granting us time to turn back.", bn: "আস-সাবুর আমাদের শেখায় অভিযোগ বা তাড়াহুড়ো ছাড়া বিপদ সহ্য করতে। পরীক্ষিত হলে 'ইয়া সাবুর' বলে আল্লাহর কাছে ধৈর্য চান — মনে রাখুন তাঁর নিজস্ব সহনশীলতা আমাদের প্রাপ্য শাস্তি বিলম্বিত করে, ফিরে আসার সময় দেয়।" } ,
    hadith: { en: "The Prophet ﷺ said: 'None is more patient (asbar) at hearing an injury than Allah: they ascribe a son to Him, yet He grants them well-being and provides for them.'", bn: "নবী ﷺ বলেন: 'কষ্টদায়ক কথা শুনে আল্লাহর চেয়ে অধিক ধৈর্যশীল (আসবার) আর কেউ নেই: তারা তাঁর প্রতি সন্তান আরোপ করে, তবুও তিনি তাদের সুস্থতা দেন ও রিজিক দেন।'", src: "Sahih al-Bukhari 6099; Sahih Muslim 2804" },
    quranicRefs: [
      { ref: "35:45", noteEn: "Wa law yu'akhidhu-llahu-n-nasa bima kasabu ma taraka 'ala zahriha min dabbah — were He to punish at once, no creature would remain; His forbearance.", noteBn: "ওয়া লাও ইউআখিযুল্লাহুন-নাসা বিমা কাসাবু মা তারাকা আলা যাহরিহা মিন দাব্বাহ — তিনি তৎক্ষণাৎ শাস্তি দিলে কোনো প্রাণী অবশিষ্ট থাকত না; তাঁর সহনশীলতা।" },
      { ref: "16:61", noteEn: "Wa law yu'akhidhu-llahu-n-nasa bi-zulmihim ma taraka 'alayha min dabbah — He does not hasten to punish wrongdoing.", noteBn: "ওয়া লাও ইউআখিযুল্লাহুন-নাসা বি-যুলমিহিম মা তারাকা আলাইহা মিন দাব্বাহ — তিনি অন্যায়ের জন্য দ্রুত শাস্তি দেন না।" },
      { ref: "22:48", noteEn: "Wa ka'ayyin min qaryatin amlaytu laha wa hiya zalimah — how many a town I gave respite though it was unjust.", noteBn: "ওয়া কাআইয়িন মিন কারয়াতিন আমলাইতু লাহা ওয়া হিয়া যালিমাহ — কত জনপদকে আমি অবকাশ দিয়েছি যদিও তা যালিম ছিল।" },
      { ref: "2:153", noteEn: "Inna-llaha ma'a-s-sabirin — indeed Allah is with the patient; He loves and rewards their sabr.", noteBn: "ইন্নাল্লাহা মাআস-সাবিরিন — নিশ্চয় আল্লাহ ধৈর্যশীলদের সাথে আছেন; তিনি তাদের ধৈর্য ভালোবাসেন ও পুরস্কৃত করেন।" }
    ]},
];

